const FRAMEWORKS={"OPQRST":{"name":"OPQRST","desc":"痛み・症状の評価","jp":"症状を体系的に掘り下げる型","steps":[{"k":"O","word":"Onset","jp":"発症"},{"k":"P","word":"Provoke","jp":"増悪寛解"},{"k":"Q","word":"Quality","jp":"性状"},{"k":"R","word":"Radiate","jp":"放散"},{"k":"S","word":"Severity","jp":"強さ"},{"k":"T","word":"Time","jp":"経過"}]},"SAMPLE":{"name":"SAMPLE","desc":"病歴の聴取","jp":"背景情報を漏れなく集める型","steps":[{"k":"S","word":"Signs","jp":"症状"},{"k":"A","word":"Allergy","jp":"アレルギー"},{"k":"M","word":"Meds","jp":"服薬"},{"k":"P","word":"Past Hx","jp":"既往歴"},{"k":"L","word":"Last meal","jp":"最終飲食"},{"k":"E","word":"Events","jp":"発症状況"}]},"CPSS":{"name":"FAST","desc":"脳卒中の評価","jp":"脳卒中の徴候を素早く確認する型","steps":[{"k":"T","word":"Time","jp":"発症時刻"},{"k":"F","word":"Face","jp":"顔"},{"k":"A","word":"Arms","jp":"腕"},{"k":"S","word":"Speech","jp":"言語"}]},"DCAP":{"name":"DCAP-BTLS","desc":"外傷の観察","jp":"外傷を頭から系統的に観察する型","steps":[{"k":"O","word":"Onset","jp":"受傷機転"},{"k":"D","word":"Deformity","jp":"変形/頭部"},{"k":"T","word":"Tender","jp":"圧痛/脊椎"},{"k":"L","word":"Lacer.","jp":"創/運動"},{"k":"S","word":"Swelling","jp":"既往"}]},"GTPAL":{"name":"GTPAL","desc":"産科の聴取","jp":"妊娠・分娩の状況を確認する型","steps":[{"k":"G","word":"Gestation","jp":"妊娠週数"},{"k":"T","word":"Timing","jp":"陣痛間隔"},{"k":"P","word":"Progress","jp":"進行/出産兆候"},{"k":"A","word":"History","jp":"既往"},{"k":"L","word":"Risk","jp":"合併症"}]}};
const SCENES=[{"id":"chest","icon":"🫀","title":"胸痛","en":"Chest Pain","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the chest pain start?","qjp":"胸の痛みはいつ始まりましたか？","purpose":"Onset｜発症のタイミングを確認します。","a":"It started about thirty minutes ago.","ajp":"30分ほど前に始まりました。","next":"p"},"p":{"step":"P","q":"Does anything make the pain better or worse?","qjp":"何かで痛みが強まったり和らぎますか？","purpose":"Provocation｜増悪・寛解の因子を探ります。","a":"It gets worse when I breathe deeply.","ajp":"深く息を吸うと悪化します。","next":"q"},"q":{"step":"Q","q":"Can you describe the pain?","qjp":"どんな痛みか説明できますか？","purpose":"Quality｜痛みの性状で原因を絞り込みます。","branch":{"question":"傷病者の答えで次の聞き方が変わります","options":[{"label":"It feels like heavy pressure.","jp":"重く締めつけられる感じです。","route":"→ 心原性を疑い『放散』を確認","next":"r_radiate","setReply":{"a":"It feels like heavy pressure on my chest.","ajp":"胸を重く圧迫される感じです。"}},{"label":"It's a sharp, stabbing pain.","jp":"鋭く刺すような痛みです。","route":"→ 胸膜性を疑い『体動』を確認","next":"r_sharp","setReply":{"a":"It's a sharp, stabbing pain.","ajp":"鋭く刺すような痛みです。"}}]}},"r_radiate":{"step":"R","q":"Does the pain spread to your arm or jaw?","qjp":"痛みは腕やあごに広がりますか？","purpose":"Radiation｜放散痛は心筋梗塞の重要なサインです。","a":"Yes, it goes down my left arm.","ajp":"はい、左腕に広がります。","next":"s"},"r_sharp":{"step":"R","q":"Does it hurt more when you cough or move?","qjp":"咳や体動で痛みは強まりますか？","purpose":"放散/性状｜体動依存性を確認します。","a":"Yes, coughing makes it much worse.","ajp":"はい、咳をするとずっとひどくなります。","next":"s"},"s":{"step":"S","q":"On a scale of one to ten, how bad is the pain?","qjp":"痛みは10段階でどのくらいですか？","purpose":"Severity｜重症度を数値で把握します。","a":"I would say about eight.","ajp":"8くらいだと思います。","next":"t"},"t":{"step":"T","q":"Is the pain constant, or does it come and go?","qjp":"痛みは続いていますか、それとも波がありますか？","purpose":"Time｜持続性か間欠性かで評価が変わります。","a":"It has been constant since it started.","ajp":"始まってからずっと続いています。","end":{"impr":"Thank you. We'll take good care of you. Try to stay calm.","imprJp":"ありがとうございます。しっかり診ますね。落ち着いていてください。"}}},"cat":"循環器","lv":10},{"id":"breath","icon":"🫁","title":"呼吸困難","en":"Breathing Difficulty","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did you start having trouble breathing?","qjp":"いつから息苦しくなりましたか？","purpose":"Onset｜発症の急性度を確認します。","a":"It came on suddenly about an hour ago.","ajp":"1時間ほど前に急に始まりました。","next":"p"},"p":{"step":"P","q":"Is it harder to breathe in any position?","qjp":"どの姿勢だと息がしにくいですか？","purpose":"Provocation｜起坐呼吸の有無を探ります。","a":"It's worse when I lie down.","ajp":"横になると悪化します。","next":"q"},"q":{"step":"Q","q":"Are you wheezing or coughing?","qjp":"喘鳴や咳はありますか？","purpose":"Quality｜気道狭窄か否かを見極めます。","branch":{"question":"返答で気道系か循環器系かを切り分けます","options":[{"label":"Yes, I'm wheezing a lot.","jp":"はい、ゼーゼーいっています。","route":"→ 喘息を疑い『既往』を確認","next":"r_asthma","setReply":{"a":"Yes, I'm wheezing a lot.","ajp":"はい、ゼーゼーとひどく鳴っています。"}},{"label":"No, but my legs are swollen.","jp":"いいえ、でも脚がむくんでいます。","route":"→ 心不全を疑い『既往』を確認","next":"r_edema","setReply":{"a":"No wheezing, but my legs are swollen.","ajp":"喘鳴はありませんが、脚がむくんでいます。"}}]}},"r_asthma":{"step":"R","q":"Do you have a history of asthma?","qjp":"喘息の既往はありますか？","purpose":"既往｜喘息発作の可能性を裏づけます。","a":"Yes, I use an inhaler.","ajp":"はい、吸入器を使っています。","next":"s"},"r_edema":{"step":"R","q":"Do you have any heart problems?","qjp":"心臓の病気はありますか？","purpose":"既往｜心不全の可能性を確認します。","a":"Yes, I have heart failure.","ajp":"はい、心不全があります。","next":"s"},"s":{"step":"S","q":"How bad is the breathlessness, from one to ten?","qjp":"息苦しさは10段階でどのくらいですか？","purpose":"Severity｜呼吸困難の程度を数値化します。","a":"About seven. It's hard to talk.","ajp":"7くらい。話すのもつらいです。","next":"t"},"t":{"step":"T","q":"Is it getting better, worse, or staying the same?","qjp":"良くなっていますか、悪化していますか、変わりませんか？","purpose":"Time｜経時変化で緊急度を判断します。","a":"It's slowly getting worse.","ajp":"だんだん悪くなっています。","end":{"impr":"Okay, we're giving you oxygen now. Just focus on slow breaths.","imprJp":"わかりました、今から酸素を投与します。ゆっくり呼吸することだけ意識してください。"}}},"cat":"呼吸器","lv":10},{"id":"history","icon":"💊","title":"病歴聴取","en":"Medical History","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms are you feeling right now?","qjp":"今どんな症状がありますか？","purpose":"Signs｜主訴を把握します。","a":"I feel dizzy and a little nauseous.","ajp":"めまいがして、少し吐き気がします。","next":"a"},"a":{"step":"A","q":"Do you have any allergies?","qjp":"何かアレルギーはありますか？","purpose":"Allergies｜投薬前に必ず確認します。","branch":{"question":"返答で次の確認事項が変わります","options":[{"label":"Yes, I'm allergic to penicillin.","jp":"はい、ペニシリンにアレルギーがあります。","route":"→ 反応の内容を詳しく確認","next":"a_detail","setReply":{"a":"Yes, I'm allergic to penicillin.","ajp":"はい、ペニシリンにアレルギーがあります。"}},{"label":"No, none that I know of.","jp":"いいえ、知る限りありません。","route":"→ そのまま服薬の確認へ","next":"m","setReply":{"a":"No, none that I know of.","ajp":"いいえ、私が知る限りありません。"}}]}},"a_detail":{"step":"A","q":"What happens when you take it?","qjp":"それを使うとどうなりますか？","purpose":"Allergies｜反応の重症度を確認します。","a":"I get a rash and trouble breathing.","ajp":"発疹が出て、息がしづらくなります。","next":"m"},"m":{"step":"M","q":"Are you taking any medications?","qjp":"何かお薬を飲んでいますか？","purpose":"Medications｜常用薬を確認します。","a":"I take medicine for blood pressure.","ajp":"血圧の薬を飲んでいます。","next":"p"},"p":{"step":"P","q":"Do you have any medical conditions?","qjp":"持病はありますか？","purpose":"Past history｜既往歴を聴取します。","a":"I have diabetes.","ajp":"糖尿病があります。","next":"l"},"l":{"step":"L","q":"When did you last eat or drink?","qjp":"最後に飲食したのはいつですか？","purpose":"Last meal｜処置や手術に備え確認します。","a":"I had breakfast around seven this morning.","ajp":"今朝7時ごろ朝食をとりました。","next":"e"},"e":{"step":"E","q":"What were you doing when this started?","qjp":"症状が出たとき何をしていましたか？","purpose":"Events｜発症前後の状況を把握します。","a":"I was just walking up the stairs.","ajp":"ちょうど階段を上っていました。","end":{"impr":"Thank you, that's very helpful. We have everything we need.","imprJp":"ありがとうございます、とても助かります。必要な情報はそろいました。"}}},"cat":"基本","lv":10},{"id":"identity","icon":"🪪","title":"本人確認","en":"Patient ID","framework":"SAMPLE","start":"name","nodes":{"name":{"step":"S","q":"Can you tell me your full name?","qjp":"フルネームを教えてもらえますか？","purpose":"本人確認｜まず氏名を確認します。","branch":{"question":"答えられるかどうかで対応が分かれます","options":[{"label":"My name is Maria Santos.","jp":"マリア・サントスです。","route":"→ 意識清明。生年月日の確認へ","next":"dob","setReply":{"a":"My name is Maria Santos.","ajp":"マリア・サントスです。"}},{"label":"I... I can't remember.","jp":"えっと…思い出せません。","route":"→ 見当識低下。落ち着かせて再確認","next":"reassure","setReply":{"a":"I... I can't remember right now.","ajp":"その…今は思い出せません。"}}]}},"reassure":{"step":"S","q":"That's okay. Take your time. Can you tell me your name?","qjp":"大丈夫ですよ。ゆっくりで結構です。お名前を教えてもらえますか？","purpose":"安心づけ｜落ち着かせて再度確認します。","a":"Oh... it's Maria. Maria Santos.","ajp":"あ…マリアです。マリア・サントス。","next":"dob"},"dob":{"step":"S","q":"What is your date of birth?","qjp":"生年月日を教えてください。","purpose":"本人確認｜生年月日で身元を確定します。","a":"It's May fifteenth, nineteen ninety.","ajp":"1990年5月15日です。","next":"addr"},"addr":{"step":"S","q":"What is your home address?","qjp":"ご自宅の住所を教えてください。","purpose":"本人確認｜搬送・連絡のため確認します。","a":"I live at 2-3-4 Sakura Street, Shibuya.","ajp":"渋谷区さくら通り2-3-4です。","next":"contact"},"contact":{"step":"E","q":"Is there someone we can contact for you?","qjp":"ご家族など連絡できる方はいますか？","purpose":"緊急連絡先｜家族等への連絡に備えます。","a":"Yes, please call my husband.","ajp":"はい、夫に電話してください。","next":"phone"},"phone":{"step":"E","q":"What is their phone number?","qjp":"その方の電話番号は何番ですか？","purpose":"緊急連絡先｜連絡先番号を取得します。","a":"It's zero-nine-zero, one-two-three-four, five-six-seven-eight.","ajp":"090-1234-5678です。","end":{"impr":"Thank you. We'll contact your family right away.","imprJp":"ありがとうございます。すぐにご家族へ連絡します。"}}},"cat":"基本","lv":10},{"id":"stroke","icon":"🧠","title":"脳卒中","en":"Stroke (FAST)","framework":"CPSS","start":"t","nodes":{"t":{"step":"T","q":"What time did the symptoms start?","qjp":"症状はいつ始まりましたか？","purpose":"Time｜発症時刻は治療方針を左右する最重要情報です。","a":"I noticed it about forty minutes ago.","ajp":"40分ほど前に気づきました。","next":"f"},"f":{"step":"F","q":"Can you smile and show me your teeth?","qjp":"笑顔を作って歯を見せてもらえますか？","purpose":"Face｜顔面の左右差を確認します。","branch":{"question":"観察結果で次の評価が変わります","options":[{"label":"My face feels droopy on the left.","jp":"左の顔が下がっている感じです。","route":"→ 顔面麻痺あり。腕の評価へ","next":"a","setReply":{"a":"The left side of my face is drooping.","ajp":"顔の左側が下がっています。"}},{"label":"I can smile normally.","jp":"普通に笑えます。","route":"→ 顔面正常。腕の評価へ","next":"a","setReply":{"a":"I can smile, that feels normal.","ajp":"笑えます、それは普通の感じです。"}}]}},"a":{"step":"A","q":"Can you raise both arms and hold them up?","qjp":"両腕を上げて、そのまま保てますか？","purpose":"Arms｜上肢のドリフト(片側下垂)を確認します。","a":"My right arm keeps drifting down.","ajp":"右腕がだんだん下がってきます。","next":"s"},"s":{"step":"S","q":"Please repeat after me: The sky is blue today.","qjp":"私の後に続けて言ってください。「今日は空が青い」","purpose":"Speech｜構音・言語の障害を確認します。","a":"The... sky is... bwoo today.","ajp":"そ…空が…あおい、です（不明瞭）。","next":"hist"},"hist":{"step":"T","q":"Are you on any blood thinners?","qjp":"血液をサラサラにする薬を飲んでいますか？","purpose":"既往｜抗凝固薬は治療選択に影響します。","a":"Yes, I take warfarin.","ajp":"はい、ワルファリンを飲んでいます。","end":{"impr":"You may be having a stroke. We're taking you to the hospital right now.","imprJp":"脳卒中の可能性があります。今すぐ病院へお連れします。"}}},"cat":"神経","lv":9},{"id":"seizure","icon":"⚡","title":"けいれん","en":"Seizure","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Are you fully awake now?","qjp":"今は完全に目が覚めていますか？","purpose":"Signs｜発作後の意識状態を確認します。","a":"I feel groggy and confused.","ajp":"ぼんやりして、混乱しています。","next":"event"},"event":{"step":"E","q":"How long did the shaking last?","qjp":"けいれんはどのくらい続きましたか？","purpose":"Events｜持続時間で重症度を判断します。","branch":{"question":"目撃情報で対応が分かれます","options":[{"label":"About two minutes.","jp":"2分くらいです。","route":"→ 通常の発作。既往の確認へ","next":"hx","setReply":{"a":"It lasted about two minutes.","ajp":"2分ほど続きました。"}},{"label":"More than five minutes, and it didn't stop.","jp":"5分以上で、止まりませんでした。","route":"→ 重積発作の疑い。緊急対応へ","next":"status","setReply":{"a":"More than five minutes. It wouldn't stop.","ajp":"5分以上です。止まりませんでした。"}}]}},"status":{"step":"E","q":"Has this happened before today?","qjp":"今日、これより前にも起きましたか？","purpose":"重積｜反復・遷延は緊急度が高い状態です。","a":"Yes, this is the second time.","ajp":"はい、これで2回目です。","next":"hx"},"hx":{"step":"P","q":"Do you have a history of epilepsy?","qjp":"てんかんの既往はありますか？","purpose":"Past history｜初発か既知かを区別します。","a":"Yes, I have epilepsy.","ajp":"はい、てんかんがあります。","next":"m"},"m":{"step":"M","q":"Did you take your medication today?","qjp":"今日は薬を飲みましたか？","purpose":"Medications｜服薬コンプライアンスを確認します。","a":"No, I forgot this morning.","ajp":"いいえ、今朝飲み忘れました。","end":{"impr":"Thank you. We'll monitor you closely on the way to the hospital.","imprJp":"ありがとうございます。病院まで注意して見守りますね。"}}},"cat":"神経","lv":7},{"id":"abdpain","icon":"🤰","title":"腹痛","en":"Abdominal Pain","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the stomach pain begin?","qjp":"お腹の痛みはいつ始まりましたか？","purpose":"Onset｜発症の経過を確認します。","a":"It started last night.","ajp":"昨夜から始まりました。","next":"p"},"p":{"step":"P","q":"Does eating make it better or worse?","qjp":"食事で痛みは強まりますか、和らぎますか？","purpose":"Provocation｜食事との関係で原因を探ります。","a":"It gets worse after I eat.","ajp":"食べた後にひどくなります。","next":"q"},"q":{"step":"Q","q":"Is the pain sharp or dull?","qjp":"痛みは鋭いですか、鈍いですか？","purpose":"Quality｜痛みの性状を把握します。","a":"It's a sharp, cramping pain.","ajp":"鋭く、差し込むような痛みです。","next":"r"},"r":{"step":"R","q":"Can you point to where it hurts most?","qjp":"一番痛い場所を指でさせますか？","purpose":"Region｜部位は疾患の絞り込みに直結します。","branch":{"question":"痛む部位で次の確認が変わります","options":[{"label":"Here, on the lower right side.","jp":"ここ、右下のあたりです。","route":"→ 虫垂炎を疑い移動歴を確認","next":"appendix","setReply":{"a":"It's here, on the lower right side.","ajp":"ここ、右下のあたりです。"}},{"label":"All over my belly.","jp":"お腹全体です。","route":"→ 広範囲。随伴症状を確認","next":"diffuse","setReply":{"a":"It's all over my belly.","ajp":"お腹全体が痛いです。"}}]}},"appendix":{"step":"R","q":"Did the pain start near your belly button?","qjp":"痛みは最初おへその辺りから始まりましたか？","purpose":"放散/移動｜虫垂炎特有の痛みの移動を確認します。","a":"Yes, it moved from the middle to the right.","ajp":"はい、真ん中から右へ移りました。","next":"s"},"diffuse":{"step":"R","q":"Do you have a fever or vomiting?","qjp":"発熱や嘔吐はありますか？","purpose":"随伴症状｜腹膜炎や感染を評価します。","a":"Yes, I've been vomiting and feel hot.","ajp":"はい、吐いていて、熱っぽいです。","next":"s"},"s":{"step":"S","q":"How severe is the pain, one to ten?","qjp":"痛みは10段階でどのくらいですか？","purpose":"Severity｜重症度を数値化します。","a":"It's about a nine now.","ajp":"今は9くらいです。","next":"t"},"t":{"step":"T","q":"Is the pain constant or does it come in waves?","qjp":"痛みは続いていますか、波がありますか？","purpose":"Time｜持続性か間欠性かを確認します。","a":"It comes in waves.","ajp":"波があります。","end":{"impr":"Thank you. Please try not to eat or drink anything for now.","imprJp":"ありがとうございます。今は飲食を控えてくださいね。"}}},"cat":"消化器","lv":10},{"id":"anaphylaxis","icon":"🐝","title":"アナフィラキシー","en":"Anaphylaxis","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms are you having right now?","qjp":"今どんな症状がありますか？","purpose":"Signs｜重症度と進行を評価します。","a":"My throat feels tight and my face is swelling.","ajp":"喉が締めつけられて、顔が腫れています。","next":"a"},"a":{"step":"A","q":"Do you know what caused this reaction?","qjp":"何が原因か分かりますか？","purpose":"Allergies｜曝露源を特定します。","branch":{"question":"曝露源で次の確認が変わります","options":[{"label":"I was stung by a bee.","jp":"蜂に刺されました。","route":"→ 刺傷。針の有無を確認","next":"sting","setReply":{"a":"A bee stung me a few minutes ago.","ajp":"数分前に蜂に刺されました。"}},{"label":"I ate peanuts.","jp":"ピーナッツを食べました。","route":"→ 食物。既往の確認へ","next":"food","setReply":{"a":"I ate something with peanuts.","ajp":"ピーナッツの入ったものを食べました。"}}]}},"sting":{"step":"A","q":"Have you ever reacted to a sting before?","qjp":"以前にも刺されて反応が出たことはありますか？","purpose":"既往｜過去の反応歴は重症化の指標です。","a":"Yes, but it was milder last time.","ajp":"はい、でも前回はもっと軽かったです。","next":"m"},"food":{"step":"A","q":"Do you have a known peanut allergy?","qjp":"ピーナッツアレルギーがあると分かっていますか？","purpose":"既往｜既知のアレルギーを確認します。","a":"Yes, I'm very allergic to peanuts.","ajp":"はい、ピーナッツに強いアレルギーがあります。","next":"m"},"m":{"step":"M","q":"Do you have an epinephrine auto-injector?","qjp":"エピネフリンの自己注射器を持っていますか？","purpose":"Medications｜エピペンの有無は救命に直結します。","a":"Yes, it's in my bag.","ajp":"はい、かばんの中にあります。","next":"e"},"e":{"step":"E","q":"Have you used it yet?","qjp":"もう使いましたか？","purpose":"Events｜投与状況を確認します。","a":"No, not yet.","ajp":"いいえ、まだです。","end":{"impr":"We need to use it now. We're treating you immediately.","imprJp":"今すぐ使う必要があります。直ちに処置します。"}}},"cat":"環境・中毒","lv":9},{"id":"hypoglycemia","icon":"🍬","title":"低血糖","en":"Hypoglycemia","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How are you feeling right now?","qjp":"今、気分はどうですか？","purpose":"Signs｜低血糖症状(冷汗・震え)を確認します。","a":"I feel shaky, sweaty and confused.","ajp":"震えて、汗が出て、頭が混乱します。","next":"p"},"p":{"step":"P","q":"Do you have diabetes?","qjp":"糖尿病はありますか？","purpose":"Past history｜糖尿病の有無を確認します。","branch":{"question":"返答で次の確認が変わります","options":[{"label":"Yes, I take insulin.","jp":"はい、インスリンを使っています。","route":"→ インスリン使用。投与状況を確認","next":"insulin","setReply":{"a":"Yes, I'm diabetic and I take insulin.","ajp":"はい、糖尿病でインスリンを使っています。"}},{"label":"Yes, I take pills for it.","jp":"はい、飲み薬を使っています。","route":"→ 経口薬。最終食事を確認","next":"l","setReply":{"a":"Yes, I take tablets for diabetes.","ajp":"はい、糖尿病の錠剤を飲んでいます。"}}]}},"insulin":{"step":"M","q":"How much insulin did you take today?","qjp":"今日はインスリンをどのくらい打ちましたか？","purpose":"Medications｜過量投与の可能性を評価します。","a":"My usual dose, but I felt sick.","ajp":"いつもの量ですが、気分が悪かったです。","next":"l"},"l":{"step":"L","q":"When did you last eat?","qjp":"最後に食事をしたのはいつですか？","purpose":"Last meal｜欠食は低血糖の主因です。","a":"I skipped lunch today.","ajp":"今日は昼食を抜きました。","next":"e"},"e":{"step":"E","q":"Can you swallow something sweet safely?","qjp":"甘いものを安全に飲み込めそうですか？","purpose":"Events｜経口補給が可能か気道を評価します。","a":"Yes, I think I can.","ajp":"はい、できると思います。","end":{"impr":"Good. We'll give you some sugar now and check your blood.","imprJp":"よかった。今から糖分をとってもらい、血糖を測りますね。"}}},"cat":"代謝","lv":7},{"id":"fall","icon":"🦴","title":"転倒・転落","en":"Fall / Injury","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"Can you tell me how you fell?","qjp":"どのように転んだか教えてもらえますか？","purpose":"受傷機転｜損傷の予測に重要です。","a":"I fell down the stairs.","ajp":"階段から落ちました。","next":"high"},"high":{"step":"O","q":"How far did you fall?","qjp":"どのくらいの高さから落ちましたか？","purpose":"受傷機転｜落下高は重症度予測に直結します。","a":"About five or six steps.","ajp":"5、6段くらいです。","next":"head"},"head":{"step":"D","q":"Did you hit your head?","qjp":"頭を打ちましたか？","purpose":"Deformity/頭部｜頭部外傷を評価します。","branch":{"question":"返答で評価の方向が変わります","options":[{"label":"Yes, and I blacked out for a moment.","jp":"はい、一瞬気を失いました。","route":"→ 意識消失あり。神経評価へ","next":"loc","setReply":{"a":"Yes, I hit my head and blacked out briefly.","ajp":"はい、頭を打って一瞬意識を失いました。"}},{"label":"No, I landed on my side.","jp":"いいえ、横向きに落ちました。","route":"→ 体幹/四肢の評価へ","next":"pain","setReply":{"a":"No, I landed on my side.","ajp":"いいえ、横向きに着地しました。"}}]}},"loc":{"step":"T","q":"Do you feel any neck or back pain?","qjp":"首や背中に痛みはありますか？","purpose":"Tenderness/脊椎｜脊椎損傷を評価します。","a":"My neck feels stiff and sore.","ajp":"首が硬くて痛いです。","next":"move"},"pain":{"step":"T","q":"Where does it hurt the most?","qjp":"一番痛いのはどこですか？","purpose":"Tenderness｜損傷部位を特定します。","a":"My right hip and arm.","ajp":"右の腰と腕です。","next":"move"},"move":{"step":"L","q":"Can you move your fingers and toes?","qjp":"手の指と足の指は動かせますか？","purpose":"Laceration/運動｜神経・運動機能を確認します。","a":"My toes feel a little numb.","ajp":"足の指が少ししびれます。","next":"thin"},"thin":{"step":"S","q":"Are you taking any blood thinners?","qjp":"血液をサラサラにする薬を飲んでいますか？","purpose":"既往｜出血リスクの評価に必要です。","a":"Yes, I take a daily blood thinner.","ajp":"はい、毎日血をサラサラにする薬を飲んでいます。","end":{"impr":"Please stay still. We'll support your neck and move you carefully.","imprJp":"動かないでください。首を固定して、慎重にお運びします。"}}},"cat":"外傷","lv":10},{"id":"asthma","icon":"😮‍💨","title":"喘息発作","en":"Asthma Attack","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the attack start?","qjp":"発作はいつ始まりましたか？","purpose":"Onset｜発症のタイミングを確認します。","a":"About twenty minutes ago.","ajp":"20分ほど前です。","next":"p"},"p":{"step":"P","q":"What were you doing when it started?","qjp":"始まったとき何をしていましたか？","purpose":"Provocation｜誘因を特定します。","a":"I was around a cat.","ajp":"猫のそばにいました。","next":"q"},"q":{"step":"Q","q":"Can you speak in full sentences?","qjp":"文章を最後まで話せますか？","purpose":"Quality｜会話可能かは重症度の指標です。","branch":{"question":"話せる程度で重症度が分かれます","options":[{"label":"Only a few words at a time.","jp":"少しずつしか話せません。","route":"→ 重症。吸入器の使用を確認","next":"severe","setReply":{"a":"I can only say a few words.","ajp":"少しずつしか言えません。"}},{"label":"Yes, but it's getting harder.","jp":"はい、でもきつくなってきました。","route":"→ 中等症。吸入器の確認へ","next":"inhaler","setReply":{"a":"Yes, but it's getting harder.","ajp":"はい、でもだんだんつらくなっています。"}}]}},"severe":{"step":"R","q":"Have you used your reliever inhaler?","qjp":"発作止めの吸入器は使いましたか？","purpose":"治療｜既使用の薬剤と効果を確認します。","a":"Yes, twice, but it's not helping.","ajp":"はい、2回。でも効きません。","next":"s"},"inhaler":{"step":"R","q":"Do you have your inhaler with you?","qjp":"吸入器は持っていますか？","purpose":"治療｜手元の薬剤を確認します。","a":"Yes, it's right here.","ajp":"はい、ここにあります。","next":"s"},"s":{"step":"S","q":"How bad is the breathing, one to ten?","qjp":"息苦しさは10段階でどのくらいですか？","purpose":"Severity｜重症度を数値化します。","a":"About eight.","ajp":"8くらいです。","next":"t"},"t":{"step":"T","q":"Have your attacks ever needed a hospital before?","qjp":"これまで発作で入院したことはありますか？","purpose":"既往｜重症発作の既往は危険因子です。","a":"Yes, once last year.","ajp":"はい、去年1回あります。","end":{"impr":"Okay, we're helping with your breathing now. Try to relax your shoulders.","imprJp":"わかりました、今から呼吸を助けます。肩の力を抜いてみてください。"}}},"cat":"呼吸器","lv":10},{"id":"overdose","icon":"💊","title":"過量服薬","en":"Overdose","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How are you feeling right now?","qjp":"今、気分はどうですか？","purpose":"Signs｜意識・呼吸状態を評価します。","a":"I feel very sleepy and dizzy.","ajp":"とても眠くて、めまいがします。","next":"e1"},"e1":{"step":"E","q":"What did you take?","qjp":"何を飲みましたか？","purpose":"Events｜摂取物質の特定が最優先です。","branch":{"question":"摂取物で対応が分かれます","options":[{"label":"A lot of painkillers.","jp":"鎮痛薬をたくさんです。","route":"→ 種類と量を確認","next":"amount","setReply":{"a":"I took a lot of painkillers.","ajp":"鎮痛薬をたくさん飲みました。"}},{"label":"My sleeping pills and alcohol.","jp":"睡眠薬とお酒です。","route":"→ 併用。時刻を確認","next":"when","setReply":{"a":"My sleeping pills with some alcohol.","ajp":"睡眠薬とお酒を一緒にです。"}}]}},"amount":{"step":"E","q":"How many did you take, and do you have the box?","qjp":"何錠飲みましたか？箱は手元にありますか？","purpose":"Events｜量と薬剤名は治療に不可欠です。","a":"Maybe fifteen. Here is the box.","ajp":"たぶん15錠。これが箱です。","next":"when"},"when":{"step":"E","q":"How long ago did you take them?","qjp":"飲んでからどのくらい経ちましたか？","purpose":"Events｜経過時間は処置の判断に重要です。","a":"About an hour ago.","ajp":"1時間ほど前です。","next":"a"},"a":{"step":"A","q":"Do you have any allergies?","qjp":"何かアレルギーはありますか？","purpose":"Allergies｜投薬の安全確認です。","a":"No allergies.","ajp":"アレルギーはありません。","end":{"impr":"Thank you for telling me. You did the right thing. We're here to help you.","imprJp":"話してくれてありがとう。正しい判断でした。私たちが助けます。"}}},"cat":"環境・中毒","lv":9},{"id":"burn","icon":"🔥","title":"熱傷","en":"Burns","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Where are you burned?","qjp":"どこをやけどしましたか？","purpose":"Signs｜受傷部位と範囲を確認します。","a":"My right hand and forearm.","ajp":"右手と前腕です。","next":"e1"},"e1":{"step":"E","q":"What caused the burn?","qjp":"何が原因でやけどしましたか？","purpose":"Events｜原因で処置が変わります。","branch":{"question":"原因で次の確認が変わります","options":[{"label":"Hot cooking oil.","jp":"熱い料理油です。","route":"→ 熱傷。冷却状況を確認","next":"thermal","setReply":{"a":"I spilled hot cooking oil on it.","ajp":"熱い料理油をこぼしました。"}},{"label":"A chemical at work.","jp":"職場の薬品です。","route":"→ 化学熱傷。物質を確認","next":"chemical","setReply":{"a":"A chemical splashed on me at work.","ajp":"職場で薬品がかかりました。"}}]}},"thermal":{"step":"E","q":"Have you cooled it with water?","qjp":"水で冷やしましたか？","purpose":"処置｜初期冷却の有無を確認します。","a":"Yes, I ran it under cold water.","ajp":"はい、冷たい水で流しました。","next":"p"},"chemical":{"step":"E","q":"Do you know what chemical it was?","qjp":"何の薬品か分かりますか？","purpose":"処置｜原因物質は洗浄方針に直結します。","a":"It was some kind of cleaner.","ajp":"洗剤のようなものでした。","next":"p"},"p":{"step":"P","q":"Are you having any trouble breathing?","qjp":"呼吸に問題はありますか？","purpose":"気道｜気道熱傷の有無を確認します。","a":"No, my breathing is fine.","ajp":"いいえ、呼吸は大丈夫です。","next":"a"},"a":{"step":"A","q":"When was your last tetanus shot?","qjp":"最後に破傷風の予防接種を受けたのはいつですか？","purpose":"既往｜創傷管理に必要な情報です。","a":"I'm not sure, a long time ago.","ajp":"はっきりしません、ずっと前です。","end":{"impr":"We'll keep the burn cool and clean. You're doing well.","imprJp":"やけどを冷やして清潔に保ちますね。よく対応できています。"}}},"cat":"外傷","lv":7},{"id":"bleeding","icon":"🩸","title":"出血","en":"Bleeding","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Where is the bleeding coming from?","qjp":"どこから出血していますか？","purpose":"Signs｜出血部位を特定します。","a":"From a deep cut on my arm.","ajp":"腕の深い切り傷からです。","next":"e1"},"e1":{"step":"E","q":"How did you get the cut?","qjp":"どうやって切りましたか？","purpose":"Events｜受傷機転を確認します。","a":"I cut it on broken glass.","ajp":"割れたガラスで切りました。","next":"flow"},"flow":{"step":"S","q":"Is the blood spurting or flowing steadily?","qjp":"血は噴き出していますか、じわじわ流れていますか？","purpose":"重症度｜動脈性出血は緊急止血が必要です。","branch":{"question":"出血の様子で緊急度が分かれます","options":[{"label":"It's spurting out fast.","jp":"勢いよく噴き出しています。","route":"→ 動脈性。直接圧迫を指示","next":"arterial","setReply":{"a":"It's spurting out quickly.","ajp":"勢いよく噴き出しています。"}},{"label":"It's just oozing slowly.","jp":"ゆっくりにじむ程度です。","route":"→ 静脈性。圧迫を継続","next":"venous","setReply":{"a":"It's oozing slowly.","ajp":"ゆっくりにじんでいます。"}}]}},"arterial":{"step":"E","q":"Can you press hard on it with a cloth?","qjp":"布で強く押さえられますか？","purpose":"処置｜直接圧迫止血を指示します。","a":"Yes, I'm pressing on it now.","ajp":"はい、今押さえています。","next":"a"},"venous":{"step":"E","q":"Can you keep pressure on it and raise it up?","qjp":"押さえたまま、腕を高く上げられますか？","purpose":"処置｜圧迫と挙上で止血を促します。","a":"Yes, I can hold it up.","ajp":"はい、上げていられます。","next":"a"},"a":{"step":"A","q":"Are you taking any blood thinners?","qjp":"血液をサラサラにする薬を飲んでいますか？","purpose":"既往｜出血傾向を評価します。","a":"No, I'm not.","ajp":"いいえ、飲んでいません。","end":{"impr":"Keep pressing firmly. We'll control the bleeding together.","imprJp":"しっかり押さえ続けてください。一緒に出血を止めましょう。"}}},"cat":"外傷","lv":10},{"id":"syncope","icon":"😵","title":"失神","en":"Fainting","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Do you remember fainting?","qjp":"気を失ったことを覚えていますか？","purpose":"Signs｜意識消失の状況を確認します。","a":"I remember feeling dizzy, then nothing.","ajp":"めまいがして、その後の記憶がありません。","next":"warn"},"warn":{"step":"E","q":"Did you feel any warning before you fainted?","qjp":"倒れる前に何か前兆はありましたか？","purpose":"Events｜前兆の有無は原因の手がかりです。","branch":{"question":"前兆の有無で疑う原因が変わります","options":[{"label":"Yes, I felt dizzy and sweaty.","jp":"はい、めまいと冷や汗がしました。","route":"→ 血管迷走神経性を疑う","next":"vaso","setReply":{"a":"Yes, I felt dizzy and sweaty first.","ajp":"はい、先にめまいと冷や汗がありました。"}},{"label":"No, it happened with no warning.","jp":"いいえ、突然でした。","route":"→ 心原性を疑い動悸を確認","next":"cardiac","setReply":{"a":"No, it happened suddenly.","ajp":"いいえ、突然起きました。"}}]}},"vaso":{"step":"E","q":"Were you standing for a long time?","qjp":"長く立っていましたか？","purpose":"Events｜起立性の誘因を確認します。","a":"Yes, I was standing in a hot room.","ajp":"はい、暑い部屋で立っていました。","next":"p"},"cardiac":{"step":"S","q":"Did you feel your heart racing?","qjp":"心臓がドキドキしましたか？","purpose":"随伴症状｜不整脈の可能性を評価します。","a":"Yes, it was pounding before I fell.","ajp":"はい、倒れる前に激しく打っていました。","next":"p"},"p":{"step":"P","q":"Do you have any heart conditions?","qjp":"心臓の病気はありますか？","purpose":"Past history｜心疾患の既往を確認します。","a":"No, none that I know of.","ajp":"いいえ、知る限りありません。","next":"m"},"m":{"step":"M","q":"Are you taking any medications?","qjp":"何かお薬を飲んでいますか？","purpose":"Medications｜降圧薬等の影響を確認します。","a":"Just blood pressure medicine.","ajp":"血圧の薬だけです。","end":{"impr":"Thank you. Please stay lying down for now while we check you.","imprJp":"ありがとうございます。検査の間、しばらく横になっていてください。"}}},"cat":"循環器","lv":8},{"id":"heatstroke","icon":"🥵","title":"熱中症","en":"Heat Stroke","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How are you feeling?","qjp":"気分はどうですか？","purpose":"Signs｜意識・体温の状態を評価します。","a":"I feel dizzy, weak and very hot.","ajp":"めまいがして、力が入らず、とても暑いです。","next":"e1"},"e1":{"step":"E","q":"Where were you before you felt sick?","qjp":"具合が悪くなる前はどこにいましたか？","purpose":"Events｜暑熱環境への曝露を確認します。","a":"I was working outside in the sun.","ajp":"日なたで外作業をしていました。","next":"sweat"},"sweat":{"step":"S","q":"Are you still sweating?","qjp":"まだ汗は出ていますか？","purpose":"重症度｜発汗停止は重症のサインです。","branch":{"question":"発汗の有無で重症度が分かれます","options":[{"label":"No, my skin is hot and dry.","jp":"いいえ、肌が熱くて乾いています。","route":"→ 重症(発汗停止)。緊急冷却へ","next":"severe","setReply":{"a":"No, my skin feels hot and dry.","ajp":"いいえ、肌が熱くて乾いています。"}},{"label":"Yes, I'm sweating a lot.","jp":"はい、汗をたくさんかいています。","route":"→ 熱疲労。水分摂取を確認","next":"mild","setReply":{"a":"Yes, I'm sweating heavily.","ajp":"はい、たくさん汗をかいています。"}}]}},"severe":{"step":"S","q":"Do you feel confused or have a headache?","qjp":"頭が混乱したり、頭痛がしますか？","purpose":"重症度｜中枢神経症状を評価します。","a":"Yes, I'm confused and my head hurts.","ajp":"はい、混乱していて頭が痛いです。","next":"l"},"mild":{"step":"L","q":"Have you been able to drink water?","qjp":"水を飲めていますか？","purpose":"水分｜脱水の程度を確認します。","a":"A little, but not much.","ajp":"少しだけ、あまり飲めていません。","next":"l"},"l":{"step":"L","q":"When did you last drink fluids?","qjp":"最後に水分をとったのはいつですか？","purpose":"Last intake｜脱水の評価に必要です。","a":"A few hours ago.","ajp":"数時間前です。","end":{"impr":"We're moving you to a cool place and cooling you down now.","imprJp":"涼しい場所へ移して、今から体を冷やしますね。"}}},"cat":"環境・中毒","lv":8},{"id":"pedfever","icon":"🧒","title":"小児の発熱","en":"Child with Fever","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How long has your child had a fever?","qjp":"お子さんの発熱はいつからですか？","purpose":"Signs｜発熱の経過を保護者に確認します。","a":"Since yesterday evening.","ajp":"昨日の夕方からです。","next":"behavior"},"behavior":{"step":"S","q":"Is your child alert and active?","qjp":"お子さんは反応がよく、元気ですか？","purpose":"PAT｜活気は重症感の最重要指標です。","branch":{"question":"活気の様子で緊急度が分かれます","options":[{"label":"No, very floppy and hard to wake.","jp":"いいえ、ぐったりして起こしにくいです。","route":"→ 重症感あり。緊急評価へ","next":"lethargic","setReply":{"a":"No, she's very floppy and hard to wake.","ajp":"いいえ、ぐったりして起こしにくいです。"}},{"label":"Yes, still playing a little.","jp":"はい、まだ少し遊んでいます。","route":"→ 活気あり。水分の確認へ","next":"active","setReply":{"a":"Yes, she's still playing a little.","ajp":"はい、まだ少し遊んでいます。"}}]}},"lethargic":{"step":"S","q":"Is there any rash on the skin?","qjp":"皮膚に発疹はありますか？","purpose":"重症感｜髄膜炎等の重症サインを探ります。","a":"Yes, some purple spots appeared.","ajp":"はい、紫色の斑点が出ています。","next":"a"},"active":{"step":"L","q":"Is your child drinking and urinating normally?","qjp":"お子さんは水分をとり、おしっこは出ていますか？","purpose":"水分｜脱水の有無を評価します。","a":"Drinking a little, fewer wet diapers.","ajp":"少し飲んでいますが、おむつの濡れが減っています。","next":"a"},"a":{"step":"A","q":"Does your child have any allergies?","qjp":"お子さんにアレルギーはありますか？","purpose":"Allergies｜投薬前に確認します。","a":"No known allergies.","ajp":"分かっているアレルギーはありません。","next":"m"},"m":{"step":"M","q":"Have you given any medicine for the fever?","qjp":"熱に対して薬を飲ませましたか？","purpose":"Medications｜解熱薬の使用を確認します。","a":"I gave children's acetaminophen.","ajp":"小児用のアセトアミノフェンを飲ませました。","end":{"impr":"Thank you. We'll check your child carefully right away.","imprJp":"ありがとうございます。すぐにお子さんをしっかり診ますね。"}}},"cat":"小児","lv":9},{"id":"labor","icon":"🤱","title":"陣痛・分娩","en":"Labor","framework":"GTPAL","start":"g","nodes":{"g":{"step":"G","q":"How many weeks pregnant are you?","qjp":"妊娠何週ですか？","purpose":"妊娠週数｜搬送先と緊急度の判断に必須です。","a":"I'm thirty-nine weeks.","ajp":"39週です。","next":"contract"},"contract":{"step":"T","q":"How far apart are the contractions?","qjp":"陣痛の間隔はどのくらいですか？","purpose":"陣痛間隔｜分娩の進行度を評価します。","branch":{"question":"陣痛間隔で切迫度が分かれます","options":[{"label":"About two minutes apart.","jp":"2分間隔くらいです。","route":"→ 分娩切迫。出産兆候を確認","next":"imminent","setReply":{"a":"They're about two minutes apart.","ajp":"2分間隔くらいです。"}},{"label":"About ten minutes apart.","jp":"10分間隔くらいです。","route":"→ 早期。破水の確認へ","next":"early","setReply":{"a":"About ten minutes apart.","ajp":"10分間隔くらいです。"}}]}},"imminent":{"step":"P","q":"Do you feel the urge to push?","qjp":"いきみたい感じはありますか？","purpose":"出産兆候｜娩出が近いかを判断します。","a":"Yes, I feel a lot of pressure.","ajp":"はい、強い圧迫感があります。","next":"water"},"early":{"step":"P","q":"Has your water broken?","qjp":"破水はしましたか？","purpose":"破水｜分娩進行と感染リスクを評価します。","a":"Not yet.","ajp":"まだです。","next":"water"},"water":{"step":"A","q":"Is this your first baby?","qjp":"初めてのお産ですか？","purpose":"既往｜経産婦は進行が速いことがあります。","a":"No, this is my second.","ajp":"いいえ、2人目です。","next":"comp"},"comp":{"step":"L","q":"Have there been any problems in this pregnancy?","qjp":"今回の妊娠で問題はありましたか？","purpose":"合併症｜ハイリスク要因を確認します。","a":"No, everything has been normal.","ajp":"いいえ、すべて順調でした。","end":{"impr":"You're doing great. We're prepared to help you safely.","imprJp":"よく頑張っています。安全にお手伝いできる準備はできています。"}}},"cat":"産科","lv":8},{"id":"mentalhealth","icon":"💙","title":"心の危機","en":"Mental Health Crisis","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"I'm here to help. How are you feeling right now?","qjp":"力になりに来ました。今、どんな気持ちですか？","purpose":"信頼関係｜まず安心と傾聴の姿勢を示します。","a":"I feel hopeless and very tired.","ajp":"絶望していて、とても疲れています。","next":"safe"},"safe":{"step":"S","q":"Are you safe right now? Are you hurt?","qjp":"今、安全ですか？怪我はありませんか？","purpose":"安全確認｜身体的危険の有無を確認します。","branch":{"question":"返答で対応が分かれます","options":[{"label":"I haven't hurt myself.","jp":"自分を傷つけてはいません。","route":"→ 支援者の確認へ","next":"support","setReply":{"a":"No, I haven't hurt myself.","ajp":"いいえ、自分を傷つけてはいません。"}},{"label":"I took some pills earlier.","jp":"さっき薬を飲みました。","route":"→ 身体評価を優先","next":"medical","setReply":{"a":"I took some pills a little while ago.","ajp":"少し前に薬を飲みました。"}}]}},"medical":{"step":"E","q":"Can you tell me what you took and when?","qjp":"何をいつ飲んだか教えてもらえますか？","purpose":"安全｜身体的緊急性を最優先で評価します。","a":"Some sleeping pills, about an hour ago.","ajp":"睡眠薬を、1時間ほど前に。","next":"support"},"support":{"step":"S","q":"Is there someone you trust that we can call?","qjp":"信頼できる方で、連絡できる人はいますか？","purpose":"支援｜支援者とのつながりを確認します。","a":"Maybe my sister.","ajp":"姉に…なら。","next":"care"},"care":{"step":"E","q":"Will you let us take you somewhere safe to talk?","qjp":"安全な場所で話せるよう、一緒に行ってもらえますか？","purpose":"受け入れ｜本人の同意を得て支援につなぎます。","a":"Okay... yes.","ajp":"はい…わかりました。","end":{"impr":"Thank you for trusting me. You're not alone, and we'll stay with you.","imprJp":"信頼してくれてありがとう。あなたは一人ではありません。私たちがそばにいます。"}}},"cat":"精神","lv":10},{"id":"language","icon":"🗣️","title":"言葉が通じない","en":"Language Barrier","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Do you speak English? A little?","qjp":"英語は話せますか？少しでも？","purpose":"言語確認｜コミュニケーション手段を探ります。","branch":{"question":"理解度で進め方が変わります","options":[{"label":"A little. Slowly, please.","jp":"少しだけ。ゆっくりお願いします。","route":"→ ゆっくり簡単な英語で続行","next":"slow","setReply":{"a":"A little. Please speak slowly.","ajp":"少しだけ。ゆっくり話してください。"}},{"label":"No English. (points to phone)","jp":"英語は無理です。（電話を指す）","route":"→ 翻訳アプリの活用へ","next":"translate","setReply":{"a":"No English... (points to translation app)","ajp":"英語は分かりません…（翻訳アプリを指す）"}}]}},"slow":{"step":"S","q":"Point to where it hurts.","qjp":"痛いところを指でさしてください。","purpose":"簡易確認｜身振りで主訴を把握します。","a":"(points to chest) Here. Pain.","ajp":"（胸をさす）ここ。痛い。","next":"pain"},"translate":{"step":"S","q":"Okay. Show me on the app where it hurts.","qjp":"わかりました。アプリで痛い場所を見せてください。","purpose":"代替手段｜翻訳ツールで意思疎通します。","a":"(types) My chest hurts.","ajp":"（入力）胸が痛いです。","next":"pain"},"pain":{"step":"S","q":"Is the pain strong? Show me with your fingers, one to ten.","qjp":"痛みは強いですか？指で1から10で示してください。","purpose":"重症度｜数字や身振りで程度を把握します。","a":"(holds up eight fingers)","ajp":"（指を8本立てる）","next":"allergy"},"allergy":{"step":"A","q":"Medicine allergy? Yes or no?","qjp":"薬のアレルギーは？あり？なし？","purpose":"Allergies｜短い言葉で安全確認します。","a":"No. No allergy.","ajp":"いいえ。アレルギーなし。","next":"family"},"family":{"step":"E","q":"Family? Can we call someone?","qjp":"ご家族は？誰かに電話できますか？","purpose":"支援｜連絡先と通訳者の確保を試みます。","a":"(nods) My son speaks English.","ajp":"（うなずく）息子が英語を話します。","end":{"impr":"Good. We'll call your son and get help. You are safe with us.","imprJp":"よかった。息子さんに電話して助けてもらいます。私たちがいるので安心してください。"}}},"cat":"基本","lv":10},{"id":"palpitations","icon":"💓","title":"動悸","en":"Palpitations","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the palpitations start?","qjp":"動悸はいつ始まりましたか？","purpose":"Onset｜発症のタイミングを確認します。","a":"Suddenly, about ten minutes ago.","ajp":"10分ほど前に急に始まりました。","next":"q"},"q":{"step":"Q","q":"Is your heartbeat regular or irregular?","qjp":"鼓動は規則的ですか、不規則ですか？","purpose":"Quality｜不整脈の種類を絞り込みます。","branch":{"question":"鼓動のリズムで疑う不整脈が変わります","options":[{"label":"It's fast but regular.","jp":"速いけど規則的です。","route":"→ 発作性頻拍を疑い随伴症状へ","next":"reg","setReply":{"a":"It's fast but steady.","ajp":"速いですが一定です。"}},{"label":"It's irregular and jumpy.","jp":"バラバラで飛ぶ感じです。","route":"→ 心房細動を疑い既往へ","next":"irreg","setReply":{"a":"It's irregular and skipping.","ajp":"不規則で飛ぶ感じです。"}}]}},"reg":{"step":"S","q":"Do you feel dizzy or short of breath?","qjp":"めまいや息切れはありますか？","purpose":"随伴症状｜循環不全の有無を確認します。","a":"A little dizzy, yes.","ajp":"少しめまいがします。","next":"t"},"irreg":{"step":"P","q":"Have you had heart rhythm problems before?","qjp":"以前に不整脈を指摘されたことは？","purpose":"既往｜心房細動等の既往を確認します。","a":"Yes, I have atrial fibrillation.","ajp":"はい、心房細動があります。","next":"t"},"t":{"step":"T","q":"Is it still going on right now?","qjp":"今もまだ続いていますか？","purpose":"Time｜持続性を確認します。","a":"Yes, it hasn't stopped.","ajp":"はい、止まりません。","end":{"impr":"Thank you. We'll check your heart rhythm right away.","imprJp":"ありがとうございます。すぐに心臓のリズムを確認しますね。"}}},"cat":"循環器","lv":4},{"id":"hypertension","icon":"🩺","title":"高血圧緊急症","en":"Hypertensive Emergency","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did you start feeling unwell?","qjp":"いつから具合が悪いですか？","purpose":"Onset｜発症の経過を確認します。","a":"For the past few hours.","ajp":"ここ数時間です。","next":"q"},"q":{"step":"Q","q":"Do you have a headache or chest pain?","qjp":"頭痛や胸痛はありますか？","purpose":"Quality｜臓器障害の徴候を探ります。","branch":{"question":"症状で標的臓器を絞り込みます","options":[{"label":"A very bad headache.","jp":"ひどい頭痛です。","route":"→ 脳の評価。視覚症状へ","next":"neuro","setReply":{"a":"Yes, a pounding headache.","ajp":"はい、ズキズキする頭痛です。"}},{"label":"Chest pain and shortness of breath.","jp":"胸痛と息切れです。","route":"→ 心臓の評価へ","next":"cardiac","setReply":{"a":"Chest pain and I'm short of breath.","ajp":"胸が痛くて息切れがします。"}}]}},"neuro":{"step":"R","q":"Are you having any vision changes?","qjp":"見え方に変化はありますか？","purpose":"標的臓器｜高血圧性脳症を評価します。","a":"My vision is a bit blurry.","ajp":"少しぼやけて見えます。","next":"p"},"cardiac":{"step":"R","q":"Do you have a history of heart disease?","qjp":"心臓病の既往はありますか？","purpose":"標的臓器｜心負荷を評価します。","a":"Yes, I had a heart attack before.","ajp":"はい、以前心筋梗塞をしました。","next":"p"},"p":{"step":"P","q":"Are you taking your blood pressure medicine?","qjp":"血圧の薬は飲めていますか？","purpose":"服薬｜コンプライアンスを確認します。","a":"I ran out a few days ago.","ajp":"数日前に切らしてしまいました。","end":{"impr":"Thank you. We'll monitor your pressure closely on the way.","imprJp":"ありがとうございます。搬送中、血圧を注意して見ますね。"}}},"cat":"循環器","lv":5},{"id":"dvt","icon":"🦵","title":"下肢の腫れ","en":"Leg Swelling (DVT)","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did your leg start to swell?","qjp":"脚はいつから腫れてきましたか？","purpose":"Onset｜発症の経過を確認します。","a":"Over the last two days.","ajp":"ここ2日ほどです。","next":"r"},"r":{"step":"R","q":"Is it one leg or both legs?","qjp":"片方の脚ですか、両脚ですか？","purpose":"Region｜DVTは片側性が多い特徴です。","branch":{"question":"片側か両側かで原因が分かれます","options":[{"label":"Just my right leg.","jp":"右脚だけです。","route":"→ DVTを疑い誘因へ","next":"dvt","setReply":{"a":"Just my right leg is swollen.","ajp":"右脚だけ腫れています。"}},{"label":"Both legs.","jp":"両脚です。","route":"→ 全身性を疑い既往へ","next":"both","setReply":{"a":"Both of my legs are swollen.","ajp":"両脚とも腫れています。"}}]}},"dvt":{"step":"P","q":"Have you been on a long trip or in bed recently?","qjp":"最近、長旅や長く寝込んだことは？","purpose":"誘因｜不動はDVTの危険因子です。","a":"Yes, I took a long flight.","ajp":"はい、長距離のフライトに乗りました。","next":"s"},"both":{"step":"P","q":"Do you have any heart or kidney problems?","qjp":"心臓や腎臓の病気はありますか？","purpose":"既往｜全身性浮腫の原因を探ります。","a":"I have some heart trouble.","ajp":"少し心臓が悪いです。","next":"s"},"s":{"step":"S","q":"Is the leg painful or warm to touch?","qjp":"脚は痛みますか、触ると熱いですか？","purpose":"Severity｜炎症・血栓の徴候を確認します。","a":"Yes, it's painful and warm.","ajp":"はい、痛くて熱を持っています。","end":{"impr":"Thank you. Please keep the leg still and we'll take you in.","imprJp":"ありがとうございます。脚を動かさずにいてください。お運びします。"}}},"cat":"循環器","lv":9},{"id":"hyperventilation","icon":"😤","title":"過換気","en":"Hyperventilation","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What are you feeling right now?","qjp":"今、どんな感じがしますか？","purpose":"Signs｜症状と誘因を把握します。","a":"My hands are tingling and I can't breathe well.","ajp":"手がしびれて、うまく息ができません。","next":"e1"},"e1":{"step":"E","q":"Did something stressful just happen?","qjp":"直前に何かストレスになることが？","purpose":"Events｜心因性の誘因を探ります。","branch":{"question":"誘因の有無で対応が分かれます","options":[{"label":"Yes, I got very upset.","jp":"はい、とても動揺しました。","route":"→ 心因性。落ち着かせる対応へ","next":"calm","setReply":{"a":"Yes, I just had a big shock.","ajp":"はい、強いショックを受けました。"}},{"label":"No, it started on its own.","jp":"いいえ、自然に始まりました。","route":"→ 器質的原因の除外へ","next":"organic","setReply":{"a":"No, it came on by itself.","ajp":"いいえ、ひとりでに始まりました。"}}]}},"calm":{"step":"S","q":"Try to breathe slowly with me. Can you do that?","qjp":"私と一緒にゆっくり呼吸できますか？","purpose":"対応｜呼吸の誘導で症状を和らげます。","a":"Okay, I'll try.","ajp":"はい、やってみます。","next":"p"},"organic":{"step":"P","q":"Do you have any heart or lung conditions?","qjp":"心臓や肺の病気はありますか？","purpose":"既往｜器質的疾患を除外します。","a":"No, nothing like that.","ajp":"いいえ、そういったものはありません。","next":"p"},"p":{"step":"P","q":"Have you ever had a panic attack before?","qjp":"以前にパニック発作を起こしたことは？","purpose":"既往｜過去のエピソードを確認します。","a":"Yes, a few times.","ajp":"はい、何度かあります。","end":{"impr":"You're safe. Keep breathing slowly with me. It will pass.","imprJp":"大丈夫です。一緒にゆっくり呼吸しましょう。必ず落ち着きます。"}}},"cat":"呼吸器","lv":8},{"id":"identity-verification","icon":"🆔","title":"本人確認","en":"Identity Verification","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What is your full name?","qjp":"お名前をフルネームで教えていただけますか？","purpose":"Signs｜患者様の基本情報を確認します。","a":"My name is John Smith.","ajp":"私の名前はジョン・スミスです。","next":"a"},"a":{"step":"A","q":"When is your date of birth?","qjp":"お生まれはいつですか？","purpose":"Allergies｜年齢・生年月日を確認します。","a":"I was born on March 15, 1980.","ajp":"1980年3月15日生まれです。","next":"m"},"m":{"step":"M","q":"What is your address?","qjp":"ご住所を教えていただけますか？","purpose":"Medications｜住所で本人確認を完了します。","a":"I live at 123 Main Street.","ajp":"メインストリート123番地に住んでいます。","end":{"impr":"Thank you for confirming your identity. We're ready to assist you.","imprJp":"本人確認ありがとうございました。これからサポートさせていただきます。"}}},"cat":"初期対応","lv":1},{"id":"copd","icon":"🚬","title":"COPD増悪","en":"COPD Flare-up","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did your breathing get worse?","qjp":"呼吸が悪くなったのはいつからですか？","purpose":"Onset｜増悪の経過を確認します。","a":"It's been getting worse for two days.","ajp":"2日ほどかけて悪くなっています。","next":"p"},"p":{"step":"P","q":"Do you have more phlegm than usual?","qjp":"普段より痰は増えていますか？","purpose":"Provocation｜感染性増悪を評価します。","branch":{"question":"痰の様子で感染の有無を見ます","options":[{"label":"Yes, and it's yellow-green.","jp":"はい、黄緑色です。","route":"→ 感染性。発熱を確認","next":"infect","setReply":{"a":"Yes, it's yellow and green.","ajp":"はい、黄色と緑色です。"}},{"label":"No, about the same.","jp":"いいえ、いつも通りです。","route":"→ 非感染性。誘因を確認","next":"trigger","setReply":{"a":"No, it's about the same.","ajp":"いいえ、いつもと同じくらいです。"}}]}},"infect":{"step":"R","q":"Do you have a fever?","qjp":"熱はありますか？","purpose":"随伴症状｜気道感染を裏づけます。","a":"Yes, I feel feverish.","ajp":"はい、熱っぽいです。","next":"s"},"trigger":{"step":"R","q":"Were you exposed to smoke or cold air?","qjp":"煙や冷気にあたりましたか？","purpose":"誘因｜増悪の引き金を探ります。","a":"It was very cold outside.","ajp":"外がとても寒かったです。","next":"s"},"s":{"step":"S","q":"Are you using your home oxygen?","qjp":"自宅の酸素は使っていますか？","purpose":"治療｜在宅酸素の使用を確認します。","a":"Yes, but it's not enough now.","ajp":"はい、でも今は足りません。","end":{"impr":"Okay, we'll support your breathing carefully. Stay calm.","imprJp":"わかりました、慎重に呼吸を助けます。落ち着いていてください。"}}},"cat":"呼吸器","lv":3},{"id":"vomiting","icon":"🤮","title":"嘔吐","en":"Vomiting","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the vomiting start?","qjp":"嘔吐はいつ始まりましたか？","purpose":"Onset｜発症の経過を確認します。","a":"Since early this morning.","ajp":"今朝早くからです。","next":"q"},"q":{"step":"Q","q":"What does the vomit look like?","qjp":"吐いたものはどんな様子ですか？","purpose":"Quality｜吐物の性状で原因を絞ります。","branch":{"question":"吐物の様子で危険度が分かれます","options":[{"label":"Just food and liquid.","jp":"食べ物と液体だけです。","route":"→ 通常。脱水を評価","next":"normal","setReply":{"a":"Just food and some liquid.","ajp":"食べ物と液体だけです。"}},{"label":"There was blood in it.","jp":"血が混じっていました。","route":"→ 消化管出血を疑う","next":"blood","setReply":{"a":"There was some blood in it.","ajp":"血が少し混じっていました。"}}]}},"normal":{"step":"S","q":"Can you keep any water down?","qjp":"水分はとれていますか？","purpose":"重症度｜脱水の進行を評価します。","a":"No, I bring it all up.","ajp":"いいえ、全部吐いてしまいます。","next":"t"},"blood":{"step":"S","q":"How much blood did you see?","qjp":"血はどのくらい見えましたか？","purpose":"重症度｜出血量を把握します。","a":"A small amount, dark red.","ajp":"少量で、暗い赤色でした。","next":"t"},"t":{"step":"T","q":"Do you have stomach pain or diarrhea too?","qjp":"腹痛や下痢もありますか？","purpose":"随伴症状｜消化器疾患を絞り込みます。","a":"Yes, some stomach cramps.","ajp":"はい、お腹がさしこみます。","end":{"impr":"Thank you. Try small sips of water only if you can.","imprJp":"ありがとうございます。可能なら水を少量ずつだけにしてください。"}}},"cat":"消化器","lv":3},{"id":"headache","icon":"🤕","title":"激しい頭痛","en":"Severe Headache","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did this headache start?","qjp":"この頭痛はいつ始まりましたか？","purpose":"Onset｜突発発症は危険なサインです。","branch":{"question":"発症の仕方で緊急度が分かれます","options":[{"label":"It hit suddenly, like a thunderclap.","jp":"突然、雷に打たれたようにです。","route":"→ くも膜下出血を疑う","next":"sudden","setReply":{"a":"Suddenly, like being hit hard.","ajp":"突然、強く殴られたようにです。"}},{"label":"It built up slowly.","jp":"だんだん強くなりました。","route":"→ 緊張型/片頭痛を評価","next":"gradual","setReply":{"a":"It came on slowly.","ajp":"ゆっくり強くなりました。"}}]}},"sudden":{"step":"S","q":"Is this the worst headache of your life?","qjp":"人生で最悪の頭痛ですか？","purpose":"Severity｜最悪の頭痛は重大疾患を示唆します。","a":"Yes, by far the worst.","ajp":"はい、断然これまでで最悪です。","next":"assoc"},"gradual":{"step":"S","q":"Have you had headaches like this before?","qjp":"以前にも似た頭痛はありましたか？","purpose":"既往｜反復性か初発かを区別します。","a":"Yes, similar to my migraines.","ajp":"はい、片頭痛に似ています。","next":"assoc"},"assoc":{"step":"R","q":"Do you have neck stiffness or vomiting?","qjp":"首のこわばりや嘔吐はありますか？","purpose":"随伴症状｜髄膜刺激徴候を評価します。","a":"My neck is stiff and I feel sick.","ajp":"首が硬く、吐き気がします。","end":{"impr":"Thank you. Please keep still and we'll get you checked quickly.","imprJp":"ありがとうございます。動かずにいてください。すぐに調べます。"}}},"cat":"神経","lv":1},{"id":"vertigo","icon":"🌀","title":"めまい","en":"Dizziness / Vertigo","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the dizziness begin?","qjp":"めまいはいつ始まりましたか？","purpose":"Onset｜発症の経過を確認します。","a":"This morning when I woke up.","ajp":"今朝起きたときです。","next":"q"},"q":{"step":"Q","q":"Does the room feel like it's spinning?","qjp":"周りがぐるぐる回る感じですか？","purpose":"Quality｜回転性か浮動性かを区別します。","branch":{"question":"めまいの種類で原因が分かれます","options":[{"label":"Yes, everything spins.","jp":"はい、全部回ります。","route":"→ 末梢性を疑い体位へ","next":"spin","setReply":{"a":"Yes, the room is spinning.","ajp":"はい、部屋が回っています。"}},{"label":"No, I just feel faint.","jp":"いいえ、フラッとする感じです。","route":"→ 失神性を疑い随伴症状へ","next":"faint","setReply":{"a":"No, I just feel light-headed.","ajp":"いいえ、フラッとするだけです。"}}]}},"spin":{"step":"P","q":"Does it get worse when you move your head?","qjp":"頭を動かすと悪化しますか？","purpose":"誘因｜体位性めまいを評価します。","a":"Yes, much worse.","ajp":"はい、ずっとひどくなります。","next":"r"},"faint":{"step":"P","q":"Do you have any weakness or trouble speaking?","qjp":"脱力やしゃべりにくさはありますか？","purpose":"中枢性｜脳卒中を除外します。","a":"No, just the dizziness.","ajp":"いいえ、めまいだけです。","next":"r"},"r":{"step":"R","q":"Do you have ringing in your ears or hearing loss?","qjp":"耳鳴りや聞こえにくさはありますか？","purpose":"随伴症状｜内耳性疾患を評価します。","a":"My right ear feels blocked.","ajp":"右耳が詰まった感じです。","end":{"impr":"Thank you. Please don't stand up suddenly. We'll help you.","imprJp":"ありがとうございます。急に立たないでください。介助します。"}}},"cat":"神経","lv":8},{"id":"fracture","icon":"🦴","title":"骨折","en":"Fracture","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"How did the injury happen?","qjp":"どうやって怪我をしましたか？","purpose":"受傷機転｜骨折の様式を推定します。","a":"I twisted my ankle on the stairs.","ajp":"階段で足首をひねりました。","next":"p"},"p":{"step":"P","q":"Can you put any weight on it?","qjp":"体重をかけられますか？","purpose":"Provocation｜荷重可否で重症度を見ます。","branch":{"question":"荷重できるかで疑いが分かれます","options":[{"label":"No, it's far too painful.","jp":"いいえ、痛すぎて無理です。","route":"→ 骨折を強く疑う","next":"frac","setReply":{"a":"No, I can't put weight on it.","ajp":"いいえ、体重をかけられません。"}},{"label":"A little, but it hurts.","jp":"少しは。でも痛いです。","route":"→ 捻挫/不全骨折を評価","next":"sprain","setReply":{"a":"A little, but it really hurts.","ajp":"少しは。でもかなり痛いです。"}}]}},"frac":{"step":"R","q":"Is there any deformity or swelling?","qjp":"変形や腫れはありますか？","purpose":"観察｜変形は骨折の確実な徴候です。","a":"Yes, it looks crooked and swollen.","ajp":"はい、曲がって腫れています。","next":"s"},"sprain":{"step":"R","q":"Can you move your toes normally?","qjp":"足の指は普通に動かせますか？","purpose":"神経血管｜末梢の循環・神経を確認します。","a":"Yes, but it's painful.","ajp":"はい、でも痛いです。","next":"s"},"s":{"step":"S","q":"How bad is the pain, one to ten?","qjp":"痛みは10段階でどのくらいですか？","purpose":"Severity｜重症度を数値化します。","a":"About a seven.","ajp":"7くらいです。","end":{"impr":"Thank you. We'll splint it and keep it still for you.","imprJp":"ありがとうございます。固定して動かないようにしますね。"}}},"cat":"外傷","lv":3},{"id":"alcohol","icon":"🍺","title":"急性アルコール中毒","en":"Alcohol Intoxication","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Can you tell me how much you drank?","qjp":"どのくらい飲んだか教えてもらえますか？","purpose":"Signs｜摂取量と意識を評価します。","a":"A lot... I lost count.","ajp":"たくさん…分からなくなりました。","next":"e1"},"e1":{"step":"E","q":"Did you take anything else with the alcohol?","qjp":"お酒と一緒に他のものは？","purpose":"Events｜薬物併用を確認します。","branch":{"question":"併用の有無で危険度が分かれます","options":[{"label":"Yes, some pills too.","jp":"はい、薬も少し。","route":"→ 併用中毒を疑い緊急評価","next":"mixed","setReply":{"a":"Yes, I took some pills too.","ajp":"はい、薬も少し飲みました。"}},{"label":"No, just alcohol.","jp":"いいえ、お酒だけです。","route":"→ 意識・気道を確認","next":"alone","setReply":{"a":"No, just alcohol.","ajp":"いいえ、お酒だけです。"}}]}},"mixed":{"step":"S","q":"What pills did you take?","qjp":"どんな薬を飲みましたか？","purpose":"危険｜併用物質を特定します。","a":"Some sleeping tablets.","ajp":"睡眠薬を少し。","next":"a"},"alone":{"step":"S","q":"Are you feeling sick or going to vomit?","qjp":"気分が悪い、吐きそうですか？","purpose":"気道｜誤嚥リスクを評価します。","a":"Yes, I feel sick.","ajp":"はい、気持ち悪いです。","next":"a"},"a":{"step":"A","q":"Do you have any medical conditions?","qjp":"持病はありますか？","purpose":"既往｜基礎疾患を確認します。","a":"No, I don't think so.","ajp":"いいえ、たぶんありません。","end":{"impr":"Thank you. We'll keep you on your side and watch you closely.","imprJp":"ありがとうございます。横向きにして、しっかり見守りますね。"}}},"cat":"環境・中毒","lv":6},{"id":"diarrhea","icon":"🚽","title":"下痢・脱水","en":"Diarrhea / Dehydration","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How long have you had diarrhea?","qjp":"下痢はどのくらい続いていますか？","purpose":"Signs｜経過と脱水を評価します。","a":"For about two days.","ajp":"2日ほどです。","next":"e1"},"e1":{"step":"E","q":"Did you eat anything unusual?","qjp":"何か変わったものを食べましたか？","purpose":"Events｜食中毒等の誘因を探ります。","branch":{"question":"心当たりで原因が分かれます","options":[{"label":"I ate raw seafood.","jp":"生の魚介を食べました。","route":"→ 食中毒を疑い随伴症状へ","next":"food","setReply":{"a":"I ate some raw seafood.","ajp":"生の魚介を食べました。"}},{"label":"Nothing unusual.","jp":"特に変わったものは。","route":"→ 感染性を疑い水分へ","next":"infect","setReply":{"a":"Nothing unusual, really.","ajp":"本当に普段通りです。"}}]}},"food":{"step":"S","q":"Do you have a fever or vomiting?","qjp":"発熱や嘔吐はありますか？","purpose":"随伴症状｜感染の重症度を評価します。","a":"Yes, both.","ajp":"はい、両方あります。","next":"l"},"infect":{"step":"S","q":"Are others around you sick too?","qjp":"周りにも具合の悪い人は？","purpose":"疫学｜集団発生を確認します。","a":"My family has it too.","ajp":"家族も同じ症状です。","next":"l"},"l":{"step":"L","q":"Are you able to drink fluids?","qjp":"水分はとれていますか？","purpose":"Last intake｜脱水の程度を評価します。","a":"A little, but I feel very dry.","ajp":"少しだけ。でもカラカラです。","end":{"impr":"Thank you. We'll give you fluids to help you feel better.","imprJp":"ありがとうございます。点滴で水分を補って楽にしますね。"}}},"cat":"消化器","lv":1},{"id":"headinjury","icon":"🤜","title":"頭部外傷","en":"Head Injury","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"How did you injure your head?","qjp":"どうやって頭を負傷しましたか？","purpose":"受傷機転｜損傷の重症度を予測します。","a":"I was hit by a falling object.","ajp":"落下物が当たりました。","next":"d"},"d":{"step":"D","q":"Did you lose consciousness at all?","qjp":"意識を失いましたか？","purpose":"Deformity/意識｜外傷性脳損傷を評価します。","branch":{"question":"意識消失の有無で評価が分かれます","options":[{"label":"Yes, for a minute or so.","jp":"はい、1分ほど。","route":"→ 神経症状の確認へ","next":"loc","setReply":{"a":"Yes, I blacked out briefly.","ajp":"はい、少しの間気を失いました。"}},{"label":"No, I stayed awake.","jp":"いいえ、意識はありました。","route":"→ 症状の確認へ","next":"awake","setReply":{"a":"No, I stayed conscious.","ajp":"いいえ、意識はありました。"}}]}},"loc":{"step":"T","q":"Do you feel confused or have memory gaps?","qjp":"混乱や記憶の抜けはありますか？","purpose":"神経症状｜脳震盪を評価します。","a":"I don't remember the moment it happened.","ajp":"ぶつかった瞬間を覚えていません。","next":"l"},"awake":{"step":"T","q":"Are you nauseous or seeing double?","qjp":"吐き気や物が二重に見えることは？","purpose":"神経症状｜頭蓋内圧亢進を評価します。","a":"A little nauseous.","ajp":"少し吐き気があります。","next":"l"},"l":{"step":"L","q":"Are you taking any blood thinners?","qjp":"血液をサラサラにする薬は飲んでいますか？","purpose":"既往｜頭蓋内出血のリスクを評価します。","a":"Yes, I am.","ajp":"はい、飲んでいます。","end":{"impr":"Thank you. Please keep your head still while we assess you.","imprJp":"ありがとうございます。評価の間、頭を動かさずにいてください。"}}},"cat":"外傷","lv":3},{"id":"spinal","icon":"🦴","title":"脊椎損傷疑い","en":"Spinal Injury","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"How did the accident happen?","qjp":"どのように事故が起きましたか？","purpose":"受傷機転｜高エネルギー外傷を評価します。","a":"I dove into shallow water.","ajp":"浅い水に飛び込みました。","next":"d"},"d":{"step":"D","q":"Please don't move. Can you feel your legs?","qjp":"動かないで。脚の感覚はありますか？","purpose":"神経｜脊髄損傷を評価します。","branch":{"question":"感覚・運動の有無で重症度が分かれます","options":[{"label":"No, I can't feel them.","jp":"いいえ、感覚がありません。","route":"→ 完全固定。慎重に対応","next":"severe","setReply":{"a":"No, I cannot feel my legs.","ajp":"いいえ、脚の感覚がありません。"}},{"label":"Yes, but they tingle.","jp":"はい、でもしびれます。","route":"→ 不全損傷を疑い固定","next":"partial","setReply":{"a":"Yes, but they are tingling.","ajp":"はい、でもしびれています。"}}]}},"severe":{"step":"T","q":"Do you have neck or back pain?","qjp":"首や背中に痛みはありますか？","purpose":"圧痛｜損傷高位を推定します。","a":"My neck hurts a lot.","ajp":"首がとても痛いです。","next":"l"},"partial":{"step":"T","q":"Can you wiggle your toes for me?","qjp":"足の指を動かせますか？","purpose":"運動｜残存機能を確認します。","a":"Just a little.","ajp":"少しだけ動きます。","next":"l"},"l":{"step":"L","q":"Stay completely still. Any arm weakness?","qjp":"完全に動かないで。腕の脱力は？","purpose":"神経｜頸髄損傷の高位を評価します。","a":"My hands feel weak too.","ajp":"手も力が入りません。","end":{"impr":"Stay still. We will immobilize your spine and move you as one unit.","imprJp":"動かないで。脊椎を固定し、体全体で慎重に動かします。"}}},"cat":"外傷","lv":4},{"id":"sting","icon":"🐝","title":"蜂刺され・虫咬傷","en":"Sting / Bite","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What stung or bit you?","qjp":"何に刺されたり咬まれましたか？","purpose":"Signs｜原因生物を特定します。","a":"A bee stung my arm.","ajp":"蜂に腕を刺されました。","next":"a"},"a":{"step":"A","q":"Are you having any whole-body symptoms?","qjp":"全身の症状はありますか？","purpose":"Allergies｜全身反応を評価します。","branch":{"question":"全身症状の有無で緊急度が分かれます","options":[{"label":"My throat feels tight.","jp":"喉が締めつけられます。","route":"→ アナフィラキシーを疑い緊急対応","next":"systemic","setReply":{"a":"My throat is getting tight.","ajp":"喉が締めつけられてきました。"}},{"label":"Just local pain and swelling.","jp":"刺された所が痛くて腫れるだけです。","route":"→ 局所反応。針を確認","next":"local","setReply":{"a":"Just pain and swelling here.","ajp":"ここが痛くて腫れるだけです。"}}]}},"systemic":{"step":"M","q":"Do you have an epinephrine pen?","qjp":"エピネフリンの注射器を持っていますか？","purpose":"Medications｜エピペンの有無は救命に直結します。","a":"Yes, in my pocket.","ajp":"はい、ポケットにあります。","next":"e"},"local":{"step":"A","q":"Is the stinger still in your skin?","qjp":"針はまだ皮膚に残っていますか？","purpose":"処置｜残存した針の除去を確認します。","a":"Yes, I can see it.","ajp":"はい、見えています。","next":"e"},"e":{"step":"E","q":"Have you reacted badly to stings before?","qjp":"以前、刺されてひどい反応は？","purpose":"既往｜過去の反応歴を確認します。","a":"No, never like this.","ajp":"いいえ、こんなのは初めてです。","end":{"impr":"Thank you. We will watch you closely for any reaction.","imprJp":"ありがとうございます。反応が出ないか注意して見ますね。"}}},"cat":"環境・中毒","lv":2},{"id":"pedseizure","icon":"🧒","title":"小児の熱性けいれん","en":"Febrile Seizure","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Is your child shaking now, or has it stopped?","qjp":"お子さんは今けいれんしていますか、止まりましたか？","purpose":"Signs｜現在の発作状況を確認します。","a":"It just stopped a minute ago.","ajp":"1分前に止まりました。","next":"e1"},"e1":{"step":"E","q":"How long did the shaking last?","qjp":"けいれんはどのくらい続きましたか？","purpose":"Events｜持続時間で重症度を判断します。","branch":{"question":"持続時間で緊急度が分かれます","options":[{"label":"Less than two minutes.","jp":"2分未満です。","route":"→ 単純型。発熱を確認","next":"simple","setReply":{"a":"Less than two minutes.","ajp":"2分未満です。"}},{"label":"Over five minutes.","jp":"5分以上です。","route":"→ 複雑型。緊急対応へ","next":"complex","setReply":{"a":"More than five minutes.","ajp":"5分以上です。"}}]}},"simple":{"step":"S","q":"Does your child have a high fever?","qjp":"お子さんは高い熱がありますか？","purpose":"誘因｜熱性けいれんの背景を確認します。","a":"Yes, very hot to touch.","ajp":"はい、触ると熱いです。","next":"p"},"complex":{"step":"S","q":"Is your child awake and responding now?","qjp":"お子さんは今、起きて反応しますか？","purpose":"重症度｜発作後の意識を確認します。","a":"Drowsy, but responding a little.","ajp":"ぼんやりですが、少し反応します。","next":"p"},"p":{"step":"P","q":"Has your child had seizures before?","qjp":"以前にもけいれんはありましたか？","purpose":"既往｜反復性を確認します。","a":"No, this is the first.","ajp":"いいえ、初めてです。","end":{"impr":"Thank you. Keep your child on their side. We're here now.","imprJp":"ありがとうございます。お子さんを横向きに。もう大丈夫です。"}}},"cat":"小児","lv":6},{"id":"depression","icon":"💙","title":"抑うつ・無気力","en":"Depression / Low Mood","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"I'm here to listen. How have you been feeling?","qjp":"お話を聞きに来ました。どんなお気持ちですか？","purpose":"信頼関係｜傾聴の姿勢を示します。","a":"Empty, and very tired of everything.","ajp":"空っぽで、何もかも疲れました。","next":"e1"},"e1":{"step":"E","q":"How long have you felt this way?","qjp":"いつからそう感じていますか？","purpose":"Events｜経過を把握します。","branch":{"question":"危機の度合いで対応が分かれます","options":[{"label":"For months now.","jp":"もう何ヶ月もです。","route":"→ 支援体制を確認","next":"chronic","setReply":{"a":"For months now.","ajp":"もう何ヶ月もです。"}},{"label":"I've thought about ending it.","jp":"終わりにしたいと考えました。","route":"→ 安全を最優先に確認","next":"risk","setReply":{"a":"Lately I've thought about giving up.","ajp":"最近、もうやめたいと考えました。"}}]}},"risk":{"step":"S","q":"Thank you for telling me. Are you safe right now?","qjp":"話してくれてありがとう。今、安全ですか？","purpose":"安全｜危機介入を最優先します。","a":"I think so, for now.","ajp":"今は…たぶん。","next":"support"},"chronic":{"step":"S","q":"Are you able to eat and sleep?","qjp":"食事や睡眠はとれていますか？","purpose":"評価｜身体への影響を確認します。","a":"Not really, I barely sleep.","ajp":"あまり。ほとんど眠れません。","next":"support"},"support":{"step":"P","q":"Is there someone supporting you right now?","qjp":"今、支えてくれる人はいますか？","purpose":"支援｜サポート体制を確認します。","a":"My sister checks on me.","ajp":"姉が気にかけてくれます。","end":{"impr":"Thank you for trusting me. You don't have to face this alone.","imprJp":"信頼してくれてありがとう。一人で抱えなくて大丈夫です。"}}},"cat":"精神","lv":8},{"id":"fever_inf","icon":"🌡️","title":"発熱・感染症","en":"Fever / Infection","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How high is the fever and how long?","qjp":"熱はどのくらい高く、いつからですか？","purpose":"Signs｜発熱の経過を確認します。","a":"Thirty-nine degrees for two days.","ajp":"39度が2日続いています。","next":"e1"},"e1":{"step":"E","q":"Where do you think the infection is?","qjp":"どこの感染だと思いますか？","purpose":"Events｜感染源を探ります。","branch":{"question":"随伴症状で感染源が分かれます","options":[{"label":"I have a cough and chest pain.","jp":"咳と胸の痛みがあります。","route":"→ 肺炎を疑う","next":"chest","setReply":{"a":"A cough and chest pain.","ajp":"咳と胸の痛みです。"}},{"label":"Burning when I urinate.","jp":"排尿時に焼ける感じです。","route":"→ 尿路感染を疑う","next":"urine","setReply":{"a":"It burns when I urinate.","ajp":"排尿時に焼ける感じがします。"}}]}},"chest":{"step":"S","q":"Are you short of breath?","qjp":"息切れはありますか？","purpose":"重症度｜呼吸状態を評価します。","a":"A little when I move.","ajp":"動くと少し。","next":"a"},"urine":{"step":"S","q":"Do you have back pain or chills?","qjp":"背中の痛みや悪寒は？","purpose":"重症度｜腎盂腎炎・敗血症を評価します。","a":"Yes, my back aches.","ajp":"はい、背中が痛みます。","next":"a"},"a":{"step":"A","q":"Do you have any allergies to antibiotics?","qjp":"抗生物質のアレルギーはありますか？","purpose":"Allergies｜投薬前に確認します。","a":"No, none.","ajp":"いいえ、ありません。","end":{"impr":"Thank you. We'll check your vitals and start treatment.","imprJp":"ありがとうございます。バイタルを確認し、治療を始めますね。"}}},"cat":"感染","lv":5},{"id":"hemoptysis","icon":"🩸","title":"喀血","en":"Coughing Blood","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did you start coughing up blood?","qjp":"いつから血を吐き始めましたか？","purpose":"Onset｜発症の経過を確認します。","a":"This morning.","ajp":"今朝からです。","next":"s"},"s":{"step":"S","q":"How much blood are we talking about?","qjp":"出血量はどのくらいですか？","purpose":"Severity｜出血量は緊急度を左右します。","branch":{"question":"出血量で緊急度が分かれます","options":[{"label":"Just streaks in my spit.","jp":"唾に血が混じる程度です。","route":"→ 少量。既往の確認へ","next":"minor","setReply":{"a":"Just a few streaks in my spit.","ajp":"唾に少し筋状に混じる程度です。"}},{"label":"A lot, like a cupful.","jp":"カップ一杯くらい大量です。","route":"→ 大量。緊急評価へ","next":"major","setReply":{"a":"A lot, almost a cupful.","ajp":"カップ一杯近い大量です。"}}]}},"minor":{"step":"P","q":"Do you have a cough or a cold?","qjp":"咳や風邪はありますか？","purpose":"随伴症状｜気道感染を評価します。","a":"Yes, I've had a bad cough.","ajp":"はい、ひどい咳が続いています。","next":"hx"},"major":{"step":"P","q":"Do you feel dizzy or faint?","qjp":"めまいや気の遠くなる感じは？","purpose":"重症度｜循環への影響を確認します。","a":"Yes, very dizzy.","ajp":"はい、ひどくめまいがします。","next":"hx"},"hx":{"step":"T","q":"Do you have any lung disease?","qjp":"肺の病気はありますか？","purpose":"既往｜結核・腫瘍等の背景を確認します。","a":"I had tuberculosis years ago.","ajp":"何年も前に結核をしました。","end":{"impr":"Thank you. Please sit upright and try to stay calm.","imprJp":"ありがとうございます。上体を起こして、落ち着いていてください。"}}},"cat":"呼吸器","lv":4},{"id":"gibleed","icon":"🟥","title":"吐血","en":"Vomiting Blood","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"You're vomiting blood. How are you feeling?","qjp":"吐血されていますね。気分はどうですか？","purpose":"Signs｜循環状態を評価します。","a":"Weak and a bit dizzy.","ajp":"だるくて、少しめまいがします。","next":"color"},"color":{"step":"S","q":"Was the blood bright red or dark?","qjp":"血は鮮やかな赤でしたか、暗い色でしたか？","purpose":"色｜出血源の高さを推定します。","branch":{"question":"血の色で出血源が分かれます","options":[{"label":"Bright red blood.","jp":"鮮やかな赤い血です。","route":"→ 活動性出血を疑う","next":"bright","setReply":{"a":"It was bright red.","ajp":"鮮やかな赤でした。"}},{"label":"Dark, like coffee grounds.","jp":"コーヒーかすのような暗い色です。","route":"→ 古い出血を疑う","next":"dark","setReply":{"a":"Dark, like coffee grounds.","ajp":"コーヒーかすのような暗い色でした。"}}]}},"bright":{"step":"P","q":"Do you have liver disease or ulcers?","qjp":"肝臓の病気や潰瘍はありますか？","purpose":"既往｜静脈瘤や潰瘍を評価します。","a":"I have liver problems.","ajp":"肝臓が悪いです。","next":"m"},"dark":{"step":"P","q":"Do you take painkillers regularly?","qjp":"鎮痛薬を常用していますか？","purpose":"既往｜薬剤性潰瘍を評価します。","a":"Yes, almost every day.","ajp":"はい、ほぼ毎日です。","next":"m"},"m":{"step":"M","q":"Are you on any blood thinners?","qjp":"血液をサラサラにする薬は飲んでいますか？","purpose":"Medications｜出血リスクを評価します。","a":"Yes, I take one.","ajp":"はい、飲んでいます。","end":{"impr":"Thank you. Lie on your side and we'll move quickly.","imprJp":"ありがとうございます。横向きに寝て。すぐにお運びします。"}}},"cat":"消化器","lv":2},{"id":"meningitis","icon":"🧫","title":"髄膜炎疑い","en":"Suspected Meningitis","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms do you have?","qjp":"どんな症状がありますか？","purpose":"Signs｜古典的三徴を探ります。","a":"Bad headache, fever and a stiff neck.","ajp":"ひどい頭痛、発熱、首のこわばりです。","next":"e1"},"e1":{"step":"E","q":"Do bright lights bother your eyes?","qjp":"まぶしい光がつらいですか？","purpose":"Events｜羞明は髄膜刺激徴候です。","branch":{"question":"光過敏と発疹で緊急度が分かれます","options":[{"label":"Yes, and I have a rash.","jp":"はい、発疹も出ています。","route":"→ 髄膜炎菌を疑い緊急対応","next":"rash","setReply":{"a":"Yes, and I noticed a rash.","ajp":"はい、発疹にも気づきました。"}},{"label":"Light bothers me, but no rash.","jp":"光はつらいですが発疹は無いです。","route":"→ 経過と既往の確認へ","next":"norash","setReply":{"a":"Light hurts, but I see no rash.","ajp":"光はつらいですが発疹は見当たりません。"}}]}},"rash":{"step":"S","q":"Does the rash fade when you press it?","qjp":"発疹は押すと消えますか？","purpose":"重症度｜消えない発疹は緊急です。","a":"No, it stays purple.","ajp":"いいえ、紫のまま消えません。","next":"a"},"norash":{"step":"E","q":"How quickly did this come on?","qjp":"どのくらい急に出ましたか？","purpose":"経過｜急性発症の緊急度を評価します。","a":"Within a few hours.","ajp":"数時間のうちにです。","next":"a"},"a":{"step":"A","q":"Have you been around anyone sick recently?","qjp":"最近、病気の人と接触は？","purpose":"疫学｜接触歴を確認します。","a":"A classmate was hospitalized.","ajp":"クラスメイトが入院しました。","end":{"impr":"Thank you. This may be serious, so we're moving fast.","imprJp":"ありがとうございます。重い可能性があるので、急ぎます。"}}},"cat":"神経","lv":3},{"id":"stab","icon":"🔪","title":"刺創","en":"Stab Wound","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"Where were you stabbed?","qjp":"どこを刺されましたか？","purpose":"受傷部位｜損傷臓器を推定します。","a":"In my upper belly.","ajp":"お腹の上の方です。","next":"d"},"d":{"step":"D","q":"Is the object still in the wound?","qjp":"刺さったものはまだ刺さっていますか？","purpose":"異物｜刺入物は抜かず固定が原則です。","branch":{"question":"異物の有無で対応が分かれます","options":[{"label":"No, it was pulled out.","jp":"いいえ、抜かれました。","route":"→ 出血評価へ","next":"out","setReply":{"a":"No, it's been pulled out.","ajp":"いいえ、抜かれてしまいました。"}},{"label":"Yes, it's still in.","jp":"はい、まだ刺さっています。","route":"→ 抜かず固定。安静へ","next":"in","setReply":{"a":"Yes, it's still stuck in me.","ajp":"はい、まだ刺さったままです。"}}]}},"out":{"step":"T","q":"Is it bleeding a lot right now?","qjp":"今、出血は多いですか？","purpose":"出血｜失血の評価と圧迫を判断します。","a":"Yes, quite a lot.","ajp":"はい、かなり多いです。","next":"breath"},"in":{"step":"T","q":"Please don't move. Does it hurt to breathe?","qjp":"動かないで。呼吸すると痛みますか？","purpose":"安静｜胸腹部損傷を評価します。","a":"Yes, it hurts to breathe.","ajp":"はい、息をすると痛みます。","next":"breath"},"breath":{"step":"L","q":"Are you feeling cold or very thirsty?","qjp":"寒気や強いのどの渇きは？","purpose":"ショック｜出血性ショックの徴候を評価します。","a":"Yes, I feel cold and shaky.","ajp":"はい、寒くて震えます。","end":{"impr":"Thank you. Stay still, we're controlling the bleeding now.","imprJp":"ありがとうございます。動かないで。今、出血を抑えています。"}}},"cat":"外傷","lv":4},{"id":"drowning","icon":"🌊","title":"溺水","en":"Drowning","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How are you breathing now?","qjp":"今、呼吸はどうですか？","purpose":"Signs｜呼吸状態を最優先で評価します。","a":"I'm coughing a lot and wheezing.","ajp":"咳がひどく、ゼーゼーします。","next":"e1"},"e1":{"step":"E","q":"How long were you underwater?","qjp":"どのくらい水中にいましたか？","purpose":"Events｜水没時間は低酸素の指標です。","branch":{"question":"水没時間で重症度が分かれます","options":[{"label":"Just a few seconds.","jp":"数秒だけです。","route":"→ 軽症。経過観察へ","next":"brief","setReply":{"a":"Only a few seconds.","ajp":"ほんの数秒です。"}},{"label":"Maybe a minute or more.","jp":"1分以上かもしれません。","route":"→ 重症。低酸素を評価","next":"long","setReply":{"a":"Maybe a minute or longer.","ajp":"1分以上かもしれません。"}}]}},"brief":{"step":"S","q":"Did you swallow or breathe in water?","qjp":"水を飲んだり吸い込んだりしましたか？","purpose":"気道｜誤嚥の有無を確認します。","a":"I swallowed some.","ajp":"少し飲みました。","next":"temp"},"long":{"step":"S","q":"Do you feel very tired or confused?","qjp":"強い疲れや混乱はありますか？","purpose":"低酸素｜中枢神経への影響を評価します。","a":"Yes, very tired.","ajp":"はい、とても疲れています。","next":"temp"},"temp":{"step":"E","q":"Was the water very cold?","qjp":"水はとても冷たかったですか？","purpose":"環境｜低体温の併発を評価します。","a":"Yes, freezing.","ajp":"はい、凍えるようでした。","end":{"impr":"Thank you. We'll keep you warm and watch your breathing.","imprJp":"ありがとうございます。体を温めて、呼吸を見ていきますね。"}}},"cat":"環境・中毒","lv":1},{"id":"hypothermia","icon":"🥶","title":"低体温","en":"Hypothermia","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How are you feeling?","qjp":"気分はどうですか？","purpose":"Signs｜意識と震えの状態を評価します。","a":"Very cold and sleepy.","ajp":"とても寒くて、眠いです。","next":"e1"},"e1":{"step":"E","q":"How long were you out in the cold?","qjp":"どのくらい寒い中にいましたか？","purpose":"Events｜曝露時間で重症度を判断します。","branch":{"question":"震えの有無で重症度が分かれます","options":[{"label":"I'm shivering hard.","jp":"激しく震えています。","route":"→ 軽〜中等症。加温へ","next":"shiver","setReply":{"a":"I can't stop shivering.","ajp":"震えが止まりません。"}},{"label":"I stopped shivering and feel numb.","jp":"震えは止まり、感覚がありません。","route":"→ 重症。慎重な加温へ","next":"noshiver","setReply":{"a":"I stopped shivering, I feel numb.","ajp":"震えは止まり、麻痺した感じです。"}}]}},"shiver":{"step":"S","q":"Can you move your hands and feet?","qjp":"手足は動かせますか？","purpose":"評価｜末梢の状態を確認します。","a":"Barely, they're stiff.","ajp":"かろうじて。こわばっています。","next":"l"},"noshiver":{"step":"S","q":"Stay still for me. Can you hear me clearly?","qjp":"動かないで。私の声ははっきり聞こえますか？","purpose":"重症｜意識レベルを確認します。","a":"Yes... but slowly.","ajp":"はい…ゆっくりですが。","next":"l"},"l":{"step":"L","q":"How did you get so cold?","qjp":"どうしてそんなに冷えたのですか？","purpose":"状況｜原因と再曝露の防止を確認します。","a":"I was stuck outside in the snow.","ajp":"雪の中で外に取り残されました。","end":{"impr":"Thank you. We'll warm you up slowly and gently.","imprJp":"ありがとうございます。ゆっくり、やさしく温めていきますね。"}}},"cat":"環境・中毒","lv":6},{"id":"comonoxide","icon":"☠️","title":"一酸化炭素中毒","en":"CO Poisoning","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms are you having?","qjp":"どんな症状がありますか？","purpose":"Signs｜CO中毒の非特異的症状を把握します。","a":"Headache, nausea and dizziness.","ajp":"頭痛、吐き気、めまいです。","next":"e1"},"e1":{"step":"E","q":"Where were you when this started?","qjp":"症状が出たときどこにいましたか？","purpose":"Events｜曝露源を特定します。","branch":{"question":"環境で曝露源が分かれます","options":[{"label":"In a room with a gas heater.","jp":"ガス暖房のある部屋です。","route":"→ 暖房器具。同室者を確認","next":"heater","setReply":{"a":"In a room with a gas heater on.","ajp":"ガス暖房をつけた部屋です。"}},{"label":"In a closed garage.","jp":"閉めた車庫の中です。","route":"→ 排気ガス。曝露時間を確認","next":"garage","setReply":{"a":"In a closed garage with the car on.","ajp":"車をかけたまま閉めた車庫です。"}}]}},"heater":{"step":"S","q":"Is anyone else there feeling sick too?","qjp":"同じ場所に具合の悪い人は？","purpose":"疫学｜同時多発はCO中毒を強く示唆します。","a":"Yes, my family feels sick too.","ajp":"はい、家族も具合が悪いです。","next":"after"},"garage":{"step":"E","q":"How long were you in there?","qjp":"どのくらいそこにいましたか？","purpose":"曝露｜時間で重症度を評価します。","a":"Maybe thirty minutes.","ajp":"30分くらいです。","next":"after"},"after":{"step":"S","q":"Do you feel confused or have chest pain?","qjp":"混乱や胸痛はありますか？","purpose":"重症度｜重症CO中毒の徴候を評価します。","a":"A little confused, yes.","ajp":"少し混乱しています。","end":{"impr":"Thank you. We're giving you oxygen and fresh air now.","imprJp":"ありがとうございます。今から酸素と新鮮な空気を送りますね。"}}},"cat":"環境・中毒","lv":3},{"id":"dka","icon":"🩸","title":"高血糖（DKA）","en":"Hyperglycemia / DKA","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms are you feeling?","qjp":"どんな症状がありますか？","purpose":"Signs｜高血糖の典型症状を把握します。","a":"Very thirsty and I keep urinating.","ajp":"のどが渇いて、頻繁に尿が出ます。","next":"p"},"p":{"step":"P","q":"Do you have diabetes?","qjp":"糖尿病はありますか？","purpose":"Past history｜1型か2型かで対応が変わります。","branch":{"question":"糖尿病のタイプで対応が分かれます","options":[{"label":"Yes, type 1, on insulin.","jp":"はい、1型でインスリンです。","route":"→ DKAを強く疑う","next":"type1","setReply":{"a":"Yes, type 1. I use insulin.","ajp":"はい、1型です。インスリンを使います。"}},{"label":"Yes, type 2, on tablets.","jp":"はい、2型で飲み薬です。","route":"→ 誘因の確認へ","next":"type2","setReply":{"a":"Yes, type 2, I take tablets.","ajp":"はい、2型で錠剤です。"}}]}},"type1":{"step":"M","q":"Have you missed any insulin doses?","qjp":"インスリンを打ち忘れていませんか？","purpose":"Medications｜DKAの主因を確認します。","a":"Yes, my pump stopped working.","ajp":"はい、ポンプが止まっていました。","next":"e"},"type2":{"step":"M","q":"Have you been sick or had an infection?","qjp":"体調を崩したり感染症は？","purpose":"誘因｜感染は高血糖の引き金です。","a":"I've had a bad cold.","ajp":"ひどい風邪をひいています。","next":"e"},"e":{"step":"E","q":"Does your breath smell fruity, or are you breathing fast?","qjp":"息が甘酸っぱい、または呼吸が速いですか？","purpose":"Events｜アセトン臭・速い呼吸はDKA徴候です。","a":"Yes, I'm breathing fast.","ajp":"はい、呼吸が速いです。","end":{"impr":"Thank you. We'll start fluids and check your blood sugar.","imprJp":"ありがとうございます。点滴を始めて血糖を確認しますね。"}}},"cat":"代謝","lv":6},{"id":"syncope_seizure","icon":"🔍","title":"失神/てんかん鑑別","en":"Syncope vs Seizure","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What do you remember before you collapsed?","qjp":"倒れる前のことを覚えていますか？","purpose":"Signs｜前駆症状の有無を確認します。","a":"I felt dizzy, then woke up on the floor.","ajp":"めまいがして、気づいたら床にいました。","next":"e1"},"e1":{"step":"E","q":"Did your body shake or stiffen?","qjp":"体が震えたり硬直しましたか？","purpose":"Events｜けいれんの有無で鑑別します。","branch":{"question":"けいれんの有無で疑いが分かれます","options":[{"label":"Yes, I shook all over.","jp":"はい、全身が震えました。","route":"→ てんかんを疑い事後を確認","next":"seiz","setReply":{"a":"Yes, my whole body shook.","ajp":"はい、全身が震えました。"}},{"label":"No, I just dropped.","jp":"いいえ、ただ倒れました。","route":"→ 失神を疑い前兆を確認","next":"synco","setReply":{"a":"No, I just dropped down.","ajp":"いいえ、ただ崩れ落ちました。"}}]}},"seiz":{"step":"S","q":"Were you confused for a while afterward?","qjp":"その後しばらく混乱していましたか？","purpose":"事後｜発作後もうろう状態を確認します。","a":"Yes, I was confused for minutes.","ajp":"はい、数分混乱していました。","next":"p"},"synco":{"step":"S","q":"Did you come round quickly?","qjp":"すぐに意識は戻りましたか？","purpose":"事後｜失神は回復が速いのが特徴です。","a":"Yes, almost right away.","ajp":"はい、ほぼすぐに戻りました。","next":"p"},"p":{"step":"P","q":"Have you had episodes like this before?","qjp":"以前にも同じことがありましたか？","purpose":"既往｜反復性を確認します。","a":"This is the first time.","ajp":"今回が初めてです。","end":{"impr":"Thank you. We'll monitor you and find out the cause.","imprJp":"ありがとうございます。経過を見て原因を調べますね。"}}},"cat":"神経","lv":2},{"id":"tia","icon":"⏱️","title":"一過性脳虚血発作","en":"TIA","framework":"CPSS","start":"t","nodes":{"t":{"step":"T","q":"When did the symptoms start and stop?","qjp":"症状はいつ始まって、いつ治まりましたか？","purpose":"Time｜TIAは一過性で消失するのが特徴です。","a":"Started an hour ago, gone in ten minutes.","ajp":"1時間前に始まり、10分で消えました。","next":"f"},"f":{"step":"F","q":"Did one side of your face droop?","qjp":"顔の片側が下がりましたか？","purpose":"Face｜顔面の左右差を確認します。","branch":{"question":"症状の種類で評価が分かれます","options":[{"label":"Yes, my face felt numb.","jp":"はい、顔がしびれました。","route":"→ 腕の評価へ","next":"a","setReply":{"a":"Yes, the right side went numb.","ajp":"はい、右側がしびれました。"}},{"label":"No, but my speech was slurred.","jp":"いいえ、でも話しにくかったです。","route":"→ 言語の評価へ","next":"a","setReply":{"a":"No, but my words came out wrong.","ajp":"いいえ、でも言葉がうまく出ませんでした。"}}]}},"a":{"step":"A","q":"Has your arm strength fully returned now?","qjp":"今は腕の力は完全に戻りましたか？","purpose":"Arms｜症状の完全消失を確認します。","a":"Yes, it feels normal again.","ajp":"はい、また普通に戻りました。","next":"s"},"s":{"step":"S","q":"Do you have high blood pressure or diabetes?","qjp":"高血圧や糖尿病はありますか？","purpose":"既往｜脳卒中の危険因子を確認します。","a":"Yes, I have high blood pressure.","ajp":"はい、高血圧があります。","end":{"impr":"Even though it passed, this is a warning. We'll take you in.","imprJp":"治まっても、これは警告サインです。病院へお連れします。"}}},"cat":"神経","lv":6},{"id":"weakness","icon":"💪","title":"片側の脱力","en":"One-sided Weakness","framework":"CPSS","start":"t","nodes":{"t":{"step":"T","q":"What time did the weakness start?","qjp":"脱力はいつ始まりましたか？","purpose":"Time｜発症時刻は治療方針に直結します。","a":"About thirty minutes ago.","ajp":"30分ほど前です。","next":"f"},"f":{"step":"F","q":"Is one side of your body affected?","qjp":"体の片側だけですか？","purpose":"局在｜片側性は脳卒中を示唆します。","branch":{"question":"範囲で評価の方向が変わります","options":[{"label":"Yes, my whole right side.","jp":"はい、右半身全部です。","route":"→ 握力の評価へ","next":"a","setReply":{"a":"Yes, my entire right side.","ajp":"はい、右半身すべてです。"}},{"label":"Just my right hand.","jp":"右手だけです。","route":"→ 末梢性も視野に評価","next":"a","setReply":{"a":"Just my right hand is weak.","ajp":"右手だけ力が入りません。"}}]}},"a":{"step":"A","q":"Can you grip my hands equally on both sides?","qjp":"両手で同じように私の手を握れますか？","purpose":"Arms｜左右の握力差を確認します。","a":"My right grip is much weaker.","ajp":"右の握力がかなり弱いです。","next":"s"},"s":{"step":"S","q":"Are you on any blood thinners?","qjp":"血液をサラサラにする薬は飲んでいますか？","purpose":"既往｜治療選択に影響します。","a":"No, I'm not.","ajp":"いいえ、飲んでいません。","end":{"impr":"This may be a stroke. We're taking you in immediately.","imprJp":"脳卒中の可能性があります。直ちにお連れします。"}}},"cat":"神経","lv":6},{"id":"slurred","icon":"🗨️","title":"ろれつが回らない","en":"Slurred Speech","framework":"CPSS","start":"t","nodes":{"t":{"step":"T","q":"When did your speech change?","qjp":"話しにくくなったのはいつからですか？","purpose":"Time｜発症時刻を確定します。","a":"It started twenty minutes ago.","ajp":"20分前に始まりました。","next":"s"},"s":{"step":"S","q":"Please repeat: The grass is green.","qjp":"続けて言ってください。「草は緑」","purpose":"Speech｜構音障害を直接評価します。","branch":{"question":"話し方で評価が分かれます","options":[{"label":"The grass is green... (unclear)","jp":"くさは…みどり（不明瞭）","route":"→ 構音障害あり。顔面へ","next":"f","setReply":{"a":"The grass is green... (slurred and unclear)","ajp":"草は緑…（不明瞭でろれつが回らない）。"}},{"label":"I know it, but the words won't come.","jp":"分かるのに、言葉が出ません。","route":"→ 失語を疑い顔面へ","next":"f","setReply":{"a":"I know the words but cannot say them.","ajp":"言葉は分かるのに口に出せません。"}}]}},"f":{"step":"F","q":"Does your face feel droopy anywhere?","qjp":"顔のどこかが下がる感じは？","purpose":"Face｜顔面麻痺を確認します。","a":"The left corner of my mouth.","ajp":"口の左の端です。","next":"a"},"a":{"step":"A","q":"Can you raise both arms evenly?","qjp":"両腕を均等に上げられますか？","purpose":"Arms｜上肢のドリフトを確認します。","a":"My left arm drifts down.","ajp":"左腕が下がってきます。","end":{"impr":"These are stroke signs. We're moving fast to the hospital.","imprJp":"脳卒中の徴候です。急いで病院へ向かいます。"}}},"cat":"神経","lv":1},{"id":"facialtrauma","icon":"😣","title":"顔面外傷","en":"Facial Trauma","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"How did you injure your face?","qjp":"どうやって顔を負傷しましたか？","purpose":"受傷機転｜損傷範囲を推定します。","a":"I was hit during a fight.","ajp":"けんかで殴られました。","next":"d"},"d":{"step":"D","q":"Are you having any trouble breathing?","qjp":"呼吸に問題はありますか？","purpose":"気道｜顔面外傷は気道閉塞の危険があります。","branch":{"question":"気道の状態で緊急度が分かれます","options":[{"label":"Yes, blood in my mouth.","jp":"はい、口の中に血が。","route":"→ 気道確保を優先","next":"airway","setReply":{"a":"Yes, there is blood in my mouth.","ajp":"はい、口の中に血があります。"}},{"label":"No, I can breathe okay.","jp":"いいえ、呼吸はできます。","route":"→ 損傷部位の評価へ","next":"intact","setReply":{"a":"No, my breathing is okay.","ajp":"いいえ、呼吸は大丈夫です。"}}]}},"airway":{"step":"T","q":"Can you lean forward and spit it out?","qjp":"前かがみで吐き出せますか？","purpose":"気道｜血液による気道閉塞を防ぎます。","a":"Yes, I can lean forward.","ajp":"はい、前かがみになれます。","next":"vision"},"intact":{"step":"T","q":"Can you move your jaw normally?","qjp":"あごは普通に動かせますか？","purpose":"観察｜骨折を評価します。","a":"My jaw hurts to move.","ajp":"あごを動かすと痛いです。","next":"vision"},"vision":{"step":"S","q":"Is your vision blurry or doubled?","qjp":"視界はぼやけたり二重に見えますか？","purpose":"重症度｜眼窩底骨折を評価します。","a":"A little blurry on one side.","ajp":"片側が少しぼやけます。","end":{"impr":"Thank you. Keep your head up and we will protect your airway.","imprJp":"ありがとうございます。頭を上げて。気道を守りますね。"}}},"cat":"外傷","lv":3},{"id":"gunshot","icon":"🚨","title":"銃創","en":"Gunshot Wound","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"Where were you shot?","qjp":"どこを撃たれましたか？","purpose":"受傷部位｜損傷経路を推定します。","a":"In my right thigh.","ajp":"右の太ももです。","next":"d"},"d":{"step":"D","q":"Is there bleeding I can see?","qjp":"見える出血はありますか？","purpose":"出血｜活動性出血を評価します。","branch":{"question":"出血の程度で対応が分かれます","options":[{"label":"Yes, it's bleeding heavily.","jp":"はい、大量に出血しています。","route":"→ 止血を最優先","next":"heavy","setReply":{"a":"Yes, it is bleeding a lot.","ajp":"はい、大量に出血しています。"}},{"label":"Some, but not too much.","jp":"少しですが、多くはないです。","route":"→ 出口創の確認へ","next":"exit","setReply":{"a":"Some, but not too much.","ajp":"少しですが、多くはありません。"}}]}},"heavy":{"step":"T","q":"I'm applying pressure. Do you feel faint?","qjp":"圧迫します。気が遠くなりますか？","purpose":"ショック｜出血性ショックを評価します。","a":"Yes, I feel dizzy.","ajp":"はい、めまいがします。","next":"breath"},"exit":{"step":"T","q":"Is there a wound on the other side too?","qjp":"反対側にも傷がありますか？","purpose":"出口創｜貫通か否かを確認します。","a":"Yes, there is a hole at the back.","ajp":"はい、裏側に穴があります。","next":"breath"},"breath":{"step":"L","q":"Are you having any trouble breathing?","qjp":"呼吸に問題はありますか？","purpose":"重症度｜致死的損傷を評価します。","a":"No, my breathing is okay.","ajp":"いいえ、呼吸は大丈夫です。","end":{"impr":"Stay with me. We are controlling the bleeding and moving now.","imprJp":"しっかりして。出血を抑えて、すぐ運びます。"}}},"cat":"外傷","lv":4},{"id":"chemburn","icon":"🧪","title":"化学熱傷","en":"Chemical Burn","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Where did the chemical touch you?","qjp":"薬品はどこに付きましたか？","purpose":"Signs｜曝露部位を確認します。","a":"On my face and left eye.","ajp":"顔と左目です。","next":"e1"},"e1":{"step":"E","q":"Did any get into your eye?","qjp":"目に入りましたか？","purpose":"Events｜眼への曝露は最優先で対応します。","branch":{"question":"曝露部位で対応の優先度が分かれます","options":[{"label":"Yes, it got in my eye.","jp":"はい、目に入りました。","route":"→ 眼の持続洗浄を最優先","next":"eye","setReply":{"a":"Yes, some got into my eye.","ajp":"はい、目に入ってしまいました。"}},{"label":"No, just on my skin.","jp":"いいえ、皮膚だけです。","route":"→ 皮膚の洗浄へ","next":"skin","setReply":{"a":"No, just on my skin.","ajp":"いいえ、皮膚だけです。"}}]}},"eye":{"step":"E","q":"We need to rinse your eye now. Can you open it?","qjp":"今すぐ目を洗います。開けられますか？","purpose":"処置｜眼の化学熱傷は即時持続洗浄が必要です。","a":"It stings, but I will try.","ajp":"しみますが、やってみます。","next":"p"},"skin":{"step":"E","q":"Have you rinsed it with lots of water?","qjp":"大量の水で洗い流しましたか？","purpose":"処置｜皮膚の希釈洗浄を確認します。","a":"Yes, for a few minutes.","ajp":"はい、数分間洗いました。","next":"p"},"p":{"step":"P","q":"Are you having any trouble breathing?","qjp":"呼吸に問題はありますか？","purpose":"気道｜気道刺激・吸入を評価します。","a":"No, breathing is fine.","ajp":"いいえ、呼吸は大丈夫です。","end":{"impr":"Keep rinsing. We will continue flushing on the way in.","imprJp":"洗い続けてください。搬送中も洗浄を続けます。"}}},"cat":"外傷","lv":8},{"id":"sportsinjury","icon":"⚽","title":"スポーツ外傷","en":"Sports Injury","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"How did you get hurt?","qjp":"どうやって怪我をしましたか？","purpose":"受傷機転｜損傷の様式を推定します。","a":"I twisted my knee while running.","ajp":"走っていて膝をひねりました。","next":"q"},"q":{"step":"Q","q":"Did you hear a pop or snap?","qjp":"ポキッという音はしましたか？","purpose":"Quality｜断裂音は靭帯損傷を示唆します。","branch":{"question":"音の有無で損傷が分かれます","options":[{"label":"Yes, I heard a loud pop.","jp":"はい、大きな音がしました。","route":"→ 靭帯損傷を疑う","next":"pop","setReply":{"a":"Yes, a loud pop.","ajp":"はい、大きな音が。"}},{"label":"No, it just hurt.","jp":"いいえ、痛んだだけです。","route":"→ 捻挫を評価","next":"nopop","setReply":{"a":"No, it just hurt right away.","ajp":"いいえ、すぐ痛んだだけです。"}}]}},"pop":{"step":"R","q":"Can the joint bear any weight?","qjp":"その関節に体重をかけられますか？","purpose":"重症度｜不安定性を評価します。","a":"No, it gives way.","ajp":"いいえ、崩れます。","next":"s"},"nopop":{"step":"R","q":"Is it swelling up?","qjp":"腫れてきていますか？","purpose":"観察｜腫脹の程度を確認します。","a":"Yes, quite quickly.","ajp":"はい、かなり早く腫れています。","next":"s"},"s":{"step":"S","q":"How bad is the pain, one to ten?","qjp":"痛みは10段階でどのくらいですか？","purpose":"Severity｜重症度を数値化します。","a":"About a six.","ajp":"6くらいです。","end":{"impr":"Thank you. We will rest, ice, and support the joint.","imprJp":"ありがとうございます。安静・冷却して関節を固定しますね。"}}},"cat":"外傷","lv":2},{"id":"smokeinhale","icon":"💨","title":"煙・ガス吸入","en":"Smoke Inhalation","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How is your breathing and throat?","qjp":"呼吸と喉の調子はどうですか？","purpose":"Signs｜気道熱傷・吸入損傷を評価します。","a":"My throat burns and I am coughing.","ajp":"喉が焼けるようで、咳が出ます。","next":"e1"},"e1":{"step":"E","q":"Were you in an enclosed smoky space?","qjp":"閉じた煙の中にいましたか？","purpose":"Events｜閉鎖空間は重症化の指標です。","branch":{"question":"曝露状況で重症度が分かれます","options":[{"label":"Yes, trapped in a room.","jp":"はい、部屋に閉じ込められました。","route":"→ 気道熱傷を強く疑う","next":"trapped","setReply":{"a":"Yes, I was trapped in a room.","ajp":"はい、部屋に閉じ込められました。"}},{"label":"No, I got out quickly.","jp":"いいえ、すぐ逃げました。","route":"→ 軽度。CO中毒を評価","next":"escaped","setReply":{"a":"No, I escaped quickly.","ajp":"いいえ、すぐ逃げました。"}}]}},"trapped":{"step":"S","q":"Is your voice hoarse or your spit sooty?","qjp":"声がかれたり、すすの混じった痰は？","purpose":"重症度｜嗄声・すす痰は気道熱傷の徴候です。","a":"My voice is hoarse.","ajp":"声がかれています。","next":"p"},"escaped":{"step":"S","q":"Do you have a headache or nausea?","qjp":"頭痛や吐き気はありますか？","purpose":"CO｜一酸化炭素中毒の併発を評価します。","a":"A slight headache.","ajp":"少し頭痛があります。","next":"p"},"p":{"step":"P","q":"Do you have any lung or heart conditions?","qjp":"肺や心臓の病気はありますか？","purpose":"既往｜基礎疾患を確認します。","a":"No, none.","ajp":"いいえ、ありません。","end":{"impr":"We are giving you high-flow oxygen right away. Stay calm.","imprJp":"今すぐ高濃度の酸素を投与します。落ち着いていてください。"}}},"cat":"環境・中毒","lv":6},{"id":"foodpoison","icon":"🍤","title":"食中毒","en":"Food Poisoning","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms do you have?","qjp":"どんな症状がありますか？","purpose":"Signs｜消化器症状を把握します。","a":"Vomiting, diarrhea and cramps.","ajp":"嘔吐、下痢、腹痛です。","next":"e1"},"e1":{"step":"E","q":"What and when did you last eat?","qjp":"最後に何をいつ食べましたか？","purpose":"Events｜原因食材を特定します。","branch":{"question":"食事内容で原因が分かれます","options":[{"label":"Reheated rice a few hours ago.","jp":"数時間前に温め直したご飯です。","route":"→ 細菌性を疑い経過へ","next":"bacterial","setReply":{"a":"Reheated rice a few hours ago.","ajp":"数時間前に温め直したご飯です。"}},{"label":"Undercooked chicken last night.","jp":"昨夜の生っぽい鶏肉です。","route":"→ 潜伏期の長い菌を疑う","next":"poultry","setReply":{"a":"Undercooked chicken last night.","ajp":"昨夜の火の通りが甘い鶏肉です。"}}]}},"bacterial":{"step":"S","q":"Did the symptoms start quite suddenly?","qjp":"症状は急に始まりましたか？","purpose":"経過｜発症の速さで原因菌を推定します。","a":"Yes, within a couple of hours.","ajp":"はい、数時間以内にです。","next":"l"},"poultry":{"step":"S","q":"Do you have a fever?","qjp":"発熱はありますか？","purpose":"随伴症状｜侵襲性感染を評価します。","a":"Yes, I feel hot.","ajp":"はい、熱っぽいです。","next":"l"},"l":{"step":"L","q":"Can you keep any fluids down?","qjp":"水分はとれていますか？","purpose":"脱水｜補液の必要性を評価します。","a":"Not really, I keep vomiting.","ajp":"あまり。吐いてしまいます。","end":{"impr":"Thank you. We will give you fluids and ease your symptoms.","imprJp":"ありがとうございます。点滴で水分を補い、症状を和らげますね。"}}},"cat":"消化器","lv":1},{"id":"dehydration","icon":"💧","title":"脱水","en":"Dehydration","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How are you feeling?","qjp":"気分はどうですか？","purpose":"Signs｜脱水の症状を把握します。","a":"Weak, dizzy and very thirsty.","ajp":"だるく、めまいがして、とても喉が渇きます。","next":"e1"},"e1":{"step":"E","q":"Why do you think you are dehydrated?","qjp":"なぜ脱水したと思いますか？","purpose":"Events｜水分喪失の原因を特定します。","branch":{"question":"原因で対応の方向が変わります","options":[{"label":"I've had diarrhea for days.","jp":"何日も下痢が続いています。","route":"→ 消化器性。尿量を確認","next":"gi","setReply":{"a":"I have had diarrhea for days.","ajp":"何日も下痢が続いています。"}},{"label":"I was out in the heat.","jp":"暑い中にいました。","route":"→ 熱性。意識を確認","next":"heat","setReply":{"a":"I was out in the heat all day.","ajp":"一日中暑い中にいました。"}}]}},"gi":{"step":"L","q":"When did you last pass urine?","qjp":"最後に排尿したのはいつですか？","purpose":"重症度｜尿量減少は脱水の指標です。","a":"Not since this morning.","ajp":"今朝から出ていません。","next":"p"},"heat":{"step":"S","q":"Do you feel confused at all?","qjp":"少しでも混乱した感じは？","purpose":"重症度｜意識障害は重症脱水の徴候です。","a":"A little foggy.","ajp":"少しぼんやりします。","next":"p"},"p":{"step":"P","q":"Do you have diabetes or kidney problems?","qjp":"糖尿病や腎臓の病気はありますか？","purpose":"既往｜基礎疾患を確認します。","a":"No, I don't.","ajp":"いいえ、ありません。","end":{"impr":"Thank you. We will start fluids to rehydrate you.","imprJp":"ありがとうございます。点滴で水分を補いますね。"}}},"cat":"代謝","lv":1},{"id":"thyroid","icon":"🦋","title":"甲状腺クリーゼ様","en":"Thyroid Storm-like","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What are you experiencing?","qjp":"どんな症状がありますか？","purpose":"Signs｜頻脈・発熱・興奮を把握します。","a":"Racing heart, sweating and shaking.","ajp":"動悸、発汗、震えです。","next":"p"},"p":{"step":"P","q":"Do you have a thyroid condition?","qjp":"甲状腺の病気はありますか？","purpose":"Past history｜甲状腺機能亢進症を確認します。","branch":{"question":"既往と誘因で評価が分かれます","options":[{"label":"Yes, an overactive thyroid.","jp":"はい、甲状腺の機能が高いです。","route":"→ クリーゼを疑い服薬へ","next":"known","setReply":{"a":"Yes, I have an overactive thyroid.","ajp":"はい、甲状腺機能亢進症です。"}},{"label":"I'm not sure.","jp":"よく分かりません。","route":"→ 鑑別のため随伴症状へ","next":"unknown","setReply":{"a":"I am not really sure.","ajp":"よく分かりません。"}}]}},"known":{"step":"M","q":"Have you been taking your thyroid medicine?","qjp":"甲状腺の薬は飲めていますか？","purpose":"Medications｜服薬中断はクリーゼの誘因です。","a":"I stopped a week ago.","ajp":"1週間前にやめました。","next":"e"},"unknown":{"step":"S","q":"Do you have a fever or feel very agitated?","qjp":"発熱や強い焦燥感は？","purpose":"随伴症状｜クリーゼの徴候を評価します。","a":"Yes, I feel hot and restless.","ajp":"はい、熱くて落ち着きません。","next":"e"},"e":{"step":"E","q":"Have you been ill or stressed recently?","qjp":"最近、体調不良やストレスは？","purpose":"Events｜誘因を確認します。","a":"I had an infection last week.","ajp":"先週、感染症にかかりました。","end":{"impr":"Thank you. We will cool you down and monitor your heart.","imprJp":"ありがとうございます。体を冷やし、心臓を見守りますね。"}}},"cat":"代謝","lv":5},{"id":"pregbleed","icon":"🤰","title":"妊娠中の出血","en":"Bleeding in Pregnancy","framework":"GTPAL","start":"g","nodes":{"g":{"step":"G","q":"How many weeks pregnant are you?","qjp":"妊娠何週ですか？","purpose":"妊娠週数｜出血の原因と緊急度を左右します。","a":"About twenty-eight weeks.","ajp":"28週くらいです。","next":"t"},"t":{"step":"T","q":"How much bleeding is there?","qjp":"出血量はどのくらいですか？","purpose":"出血量｜重症度を評価します。","branch":{"question":"出血量と痛みで原因が分かれます","options":[{"label":"Heavy, with sharp pain.","jp":"多量で、鋭い痛みがあります。","route":"→ 胎盤早期剥離を疑う","next":"painful","setReply":{"a":"Heavy bleeding with sharp pain.","ajp":"多量の出血と鋭い痛みです。"}},{"label":"Bright red, but no pain.","jp":"鮮血ですが痛みはないです。","route":"→ 前置胎盤を疑う","next":"painless","setReply":{"a":"Bright red, but no pain.","ajp":"鮮やかな赤ですが痛みはありません。"}}]}},"painful":{"step":"P","q":"Is the baby still moving?","qjp":"赤ちゃんはまだ動いていますか？","purpose":"胎児｜胎動は胎児の状態を反映します。","a":"Less than usual.","ajp":"いつもより少ないです。","next":"a"},"painless":{"step":"P","q":"Did anything trigger the bleeding?","qjp":"出血のきっかけはありましたか？","purpose":"誘因｜前置胎盤では誘因なく出血します。","a":"No, it just started.","ajp":"いいえ、突然始まりました。","next":"a"},"a":{"step":"A","q":"Have you had bleeding in this pregnancy before?","qjp":"今回の妊娠で前にも出血は？","purpose":"既往｜経過のリスクを確認します。","a":"No, this is the first time.","ajp":"いいえ、今回が初めてです。","end":{"impr":"Thank you. Please lie on your left side. We are moving quickly.","imprJp":"ありがとうございます。左を下に横になってください。急ぎます。"}}},"cat":"産科","lv":2},{"id":"delivery","icon":"👶","title":"院外分娩","en":"Newborn Delivery","framework":"GTPAL","start":"g","nodes":{"g":{"step":"G","q":"The baby is here. Is the baby crying?","qjp":"赤ちゃんが出ました。泣いていますか？","purpose":"評価｜啼泣は新生児の状態の最重要指標です。","branch":{"question":"赤ちゃんの様子で対応が分かれます","options":[{"label":"Yes, crying loudly.","jp":"はい、大きく泣いています。","route":"→ 良好。保温へ","next":"crying","setReply":{"a":"Yes, the baby is crying loudly.","ajp":"はい、赤ちゃんは大きく泣いています。"}},{"label":"No, the baby is limp.","jp":"いいえ、ぐったりしています。","route":"→ 蘇生を準備","next":"limp","setReply":{"a":"No, the baby is limp and quiet.","ajp":"いいえ、ぐったりして静かです。"}}]}},"crying":{"step":"P","q":"Is the baby's skin turning pink?","qjp":"赤ちゃんの肌はピンク色になってきましたか？","purpose":"評価｜皮膚色は酸素化の指標です。","a":"Yes, getting pinker.","ajp":"はい、ピンクになってきました。","next":"a"},"limp":{"step":"P","q":"We need to stimulate and warm the baby now. Ready?","qjp":"今すぐ刺激して温めます。いいですか？","purpose":"蘇生｜刺激と保温で呼吸を促します。","a":"Yes, please help!","ajp":"はい、助けてください！","next":"a"},"a":{"step":"A","q":"How is the mother doing?","qjp":"お母さんの様子はどうですか？","purpose":"母体｜分娩後の状態を評価します。","a":"She is tired but okay.","ajp":"疲れていますが大丈夫です。","next":"l"},"l":{"step":"L","q":"Is there heavy bleeding from the mother?","qjp":"お母さんに多量の出血は？","purpose":"母体｜弛緩出血を確認します。","a":"No, not too much.","ajp":"いいえ、多くはありません。","end":{"impr":"Well done. We will keep the baby warm and care for you both.","imprJp":"よく頑張りました。赤ちゃんを温め、お二人を看ますね。"}}},"cat":"産科","lv":7},{"id":"hyperemesis","icon":"🤢","title":"妊娠悪阻","en":"Severe Morning Sickness","framework":"GTPAL","start":"g","nodes":{"g":{"step":"G","q":"How many weeks pregnant are you?","qjp":"妊娠何週ですか？","purpose":"妊娠週数｜悪阻の時期を確認します。","a":"About ten weeks.","ajp":"10週くらいです。","next":"t"},"t":{"step":"T","q":"How often are you vomiting?","qjp":"どのくらいの頻度で吐いていますか？","purpose":"頻度｜脱水の程度を評価します。","branch":{"question":"水分保持の可否で重症度が分かれます","options":[{"label":"I can't keep anything down.","jp":"何も受けつけません。","route":"→ 重症悪阻。脱水評価へ","next":"severe","setReply":{"a":"I cannot keep anything down.","ajp":"何も受けつけません。"}},{"label":"A few times a day.","jp":"1日に数回です。","route":"→ 中等度。経過確認へ","next":"moderate","setReply":{"a":"A few times a day.","ajp":"1日に数回です。"}}]}},"severe":{"step":"P","q":"Do you feel dizzy when you stand?","qjp":"立つとめまいがしますか？","purpose":"脱水｜起立性の症状で脱水を評価します。","a":"Yes, very dizzy.","ajp":"はい、ひどくめまいがします。","next":"l"},"moderate":{"step":"P","q":"Can you sip water and keep it down?","qjp":"水を少しずつ飲んで保てますか？","purpose":"水分｜経口摂取の可否を確認します。","a":"A little, yes.","ajp":"少しなら、はい。","next":"l"},"l":{"step":"L","q":"When did you last keep food or drink down?","qjp":"最後に飲食を保てたのはいつですか？","purpose":"摂取｜栄養・脱水状態を評価します。","a":"Yesterday morning.","ajp":"昨日の朝です。","end":{"impr":"Thank you. We will give you fluids to settle your stomach.","imprJp":"ありがとうございます。点滴で水分を補い、胃を落ち着かせますね。"}}},"cat":"産科","lv":6},{"id":"ectopic","icon":"⚠️","title":"異所性妊娠疑い","en":"Suspected Ectopic","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the lower belly pain start?","qjp":"下腹部の痛みはいつ始まりましたか？","purpose":"Onset｜発症の経過を確認します。","a":"It came on suddenly this morning.","ajp":"今朝、急に始まりました。","next":"r"},"r":{"step":"R","q":"Is the pain on one side?","qjp":"痛みは片側ですか？","purpose":"Region｜片側性は異所性妊娠を示唆します。","branch":{"question":"痛みの場所と随伴症状で評価が分かれます","options":[{"label":"Sharp on the right, with bleeding.","jp":"右が鋭く、出血もあります。","route":"→ 破裂を疑い緊急対応","next":"bleed","setReply":{"a":"Sharp on the right, and I am bleeding.","ajp":"右が鋭く痛み、出血もあります。"}},{"label":"It's more in the center.","jp":"真ん中あたりです。","route":"→ 他の原因も含め評価","next":"central","setReply":{"a":"It is more in the middle.","ajp":"真ん中あたりです。"}}]}},"bleed":{"step":"S","q":"Do you feel faint or have shoulder pain?","qjp":"気が遠くなる感じや肩の痛みは？","purpose":"重症度｜肩への放散痛は腹腔内出血の徴候です。","a":"Yes, my shoulder aches and I feel weak.","ajp":"はい、肩が痛くて、力が抜けます。","next":"hist"},"central":{"step":"S","q":"Do you have nausea or fever?","qjp":"吐き気や発熱はありますか？","purpose":"鑑別｜他の急性腹症を評価します。","a":"Some nausea, no fever.","ajp":"少し吐き気が。熱はありません。","next":"hist"},"hist":{"step":"T","q":"Is there a chance you are pregnant?","qjp":"妊娠の可能性はありますか？","purpose":"前提｜妊娠の可能性を確認します。","a":"Yes, my period is late.","ajp":"はい、生理が遅れています。","end":{"impr":"Thank you. This could be serious, so we are moving quickly.","imprJp":"ありがとうございます。重い可能性があるので、急ぎます。"}}},"cat":"産科","lv":4},{"id":"panic","icon":"😨","title":"パニック発作","en":"Panic Attack","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"I'm here with you. What are you feeling?","qjp":"そばにいます。今どんな感じですか？","purpose":"Signs｜症状を把握し安心を与えます。","a":"My heart is racing and I cannot breathe.","ajp":"心臓がバクバクして、息ができません。","next":"e1"},"e1":{"step":"E","q":"Have you felt exactly like this before?","qjp":"前にも全く同じ感じになったことは？","purpose":"Events｜過去のパニック発作と照合します。","branch":{"question":"既往の有無で対応が分かれます","options":[{"label":"Yes, it's a panic attack.","jp":"はい、パニック発作です。","route":"→ 既知。呼吸の誘導へ","next":"known","setReply":{"a":"Yes, I get panic attacks.","ajp":"はい、パニック発作が出ます。"}},{"label":"No, this is new and scary.","jp":"いいえ、初めてで怖いです。","route":"→ 心疾患の除外へ","next":"newep","setReply":{"a":"No, this has never happened.","ajp":"いいえ、初めてです。"}}]}},"known":{"step":"S","q":"Let's breathe slowly together. Can you try?","qjp":"一緒にゆっくり呼吸しましょう。できますか？","purpose":"対応｜呼吸誘導で症状を和らげます。","a":"Okay, I will try with you.","ajp":"はい、一緒にやってみます。","next":"p"},"newep":{"step":"S","q":"Do you have any chest pain or heart problems?","qjp":"胸の痛みや心臓の病気は？","purpose":"除外｜心疾患を見落とさないため確認します。","a":"No chest pain, just panic.","ajp":"胸の痛みはなく、ただパニックです。","next":"p"},"p":{"step":"P","q":"Is there something that triggered this?","qjp":"きっかけになったことは？","purpose":"誘因｜引き金を確認します。","a":"I am under a lot of stress.","ajp":"とてもストレスがあります。","end":{"impr":"You are safe. This will pass. Keep breathing slowly with me.","imprJp":"大丈夫です。必ず治まります。一緒にゆっくり呼吸しましょう。"}}},"cat":"精神","lv":7},{"id":"agitated","icon":"😤","title":"興奮した患者","en":"Agitated Patient","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"I'm here to help you. Can you tell me your name?","qjp":"力になりに来ました。お名前を教えてもらえますか？","purpose":"信頼関係｜まず落ち着いた声で接触します。","a":"Why are you here?","ajp":"なぜここに？","next":"e1"},"e1":{"step":"E","q":"Are you in any pain or danger right now?","qjp":"今、痛みや危険はありますか？","purpose":"安全｜興奮の背景を探ります。","branch":{"question":"興奮の背景で対応が分かれます","options":[{"label":"I'm confused, what's happening?","jp":"混乱しています、何が？","route":"→ 器質的原因を疑い評価","next":"medical","setReply":{"a":"I am confused. What is happening?","ajp":"混乱しています。何が起きているのですか？"}},{"label":"Leave me alone!","jp":"放っておいて！","route":"→ 距離を保ち安全確保","next":"deescalate","setReply":{"a":"Just leave me alone!","ajp":"放っておいてくれ！"}}]}},"medical":{"step":"S","q":"Do you have diabetes, or did you hit your head?","qjp":"糖尿病はありますか、頭を打ちましたか？","purpose":"器質的｜低血糖・頭部外傷を除外します。","a":"I am diabetic, I think.","ajp":"たぶん、糖尿病です。","next":"p"},"deescalate":{"step":"S","q":"Okay, I'll keep my distance. Can we just talk?","qjp":"わかりました、離れます。話だけできますか？","purpose":"安全｜距離を保ち、刺激を避けます。","a":"Fine. Talk.","ajp":"いいよ。話せ。","next":"p"},"p":{"step":"P","q":"Have you had any alcohol or drugs today?","qjp":"今日、お酒や薬物をとりましたか？","purpose":"既往｜中毒・離脱を評価します。","a":"I had some drinks.","ajp":"少し飲みました。","end":{"impr":"Thank you for talking with me. We will keep you safe.","imprJp":"話してくれてありがとう。安全を守りますね。"}}},"cat":"精神","lv":9},{"id":"pacemaker","icon":"🔋","cat":"循環器","title":"ペースメーカー","en":"Pacemaker Issue","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What are you feeling with your pacemaker?","qjp":"ペースメーカーでどんな感じがしますか？","purpose":"Signs｜症状と作動感を確認します。","a":"My heart feels like it's skipping.","ajp":"心臓が飛ぶような感じです。","next":"p"},"p":{"step":"P","q":"Do you feel dizzy or short of breath?","qjp":"めまいや息切れはありますか？","purpose":"重症度｜機器不全の影響を評価します。","branch":{"question":"症状で緊急度が分かれます","options":[{"label":"Yes, very dizzy.","jp":"はい、ひどくめまいが。","route":"→ 機器不全を疑い緊急評価","next":"severe","setReply":{"a":"Yes, I feel very dizzy.","ajp":"はい、ひどくめまいがします。"}},{"label":"No, just the fluttering.","jp":"いいえ、ドキドキするだけです。","route":"→ 経過と既往の確認へ","next":"mild","setReply":{"a":"No, just the fluttering feeling.","ajp":"いいえ、ドキドキする感じだけです。"}}]}},"severe":{"step":"M","q":"When did you have the pacemaker fitted?","qjp":"ペースメーカーはいつ入れましたか？","purpose":"既往｜機器の情報を確認します。","a":"About five years ago.","ajp":"5年ほど前です。","next":"e"},"mild":{"step":"M","q":"Was your device checked recently?","qjp":"最近、機器の点検はしましたか？","purpose":"既往｜電池切れ等を評価します。","a":"Not for a long time.","ajp":"長いことしていません。","next":"e"},"e":{"step":"E","q":"Do you have a device card with you?","qjp":"機器のカードは持っていますか？","purpose":"情報｜機種特定に役立ちます。","a":"Yes, here it is.","ajp":"はい、これです。","end":{"impr":"Thank you. We'll check your heart rhythm right away.","imprJp":"ありがとうございます。すぐに心臓のリズムを確認しますね。"}}},"lv":5},{"id":"arrest_witness","icon":"🆘","cat":"循環器","title":"心停止の聴取","en":"Cardiac Arrest Info","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Did you see them collapse?","qjp":"倒れるのを見ましたか？","purpose":"Signs｜目撃の有無は蘇生の判断に重要です。","a":"Yes, he just fell down.","ajp":"はい、突然倒れました。","next":"e1"},"e1":{"step":"E","q":"Has anyone started chest compressions?","qjp":"誰か胸骨圧迫を始めましたか？","purpose":"Events｜CPRの実施状況を確認します。","branch":{"question":"CPRの有無で指示が変わります","options":[{"label":"Yes, a bystander is doing it.","jp":"はい、居合わせた人がやっています。","route":"→ 継続を支援","next":"ongoing","setReply":{"a":"Yes, someone is doing it now.","ajp":"はい、今やっています。"}},{"label":"No, no one is.","jp":"いいえ、誰もしていません。","route":"→ 直ちにCPRを指導","next":"none","setReply":{"a":"No, nobody has.","ajp":"いいえ、誰もしていません。"}}]}},"ongoing":{"step":"E","q":"Good. Is there an AED nearby?","qjp":"よかった。近くにAEDはありますか？","purpose":"処置｜除細動器の確保を確認します。","a":"There's one in the lobby.","ajp":"ロビーに1台あります。","next":"t"},"none":{"step":"E","q":"Push hard and fast in the center of the chest. Can you?","qjp":"胸の真ん中を強く速く押せますか？","purpose":"処置｜即時CPRを指導します。","a":"Okay, I'll start now.","ajp":"はい、今から始めます。","next":"t"},"t":{"step":"E","q":"How long ago did they collapse?","qjp":"倒れてからどのくらい経ちましたか？","purpose":"経過｜虚脱時間は予後を左右します。","a":"About two minutes ago.","ajp":"2分ほど前です。","end":{"impr":"Keep going. We're almost there to take over.","imprJp":"続けてください。もうすぐ着いて交代します。"}}},"lv":8},{"id":"orthostatic","icon":"🧍","cat":"循環器","title":"起立性めまい","en":"Orthostatic Dizziness","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When do you feel dizzy?","qjp":"どんなときにめまいがしますか？","purpose":"Onset｜誘発状況を確認します。","a":"When I stand up quickly.","ajp":"急に立ち上がるときです。","next":"p"},"p":{"step":"P","q":"Does it improve when you sit or lie down?","qjp":"座るか横になると治まりますか？","purpose":"Provocation｜起立性の特徴を確認します。","branch":{"question":"誘因で原因が分かれます","options":[{"label":"Yes, lying down helps.","jp":"はい、横になると楽です。","route":"→ 起立性。脱水を確認","next":"dehydr","setReply":{"a":"Yes, lying down helps a lot.","ajp":"はい、横になるととても楽です。"}},{"label":"No, it stays the same.","jp":"いいえ、変わりません。","route":"→ 他の原因を評価","next":"other","setReply":{"a":"No, it stays about the same.","ajp":"いいえ、あまり変わりません。"}}]}},"dehydr":{"step":"S","q":"Have you been drinking enough fluids?","qjp":"水分は十分とれていますか？","purpose":"脱水｜循環血液量を評価します。","a":"Not much today.","ajp":"今日はあまり飲んでいません。","next":"t"},"other":{"step":"S","q":"Do you have palpitations or chest pain?","qjp":"動悸や胸痛はありますか？","purpose":"鑑別｜心原性を除外します。","a":"No, none of those.","ajp":"いいえ、どちらもありません。","next":"t"},"t":{"step":"T","q":"Are you on blood pressure medicine?","qjp":"血圧の薬は飲んでいますか？","purpose":"薬剤｜降圧薬の影響を確認します。","a":"Yes, I started a new one.","ajp":"はい、新しい薬を始めました。","end":{"impr":"Thank you. Please stand up slowly from now on.","imprJp":"ありがとうございます。これからはゆっくり立ち上がってくださいね。"}}},"lv":5},{"id":"constipation","icon":"🌀","cat":"消化器","title":"便秘・腹部膨満","en":"Constipation / Bloating","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"How long has your belly felt bloated?","qjp":"お腹の張りはいつからですか？","purpose":"Onset｜経過を確認します。","a":"For about four days.","ajp":"4日ほどです。","next":"p"},"p":{"step":"P","q":"Have you been able to pass gas or stool?","qjp":"ガスや便は出ていますか？","purpose":"Provocation｜腸閉塞の徴候を評価します。","branch":{"question":"排ガス・排便の有無で危険度が分かれます","options":[{"label":"No gas or stool at all.","jp":"ガスも便も全く出ません。","route":"→ 腸閉塞を疑い随伴症状へ","next":"obstruct","setReply":{"a":"No gas or stool at all.","ajp":"ガスも便も全く出ません。"}},{"label":"A little gas, but no stool.","jp":"少しガスは。便は出ません。","route":"→ 便秘として評価","next":"simple","setReply":{"a":"A little gas, but no stool.","ajp":"少しガスは出ますが、便は出ません。"}}]}},"obstruct":{"step":"S","q":"Are you vomiting or in severe pain?","qjp":"嘔吐や激しい痛みはありますか？","purpose":"重症度｜閉塞の進行を評価します。","a":"Yes, I've started vomiting.","ajp":"はい、吐き始めました。","next":"t"},"simple":{"step":"S","q":"Do you have pain when you press your belly?","qjp":"お腹を押すと痛みますか？","purpose":"観察｜腹膜刺激を評価します。","a":"Some discomfort, not sharp.","ajp":"鈍い不快感です、鋭くはありません。","next":"t"},"t":{"step":"T","q":"Has this happened before?","qjp":"以前にもありましたか？","purpose":"既往｜反復性を確認します。","a":"Not this badly.","ajp":"ここまでひどいのは初めてです。","end":{"impr":"Thank you. We'll examine your belly and help relieve it.","imprJp":"ありがとうございます。お腹を診て、楽になるよう手助けします。"}}},"lv":7},{"id":"gallstone","icon":"🟡","cat":"消化器","title":"胆石・右上腹部痛","en":"Gallstone Pain","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the pain in your right side start?","qjp":"右側の痛みはいつ始まりましたか？","purpose":"Onset｜発症の経過を確認します。","a":"About an hour after dinner.","ajp":"夕食の1時間後くらいです。","next":"p"},"p":{"step":"P","q":"Did it start after a fatty meal?","qjp":"脂っこい食事の後に始まりましたか？","purpose":"Provocation｜胆石痛の典型的誘因です。","branch":{"question":"誘因と放散で評価が分かれます","options":[{"label":"Yes, after fried food.","jp":"はい、揚げ物の後です。","route":"→ 胆石を疑い放散を確認","next":"biliary","setReply":{"a":"Yes, after eating fried food.","ajp":"はい、揚げ物を食べた後です。"}},{"label":"No, it came on its own.","jp":"いいえ、自然にです。","route":"→ 他の原因も評価","next":"other","setReply":{"a":"No, it came on by itself.","ajp":"いいえ、ひとりでに始まりました。"}}]}},"biliary":{"step":"R","q":"Does the pain go to your back or shoulder?","qjp":"痛みは背中や肩に広がりますか？","purpose":"Radiation｜胆石痛は右肩へ放散します。","a":"Yes, to my right shoulder.","ajp":"はい、右肩へ広がります。","next":"s"},"other":{"step":"R","q":"Do you have a fever or yellow skin?","qjp":"発熱や皮膚の黄ばみは？","purpose":"随伴症状｜胆管炎・閉塞を評価します。","a":"I feel a bit feverish.","ajp":"少し熱っぽいです。","next":"s"},"s":{"step":"S","q":"How bad is the pain, one to ten?","qjp":"痛みは10段階でどのくらいですか？","purpose":"Severity｜重症度を数値化します。","a":"About a seven.","ajp":"7くらいです。","end":{"impr":"Thank you. Please avoid food and we'll ease the pain.","imprJp":"ありがとうございます。飲食を控えて。痛みを和らげますね。"}}},"lv":8},{"id":"jaundice","icon":"💛","cat":"消化器","title":"黄疸","en":"Jaundice","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"When did your skin start turning yellow?","qjp":"皮膚はいつから黄色くなりましたか？","purpose":"Signs｜発症の経過を確認します。","a":"Over the past week.","ajp":"この1週間ほどです。","next":"e1"},"e1":{"step":"E","q":"What color is your urine and stool?","qjp":"尿や便の色はどうですか？","purpose":"Events｜胆道閉塞の手がかりです。","branch":{"question":"尿便の色で原因が分かれます","options":[{"label":"Dark urine, pale stools.","jp":"濃い尿で、便は白っぽいです。","route":"→ 閉塞性を疑い痛みを確認","next":"obstr","setReply":{"a":"Dark urine and pale stools.","ajp":"濃い尿と、白っぽい便です。"}},{"label":"They look normal.","jp":"普通の色です。","route":"→ 肝細胞性も含め評価","next":"normal","setReply":{"a":"They look about normal.","ajp":"だいたい普通の色です。"}}]}},"obstr":{"step":"S","q":"Do you have belly pain or fever?","qjp":"腹痛や発熱はありますか？","purpose":"随伴症状｜胆管炎を評価します。","a":"Yes, pain on the right.","ajp":"はい、右側が痛みます。","next":"p"},"normal":{"step":"S","q":"Have you felt very tired or lost appetite?","qjp":"強い倦怠感や食欲低下は？","purpose":"随伴症状｜肝炎を評価します。","a":"Yes, very tired lately.","ajp":"はい、最近とても疲れます。","next":"p"},"p":{"step":"P","q":"Do you drink alcohol or have liver disease?","qjp":"飲酒や肝臓の病気はありますか？","purpose":"既往｜肝疾患の背景を確認します。","a":"I drink most days.","ajp":"ほぼ毎日飲みます。","end":{"impr":"Thank you. We'll take you in for blood tests and care.","imprJp":"ありがとうございます。血液検査と治療のためお連れします。"}}},"lv":7},{"id":"dysphagia","icon":"😮","cat":"消化器","title":"嚥下困難","en":"Difficulty Swallowing","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did swallowing become hard?","qjp":"飲み込みにくくなったのはいつからですか？","purpose":"Onset｜発症の経過を確認します。","a":"It's been getting worse for weeks.","ajp":"数週間かけて悪くなっています。","next":"q"},"q":{"step":"Q","q":"Is it hard with solids, liquids, or both?","qjp":"固形物、液体、両方のどれが難しいですか？","purpose":"Quality｜閉塞性か運動性かを区別します。","branch":{"question":"つかえ方で原因が分かれます","options":[{"label":"Solids stick, liquids are okay.","jp":"固形物がつかえ、液体は平気です。","route":"→ 機械的閉塞を疑う","next":"solid","setReply":{"a":"Solids stick, but liquids are fine.","ajp":"固形物はつかえますが、液体は平気です。"}},{"label":"Both are difficult.","jp":"両方とも難しいです。","route":"→ 運動障害を疑う","next":"both","setReply":{"a":"Both solids and liquids are hard.","ajp":"固形物も液体も難しいです。"}}]}},"solid":{"step":"S","q":"Have you lost weight recently?","qjp":"最近、体重は減りましたか？","purpose":"危険｜体重減少は腫瘍を示唆します。","a":"Yes, quite a bit.","ajp":"はい、かなり減りました。","next":"t"},"both":{"step":"S","q":"Do you ever choke or cough when eating?","qjp":"食事中にむせたり咳き込みますか？","purpose":"誤嚥｜誤嚥リスクを評価します。","a":"Yes, sometimes I cough.","ajp":"はい、時々むせます。","next":"t"},"t":{"step":"T","q":"Is it painful to swallow?","qjp":"飲み込むときに痛みますか？","purpose":"随伴症状｜炎症を評価します。","a":"A little, in my chest.","ajp":"少し、胸のあたりに。","end":{"impr":"Thank you. Please don't eat for now and we'll assess you.","imprJp":"ありがとうございます。今は食べずに。きちんと調べますね。"}}},"lv":3},{"id":"heartburn","icon":"🔥","cat":"消化器","title":"胃痛・胸やけ","en":"Heartburn","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the burning feeling start?","qjp":"焼けるような感じはいつからですか？","purpose":"Onset｜発症の経過を確認します。","a":"After I ate, about an hour ago.","ajp":"食後、1時間ほど前です。","next":"p"},"p":{"step":"P","q":"Is it worse lying down or after eating?","qjp":"横になったり食後に悪化しますか？","purpose":"Provocation｜逆流性の特徴を確認します。","branch":{"question":"症状で胃食道か心原性かを切り分けます","options":[{"label":"Worse lying down, tastes sour.","jp":"横になると悪化、酸っぱい味が。","route":"→ 逆流を疑う","next":"reflux","setReply":{"a":"Worse lying down, with a sour taste.","ajp":"横になると悪化し、酸っぱい味がします。"}},{"label":"It spreads to my arm, I sweat.","jp":"腕に広がり、汗が出ます。","route":"→ 心臓を疑い緊急評価","next":"cardiac","setReply":{"a":"It spreads to my arm and I'm sweating.","ajp":"腕に広がり、汗が出ます。"}}]}},"reflux":{"step":"R","q":"Does this happen often after meals?","qjp":"食後によく起こりますか？","purpose":"経過｜慢性逆流を評価します。","a":"Yes, most evenings.","ajp":"はい、たいてい夜に。","next":"s"},"cardiac":{"step":"R","q":"Do you have any heart conditions?","qjp":"心臓の病気はありますか？","purpose":"危険｜心疾患を見落とさないため確認します。","a":"I have high blood pressure.","ajp":"高血圧があります。","next":"s"},"s":{"step":"S","q":"How bad is the discomfort, one to ten?","qjp":"不快感は10段階でどのくらいですか？","purpose":"Severity｜程度を数値化します。","a":"About a five.","ajp":"5くらいです。","end":{"impr":"Thank you. To be safe, we'll check your heart too.","imprJp":"ありがとうございます。念のため心臓も確認しますね。"}}},"lv":5},{"id":"visionloss","icon":"👁️","cat":"神経","title":"視野異常・複視","en":"Vision Changes","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did your vision change?","qjp":"見え方が変わったのはいつからですか？","purpose":"Onset｜突発発症は緊急性が高い徴候です。","a":"Suddenly, twenty minutes ago.","ajp":"突然、20分前です。","next":"q"},"q":{"step":"Q","q":"Is it one eye or both eyes?","qjp":"片目ですか、両目ですか？","purpose":"Quality｜片眼か両眼かで原因が分かれます。","branch":{"question":"範囲で疑う原因が変わります","options":[{"label":"Just my left eye went dark.","jp":"左目だけ暗くなりました。","route":"→ 網膜/血管性を疑う","next":"oneeye","setReply":{"a":"Just my left eye went dark.","ajp":"左目だけ暗くなりました。"}},{"label":"I'm seeing double.","jp":"物が二重に見えます。","route":"→ 中枢性を疑い神経症状へ","next":"double","setReply":{"a":"I'm seeing everything double.","ajp":"すべてが二重に見えます。"}}]}},"oneeye":{"step":"R","q":"Was it like a curtain coming down?","qjp":"カーテンが下りるような見え方でしたか？","purpose":"特徴｜一過性黒内障の徴候です。","a":"Yes, exactly like that.","ajp":"はい、まさにそんな感じです。","next":"s"},"double":{"step":"R","q":"Do you have weakness or slurred speech?","qjp":"脱力やろれつの回りにくさは？","purpose":"中枢性｜脳卒中を評価します。","a":"My speech is a little slurred.","ajp":"少し話しにくいです。","next":"s"},"s":{"step":"S","q":"Do you have high blood pressure or diabetes?","qjp":"高血圧や糖尿病はありますか？","purpose":"既往｜血管リスクを確認します。","a":"Yes, both.","ajp":"はい、両方あります。","end":{"impr":"Thank you. This needs urgent checking. We'll take you in.","imprJp":"ありがとうございます。急いで調べる必要があります。お連れします。"}}},"lv":5},{"id":"numbness","icon":"🫳","cat":"神経","title":"手足のしびれ","en":"Numbness in Limbs","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the numbness start?","qjp":"しびれはいつ始まりましたか？","purpose":"Onset｜急性か慢性かを確認します。","a":"It started this morning.","ajp":"今朝からです。","next":"r"},"r":{"step":"R","q":"Where exactly do you feel numb?","qjp":"どこがしびれていますか？","purpose":"Region｜分布で末梢性か中枢性かを区別します。","branch":{"question":"しびれの分布で原因が分かれます","options":[{"label":"My whole left side.","jp":"左半身全体です。","route":"→ 中枢性を疑い緊急評価","next":"central","setReply":{"a":"My whole left side is numb.","ajp":"左半身全体がしびれます。"}},{"label":"Both hands and feet.","jp":"両方の手足です。","route":"→ 末梢性を疑い既往へ","next":"periph","setReply":{"a":"Both my hands and feet.","ajp":"両方の手足です。"}}]}},"central":{"step":"S","q":"Do you have weakness or face drooping?","qjp":"脱力や顔の下がりは？","purpose":"中枢性｜脳卒中を評価します。","a":"My left arm feels weak too.","ajp":"左腕にも力が入りません。","next":"t"},"periph":{"step":"P","q":"Do you have diabetes?","qjp":"糖尿病はありますか？","purpose":"既往｜末梢神経障害の原因を評価します。","a":"Yes, for many years.","ajp":"はい、長年あります。","next":"t"},"t":{"step":"T","q":"Is the numbness getting worse?","qjp":"しびれは悪化していますか？","purpose":"経過｜進行性を評価します。","a":"It's about the same.","ajp":"だいたい変わりません。","end":{"impr":"Thank you. We'll check you carefully on the way in.","imprJp":"ありがとうございます。搬送中、しっかり確認しますね。"}}},"lv":1},{"id":"laceration","icon":"🩹","cat":"外傷","title":"裂創","en":"Laceration","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Where is the cut?","qjp":"傷はどこですか？","purpose":"Signs｜創部の位置を確認します。","a":"On my forearm, it's deep.","ajp":"前腕です、深いです。","next":"e1"},"e1":{"step":"E","q":"How did it happen?","qjp":"どうやって切れましたか？","purpose":"Events｜受傷機転と汚染を評価します。","branch":{"question":"原因で感染・損傷リスクが分かれます","options":[{"label":"On a rusty metal edge.","jp":"錆びた金属の縁です。","route":"→ 破傷風リスクを確認","next":"dirty","setReply":{"a":"On a rusty metal edge.","ajp":"錆びた金属の縁です。"}},{"label":"With a clean kitchen knife.","jp":"清潔な包丁です。","route":"→ 出血と神経を確認","next":"clean","setReply":{"a":"With a clean kitchen knife.","ajp":"清潔な包丁です。"}}]}},"dirty":{"step":"A","q":"When was your last tetanus shot?","qjp":"最後の破傷風の予防接種はいつですか？","purpose":"既往｜破傷風予防の判断に必要です。","a":"I'm not sure.","ajp":"はっきりしません。","next":"s2"},"clean":{"step":"S","q":"Can you move your fingers normally?","qjp":"指は普通に動かせますか？","purpose":"神経腱｜深部損傷を評価します。","a":"Yes, but it hurts.","ajp":"はい、でも痛いです。","next":"s2"},"s2":{"step":"S","q":"Is it still bleeding?","qjp":"まだ出血していますか？","purpose":"出血｜止血の必要性を評価します。","a":"A little, I'm pressing it.","ajp":"少し。押さえています。","end":{"impr":"Thank you. Keep pressing and we'll clean and close it.","imprJp":"ありがとうございます。押さえ続けて。洗って閉じますね。"}}},"lv":1},{"id":"highfall","icon":"🪜","cat":"外傷","title":"高所からの墜落","en":"Fall from Height","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"How far did you fall?","qjp":"どのくらいの高さから落ちましたか？","purpose":"受傷機転｜墜落高は重症度を予測します。","a":"From a second-floor roof.","ajp":"2階の屋根からです。","next":"d"},"d":{"step":"D","q":"How did you land?","qjp":"どのように着地しましたか？","purpose":"機転｜着地様式で損傷部位を推定します。","branch":{"question":"着地の仕方で損傷が分かれます","options":[{"label":"On my feet, then my back.","jp":"足から、その後背中です。","route":"→ 脊椎・踵を疑い固定","next":"feet","setReply":{"a":"On my feet, then onto my back.","ajp":"足から落ち、その後背中を打ちました。"}},{"label":"On my side.","jp":"横向きです。","route":"→ 胸腹部を評価","next":"side","setReply":{"a":"I landed on my side.","ajp":"横向きに落ちました。"}}]}},"feet":{"step":"T","q":"Do you have back or heel pain?","qjp":"背中やかかとに痛みは？","purpose":"圧痛｜軸圧損傷を評価します。","a":"Yes, my lower back hurts.","ajp":"はい、腰が痛いです。","next":"l"},"side":{"step":"T","q":"Does it hurt to breathe?","qjp":"息をすると痛みますか？","purpose":"圧痛｜肋骨・胸部損傷を評価します。","a":"Yes, on my left ribs.","ajp":"はい、左の肋骨が。","next":"l"},"l":{"step":"L","q":"Can you feel and move your legs?","qjp":"脚の感覚と動きはありますか？","purpose":"神経｜脊髄損傷を評価します。","a":"Yes, but my back is very sore.","ajp":"はい、でも背中がとても痛いです。","end":{"impr":"Please stay still. We'll immobilize you and move you carefully.","imprJp":"動かないで。固定して、慎重にお運びします。"}}},"lv":1},{"id":"electrolyte","icon":"⚡","cat":"代謝","title":"電解質異常の疑い","en":"Electrolyte Imbalance","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms are you having?","qjp":"どんな症状がありますか？","purpose":"Signs｜筋症状・不整脈を把握します。","a":"Muscle cramps and weakness.","ajp":"筋肉のけいれんと脱力です。","next":"e1"},"e1":{"step":"E","q":"Have you had vomiting or diarrhea?","qjp":"嘔吐や下痢はありましたか？","purpose":"Events｜電解質喪失の原因を探ります。","branch":{"question":"原因で評価の方向が変わります","options":[{"label":"Yes, a lot of diarrhea.","jp":"はい、ひどい下痢です。","route":"→ 喪失性。心症状を確認","next":"loss","setReply":{"a":"Yes, a lot of diarrhea.","ajp":"はい、ひどい下痢です。"}},{"label":"No, but I take water pills.","jp":"いいえ、でも利尿薬を飲んでいます。","route":"→ 薬剤性を疑う","next":"meds","setReply":{"a":"No, but I take water pills.","ajp":"いいえ、でも利尿薬を飲んでいます。"}}]}},"loss":{"step":"S","q":"Do you feel your heart racing or skipping?","qjp":"動悸や脈の飛びは？","purpose":"危険｜不整脈を評価します。","a":"Yes, it feels irregular.","ajp":"はい、不規則な感じです。","next":"p"},"meds":{"step":"M","q":"What other medications do you take?","qjp":"他にどんな薬を飲んでいますか？","purpose":"薬剤｜相互作用を評価します。","a":"A heart pill and the water pill.","ajp":"心臓の薬と利尿薬です。","next":"p"},"p":{"step":"P","q":"Do you have kidney or heart problems?","qjp":"腎臓や心臓の病気は？","purpose":"既往｜基礎疾患を確認します。","a":"My kidneys are not great.","ajp":"腎臓があまりよくありません。","end":{"impr":"Thank you. We'll check your heart and run fluids.","imprJp":"ありがとうございます。心臓を確認し、点滴をしますね。"}}},"lv":3},{"id":"adrenal","icon":"💉","cat":"代謝","title":"副腎不全の既往者","en":"Adrenal Insufficiency","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How are you feeling right now?","qjp":"今、気分はどうですか？","purpose":"Signs｜副腎クリーゼの症状を把握します。","a":"Very weak, dizzy and nauseous.","ajp":"ひどくだるく、めまいと吐き気が。","next":"p"},"p":{"step":"P","q":"Do you take steroids for adrenal problems?","qjp":"副腎の病気でステロイドを使っていますか？","purpose":"Past history｜副腎不全の前提を確認します。","branch":{"question":"服薬状況で緊急度が分かれます","options":[{"label":"Yes, but I missed doses.","jp":"はい、でも飲み忘れました。","route":"→ クリーゼを強く疑う","next":"missed","setReply":{"a":"Yes, but I missed some doses.","ajp":"はい、でも何回か飲み忘れました。"}},{"label":"Yes, and I've been sick.","jp":"はい、それに体調を崩しています。","route":"→ ストレス下のクリーゼを疑う","next":"sick","setReply":{"a":"Yes, and I've been ill lately.","ajp":"はい、それに最近具合が悪いです。"}}]}},"missed":{"step":"M","q":"Do you have an emergency steroid injection?","qjp":"緊急用のステロイド注射はありますか？","purpose":"治療｜緊急投与の手段を確認します。","a":"Yes, in my bag.","ajp":"はい、かばんにあります。","next":"e"},"sick":{"step":"S","q":"Do you have a fever or vomiting?","qjp":"発熱や嘔吐は？","purpose":"誘因｜感染ストレスを評価します。","a":"Yes, both.","ajp":"はい、両方あります。","next":"e"},"e":{"step":"E","q":"Do you carry a medical alert card?","qjp":"医療情報カードは持っていますか？","purpose":"情報｜診断確定に役立ちます。","a":"Yes, here it is.","ajp":"はい、これです。","end":{"impr":"Thank you. This is an emergency. We're treating you now.","imprJp":"ありがとうございます。緊急事態です。すぐに処置します。"}}},"lv":4},{"id":"pedcroup","icon":"🫁","cat":"小児","title":"小児の呼吸困難","en":"Croup / Stridor","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What does your child's breathing sound like?","qjp":"お子さんの呼吸はどんな音ですか？","purpose":"Signs｜上気道狭窄の徴候を確認します。","a":"A harsh barking cough.","ajp":"ケンケンという咳です。","next":"e1"},"e1":{"step":"E","q":"Is there a high-pitched sound when breathing in?","qjp":"息を吸うとき高い音がしますか？","purpose":"Events｜吸気性喘鳴は気道狭窄の徴候です。","branch":{"question":"喘鳴と陥没で重症度が分かれます","options":[{"label":"Yes, even when resting.","jp":"はい、安静時でもします。","route":"→ 重症。陥没呼吸を確認","next":"severe","setReply":{"a":"Yes, even when she's resting.","ajp":"はい、休んでいてもします。"}},{"label":"Only when upset.","jp":"泣いたときだけです。","route":"→ 軽症。経過を確認","next":"mild","setReply":{"a":"Only when she gets upset.","ajp":"動揺したときだけです。"}}]}},"severe":{"step":"S","q":"Is the skin pulling in around the ribs?","qjp":"肋骨の周りがへこみますか？","purpose":"重症度｜陥没呼吸は努力呼吸の徴候です。","a":"Yes, I can see it.","ajp":"はい、見えます。","next":"p"},"mild":{"step":"S","q":"Is your child drinking and active?","qjp":"お子さんは水分をとり、元気ですか？","purpose":"評価｜全身状態を確認します。","a":"Yes, fairly active.","ajp":"はい、わりと元気です。","next":"p"},"p":{"step":"P","q":"Has your child had this before?","qjp":"以前にもこれがありましたか？","purpose":"既往｜反復性を確認します。","a":"Once last winter.","ajp":"去年の冬に1回。","end":{"impr":"Thank you. Keep your child calm and upright. We'll help.","imprJp":"ありがとうございます。お子さんを落ち着かせ、上体を起こして。手助けします。"}}},"lv":5},{"id":"pedinfant","icon":"👶","cat":"小児","title":"乳児の不機嫌・哺乳不良","en":"Irritable Infant","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How has your baby been acting?","qjp":"赤ちゃんの様子はどうですか？","purpose":"Signs｜全身状態を保護者に確認します。","a":"Crying a lot and won't feed.","ajp":"よく泣いて、飲んでくれません。","next":"e1"},"e1":{"step":"E","q":"Is your baby more sleepy than usual?","qjp":"いつもより眠そうですか？","purpose":"Events｜活気の低下は重症のサインです。","branch":{"question":"活気の様子で緊急度が分かれます","options":[{"label":"Yes, very hard to wake.","jp":"はい、とても起こしにくいです。","route":"→ 重症感あり。緊急評価","next":"lethargic","setReply":{"a":"Yes, very hard to wake.","ajp":"はい、とても起こしにくいです。"}},{"label":"No, just fussy.","jp":"いいえ、ぐずるだけです。","route":"→ 水分・おむつを確認","next":"fussy","setReply":{"a":"No, just very fussy.","ajp":"いいえ、とてもぐずるだけです。"}}]}},"lethargic":{"step":"S","q":"Does your baby have a fever or rash?","qjp":"赤ちゃんに熱や発疹は？","purpose":"重症感｜重症感染を評価します。","a":"He feels hot.","ajp":"熱いです。","next":"l"},"fussy":{"step":"L","q":"How many wet diapers today?","qjp":"今日、おむつは何回濡れましたか？","purpose":"脱水｜尿量で脱水を評価します。","a":"Fewer than usual.","ajp":"いつもより少ないです。","next":"l"},"l":{"step":"L","q":"When did your baby last feed well?","qjp":"最後にしっかり飲んだのはいつですか？","purpose":"摂取｜栄養・脱水を評価します。","a":"This morning.","ajp":"今朝です。","end":{"impr":"Thank you. We'll check your baby over carefully right away.","imprJp":"ありがとうございます。すぐに赤ちゃんをしっかり診ますね。"}}},"lv":4},{"id":"pedingestion","icon":"🧴","cat":"小児","title":"小児の誤飲・誤嚥","en":"Pediatric Ingestion","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What did your child swallow?","qjp":"お子さんは何を飲み込みましたか？","purpose":"Signs｜摂取物の特定が最優先です。","a":"Some of my pills.","ajp":"私の薬の一部です。","next":"e1"},"e1":{"step":"E","q":"Do you know how much and when?","qjp":"量とタイミングは分かりますか？","purpose":"Events｜量と経過時間は処置に不可欠です。","branch":{"question":"摂取物で対応が分かれます","options":[{"label":"Several heart pills, just now.","jp":"心臓の薬を数錠、たった今です。","route":"→ 薬剤。症状を確認","next":"pills","setReply":{"a":"Several heart pills, just now.","ajp":"心臓の薬を数錠、たった今です。"}},{"label":"A button battery.","jp":"ボタン電池です。","route":"→ 緊急。喉の症状を確認","next":"battery","setReply":{"a":"I think a button battery.","ajp":"ボタン電池だと思います。"}}]}},"pills":{"step":"S","q":"Is your child drowsy or acting strangely?","qjp":"お子さんはぼんやりしたり様子がおかしいですか？","purpose":"症状｜中毒症状を評価します。","a":"A bit sleepy.","ajp":"少し眠そうです。","next":"a"},"battery":{"step":"S","q":"Is your child drooling or refusing to eat?","qjp":"よだれが多い、食べたがらない様子は？","purpose":"危険｜食道損傷の徴候を評価します。","a":"Yes, drooling a lot.","ajp":"はい、よだれが多いです。","next":"a"},"a":{"step":"A","q":"Do you have the package or bottle?","qjp":"包装や容器はありますか？","purpose":"情報｜成分特定に役立ちます。","a":"Yes, I brought it.","ajp":"はい、持ってきました。","end":{"impr":"Thank you. Don't make your child vomit. We'll take you in now.","imprJp":"ありがとうございます。吐かせないで。すぐにお連れします。"}}},"lv":5},{"id":"peddehydr","icon":"🍼","cat":"小児","title":"小児の脱水","en":"Pediatric Dehydration","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How long has your child been sick?","qjp":"お子さんはいつから具合が悪いですか？","purpose":"Signs｜経過を確認します。","a":"Two days of vomiting.","ajp":"2日間、嘔吐しています。","next":"e1"},"e1":{"step":"E","q":"Is it vomiting, diarrhea, or both?","qjp":"嘔吐、下痢、両方のどれですか？","purpose":"Events｜水分喪失の経路を確認します。","branch":{"question":"症状の組み合わせで重症度が分かれます","options":[{"label":"Both, many times a day.","jp":"両方、1日に何度もです。","route":"→ 重症脱水を評価","next":"both","setReply":{"a":"Both, many times a day.","ajp":"両方、1日に何度もです。"}},{"label":"Just vomiting.","jp":"嘔吐だけです。","route":"→ 尿量を確認","next":"vomit","setReply":{"a":"Just vomiting, no diarrhea.","ajp":"嘔吐だけで、下痢はありません。"}}]}},"both":{"step":"S","q":"Are your child's eyes or mouth dry?","qjp":"お子さんの目や口は乾いていますか？","purpose":"重症度｜脱水の身体所見を確認します。","a":"Yes, lips look dry.","ajp":"はい、唇が乾いています。","next":"l"},"vomit":{"step":"L","q":"How many wet diapers today?","qjp":"今日、おむつは何回濡れましたか？","purpose":"尿量｜脱水の程度を評価します。","a":"Only one so far.","ajp":"今のところ1回だけです。","next":"l"},"l":{"step":"L","q":"Can your child keep any fluids down?","qjp":"お子さんは水分をとれていますか？","purpose":"摂取｜補液の必要性を評価します。","a":"No, brings it all up.","ajp":"いいえ、全部吐きます。","end":{"impr":"Thank you. We'll give fluids to help your child feel better.","imprJp":"ありがとうございます。点滴で水分を補い、楽にしますね。"}}},"lv":2},{"id":"pedhead","icon":"🧒","cat":"小児","title":"小児の頭部打撲","en":"Pediatric Head Injury","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How did your child hit their head?","qjp":"お子さんはどうやって頭を打ちましたか？","purpose":"Signs｜受傷機転を確認します。","a":"Fell off the sofa.","ajp":"ソファから落ちました。","next":"e1"},"e1":{"step":"E","q":"Did your child lose consciousness or vomit?","qjp":"意識を失ったり吐いたりしましたか？","purpose":"Events｜頭蓋内損傷の徴候を評価します。","branch":{"question":"症状の有無で評価が分かれます","options":[{"label":"Yes, vomited twice.","jp":"はい、2回吐きました。","route":"→ 緊急評価へ","next":"redflag","setReply":{"a":"Yes, she vomited twice.","ajp":"はい、2回吐きました。"}},{"label":"No, just cried.","jp":"いいえ、泣いただけです。","route":"→ 経過観察の評価へ","next":"mild","setReply":{"a":"No, she just cried.","ajp":"いいえ、泣いただけです。"}}]}},"redflag":{"step":"S","q":"Is your child very sleepy or hard to wake?","qjp":"お子さんはとても眠そう、起こしにくいですか？","purpose":"重症度｜意識レベルを評価します。","a":"Yes, more sleepy than usual.","ajp":"はい、いつもより眠そうです。","next":"a"},"mild":{"step":"S","q":"Is your child acting normally now?","qjp":"今、お子さんはいつも通りですか？","purpose":"評価｜活気を確認します。","a":"Yes, playing again.","ajp":"はい、また遊んでいます。","next":"a"},"a":{"step":"A","q":"Is there a swelling or cut on the head?","qjp":"頭にこぶや傷はありますか？","purpose":"観察｜外表所見を確認します。","a":"A small bump.","ajp":"小さなこぶがあります。","end":{"impr":"Thank you. We'll watch your child closely for any change.","imprJp":"ありがとうございます。変化がないか、しっかり見守りますね。"}}},"lv":7},{"id":"pedallergy","icon":"🥜","cat":"小児","title":"小児のアレルギー反応","en":"Pediatric Allergy","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What symptoms does your child have?","qjp":"お子さんにどんな症状がありますか？","purpose":"Signs｜反応の重症度を評価します。","a":"Hives and a swollen face.","ajp":"じんましんと、顔の腫れです。","next":"a"},"a":{"step":"A","q":"Is your child having trouble breathing?","qjp":"お子さんは呼吸がしづらそうですか？","purpose":"Allergies｜アナフィラキシーを評価します。","branch":{"question":"呼吸症状の有無で緊急度が分かれます","options":[{"label":"Yes, wheezing and coughing.","jp":"はい、ゼーゼーと咳が。","route":"→ アナフィラキシー。緊急対応","next":"severe","setReply":{"a":"Yes, she's wheezing and coughing.","ajp":"はい、ゼーゼーして咳をしています。"}},{"label":"No, just the rash.","jp":"いいえ、発疹だけです。","route":"→ 曝露源を確認","next":"mild","setReply":{"a":"No, just the rash so far.","ajp":"いいえ、今のところ発疹だけです。"}}]}},"severe":{"step":"M","q":"Does your child have an epinephrine pen?","qjp":"お子さん用のエピネフリン注射器はありますか？","purpose":"Medications｜エピペンは救命に直結します。","a":"Yes, the school nurse has it.","ajp":"はい、学校の看護師が持っています。","next":"e"},"mild":{"step":"A","q":"What do you think caused it?","qjp":"何が原因だと思いますか？","purpose":"曝露源｜アレルゲンを特定します。","a":"He ate a peanut snack.","ajp":"ピーナッツのお菓子を食べました。","next":"e"},"e":{"step":"E","q":"Has your child reacted like this before?","qjp":"以前にも同じ反応は？","purpose":"既往｜過去の反応歴を確認します。","a":"Never this bad.","ajp":"こんなにひどいのは初めてです。","end":{"impr":"Thank you. We're treating the reaction right now.","imprJp":"ありがとうございます。今すぐ反応に対処します。"}}},"lv":2},{"id":"dementia","icon":"🧓","cat":"高齢者","title":"認知症の方の急変","en":"Acute Dementia Change","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What has changed in them today?","qjp":"今日、どんな変化がありましたか？","purpose":"Signs｜普段との違いを家族に確認します。","a":"Suddenly very confused and agitated.","ajp":"急にひどく混乱して興奮しています。","next":"e1"},"e1":{"step":"E","q":"Is this different from their usual confusion?","qjp":"普段の物忘れとは違いますか？","purpose":"Events｜せん妄を鑑別します。","branch":{"question":"急性変化の有無で評価が分かれます","options":[{"label":"Yes, much worse than normal.","jp":"はい、普段よりずっとひどいです。","route":"→ せん妄を疑い原因へ","next":"delirium","setReply":{"a":"Yes, far worse than normal.","ajp":"はい、普段よりずっとひどいです。"}},{"label":"About the same as always.","jp":"いつもと同じくらいです。","route":"→ 身体症状を確認","next":"baseline","setReply":{"a":"About the same as always.","ajp":"いつもと同じくらいです。"}}]}},"delirium":{"step":"S","q":"Do they have a fever or pain anywhere?","qjp":"発熱やどこかの痛みは？","purpose":"原因｜感染・疼痛を評価します。","a":"He feels warm.","ajp":"熱っぽいです。","next":"m"},"baseline":{"step":"S","q":"Are they eating and drinking normally?","qjp":"食事や水分は普通にとれていますか？","purpose":"評価｜全身状態を確認します。","a":"Less than usual.","ajp":"いつもより少ないです。","next":"m"},"m":{"step":"M","q":"Did they start any new medications?","qjp":"新しい薬を始めましたか？","purpose":"薬剤｜薬剤性せん妄を評価します。","a":"Yes, last week.","ajp":"はい、先週から。","end":{"impr":"Thank you. We'll look for the cause and keep them calm.","imprJp":"ありがとうございます。原因を探し、落ち着いて過ごせるようにしますね。"}}},"lv":4},{"id":"acutestress","icon":"🌫️","cat":"精神","title":"急性ストレス・解離","en":"Acute Stress / Dissociation","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"You're safe now. Can you tell me what you feel?","qjp":"もう安全です。今、何を感じますか？","purpose":"信頼関係｜安心と接地を促します。","a":"Numb, like I'm not really here.","ajp":"麻痺したような、自分がここにいない感じです。","next":"e1"},"e1":{"step":"E","q":"Did something frightening just happen?","qjp":"直前に怖いことがありましたか？","purpose":"Events｜誘因となる出来事を確認します。","branch":{"question":"接地の状態で対応が分かれます","options":[{"label":"Yes, I saw an accident.","jp":"はい、事故を目撃しました。","route":"→ 接地を促す","next":"ground","setReply":{"a":"Yes, I just saw an accident.","ajp":"はい、事故を目撃しました。"}},{"label":"I can't remember clearly.","jp":"はっきり思い出せません。","route":"→ ゆっくり確認","next":"foggy","setReply":{"a":"I can't remember it clearly.","ajp":"はっきり思い出せません。"}}]}},"ground":{"step":"S","q":"Can you feel your feet on the ground for me?","qjp":"足が地面についているのを感じられますか？","purpose":"対応｜グラウンディングで現実感を戻します。","a":"Yes... a little.","ajp":"はい…少し。","next":"p"},"foggy":{"step":"S","q":"Can you tell me your name and today's date?","qjp":"お名前と今日の日付は言えますか？","purpose":"評価｜見当識を確認します。","a":"Yes, I can do that.","ajp":"はい、それはできます。","next":"p"},"p":{"step":"P","q":"Has this happened to you before?","qjp":"以前にもこうなったことは？","purpose":"既往｜過去のエピソードを確認します。","a":"Once, after a bad event.","ajp":"一度、つらい出来事の後に。","end":{"impr":"You're safe with us. Take your time. We'll stay with you.","imprJp":"私たちといれば安全です。ゆっくりで大丈夫。そばにいます。"}}},"lv":8},{"id":"recurfall","icon":"🧓","cat":"高齢者","title":"くり返す転倒","en":"Recurrent Falls","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How did you fall this time?","qjp":"今回はどのように転びましたか？","purpose":"Signs｜転倒状況を確認します。","a":"My legs just gave way.","ajp":"脚の力が抜けました。","next":"e1"},"e1":{"step":"E","q":"Did you feel dizzy or black out before falling?","qjp":"転ぶ前にめまいや気の遠くなる感じは？","purpose":"Events｜失神性転倒を鑑別します。","branch":{"question":"前駆症状の有無で原因が分かれます","options":[{"label":"Yes, I felt faint.","jp":"はい、気が遠くなりました。","route":"→ 失神性。心臓を確認","next":"syncopal","setReply":{"a":"Yes, I felt faint first.","ajp":"はい、先に気が遠くなりました。"}},{"label":"No, I just tripped.","jp":"いいえ、つまずいただけです。","route":"→ 機械的。怪我を確認","next":"mechanical","setReply":{"a":"No, I just tripped.","ajp":"いいえ、つまずいただけです。"}}]}},"syncopal":{"step":"S","q":"Do you have heart problems or take many medicines?","qjp":"心臓の病気や、多くの薬はありますか？","purpose":"原因｜心原性・薬剤性を評価します。","a":"I take several pills.","ajp":"何種類か飲んでいます。","next":"p"},"mechanical":{"step":"S","q":"Are you hurt anywhere from the fall?","qjp":"転倒でどこか怪我はありますか？","purpose":"外傷｜骨折等を評価します。","a":"My hip is sore.","ajp":"腰が痛いです。","next":"p"},"p":{"step":"P","q":"How many times have you fallen recently?","qjp":"最近、何回くらい転びましたか？","purpose":"既往｜転倒頻度を確認します。","a":"Three times this month.","ajp":"今月3回です。","end":{"impr":"Thank you. We'll check you over and look into why this keeps happening.","imprJp":"ありがとうございます。診察して、くり返す原因を調べますね。"}}},"lv":7},{"id":"fatigue","icon":"😮‍💨","cat":"全身","title":"原因不明の全身倦怠","en":"Unexplained Fatigue","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the tiredness begin?","qjp":"倦怠感はいつ始まりましたか？","purpose":"Onset｜経過を確認します。","a":"It's built up over weeks.","ajp":"数週間かけて強くなりました。","next":"q"},"q":{"step":"Q","q":"Do you have other symptoms with it?","qjp":"他に伴う症状はありますか？","purpose":"Quality｜随伴症状で原因を絞ります。","branch":{"question":"随伴症状で方向が分かれます","options":[{"label":"Yes, chest pain and breathlessness.","jp":"はい、胸痛と息切れです。","route":"→ 心肺系を評価","next":"cardiac","setReply":{"a":"Yes, chest pain and breathlessness.","ajp":"はい、胸痛と息切れです。"}},{"label":"Just feeling weak and pale.","jp":"だるくて、顔色が悪いだけです。","route":"→ 貧血等を評価","next":"anemic","setReply":{"a":"Just weak and pale.","ajp":"だるくて、顔色が悪いだけです。"}}]}},"cardiac":{"step":"R","q":"Does it get worse with activity?","qjp":"動くと悪化しますか？","purpose":"労作｜心肺機能を評価します。","a":"Yes, much worse.","ajp":"はい、ずっとひどくなります。","next":"s"},"anemic":{"step":"R","q":"Have you noticed any bleeding anywhere?","qjp":"どこかの出血に気づきましたか？","purpose":"貧血｜出血源を探ります。","a":"My stools have been dark.","ajp":"便が黒っぽいです。","next":"s"},"s":{"step":"S","q":"Have you had fevers or weight loss?","qjp":"発熱や体重減少はありましたか？","purpose":"危険｜重篤な背景を評価します。","a":"I've lost some weight.","ajp":"少し体重が減りました。","end":{"impr":"Thank you. We'll run tests to find what's behind this.","imprJp":"ありがとうございます。原因を調べる検査をしますね。"}}},"lv":2},{"id":"urinary","icon":"🚻","cat":"泌尿器","title":"排尿障害・尿閉","en":"Urinary Retention","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did you last pass urine?","qjp":"最後に排尿したのはいつですか？","purpose":"Onset｜尿閉の経過を確認します。","a":"Not since yesterday.","ajp":"昨日から出ていません。","next":"q"},"q":{"step":"Q","q":"Do you feel a strong urge but can't go?","qjp":"強い尿意があるのに出ませんか？","purpose":"Quality｜閉塞性か否かを区別します。","branch":{"question":"症状で原因が分かれます","options":[{"label":"Yes, and my belly is swollen.","jp":"はい、お腹が張っています。","route":"→ 尿閉。痛みを確認","next":"retention","setReply":{"a":"Yes, and my lower belly is swollen.","ajp":"はい、下腹が張っています。"}},{"label":"No urge, just no urine.","jp":"尿意もなく、出ません。","route":"→ 腎機能を評価","next":"anuria","setReply":{"a":"No urge, and no urine at all.","ajp":"尿意もなく、全く出ません。"}}]}},"retention":{"step":"S","q":"How bad is the lower belly pain?","qjp":"下腹の痛みはどのくらいですか？","purpose":"Severity｜膀胱の緊満を評価します。","a":"Very uncomfortable, about eight.","ajp":"とてもつらく、8くらいです。","next":"p"},"anuria":{"step":"S","q":"Have you been drinking much less?","qjp":"水分摂取はかなり減っていますか？","purpose":"鑑別｜脱水・腎不全を評価します。","a":"Yes, hardly at all.","ajp":"はい、ほとんど飲めていません。","next":"p"},"p":{"step":"P","q":"Do you have prostate or kidney problems?","qjp":"前立腺や腎臓の病気はありますか？","purpose":"既往｜閉塞の原因を確認します。","a":"I have a prostate problem.","ajp":"前立腺の病気があります。","end":{"impr":"Thank you. We can relieve this. We'll take you in now.","imprJp":"ありがとうございます。楽にできます。今すぐお連れします。"}}},"lv":6},{"id":"fullhistory","icon":"📋","cat":"基本","title":"既往の総合確認","en":"Full History Check","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"What is the main problem today?","qjp":"今日の一番の問題は何ですか？","purpose":"Signs｜主訴を把握します。","a":"I've been feeling unwell all over.","ajp":"全身の調子が悪いです。","next":"a"},"a":{"step":"A","q":"Do you have any allergies?","qjp":"アレルギーはありますか？","purpose":"Allergies｜投薬前に必ず確認します。","a":"Yes, to penicillin.","ajp":"はい、ペニシリンに。","next":"m"},"m":{"step":"M","q":"What medications do you take regularly?","qjp":"普段どんな薬を飲んでいますか？","purpose":"Medications｜常用薬を確認します。","branch":{"question":"服薬内容で確認の重点が変わります","options":[{"label":"Several, including a blood thinner.","jp":"数種類、血液をサラサラにする薬も。","route":"→ 出血リスクを重点確認","next":"thinner","setReply":{"a":"Several, including a blood thinner.","ajp":"数種類で、血液をサラサラにする薬も含みます。"}},{"label":"Just one for blood pressure.","jp":"血圧の薬1つだけです。","route":"→ 既往の確認へ","next":"simple","setReply":{"a":"Just one for blood pressure.","ajp":"血圧の薬を1つだけです。"}}]}},"thinner":{"step":"P","q":"Why do you take the blood thinner?","qjp":"なぜその薬を飲んでいますか？","purpose":"既往｜心房細動等の背景を確認します。","a":"For an irregular heartbeat.","ajp":"不整脈のためです。","next":"l"},"simple":{"step":"P","q":"Do you have any past illnesses or surgeries?","qjp":"過去の病気や手術はありますか？","purpose":"既往｜病歴を確認します。","a":"I had my appendix out.","ajp":"虫垂を取りました。","next":"l"},"l":{"step":"L","q":"When did you last eat or drink?","qjp":"最後に飲食したのはいつですか？","purpose":"Last meal｜処置に備え確認します。","a":"A couple of hours ago.","ajp":"2時間ほど前です。","end":{"impr":"Thank you. That gives us a clear picture to help you.","imprJp":"ありがとうございます。これで状況がよく分かりました。"}}},"lv":9},{"id":"arrhythmia","icon":"💗","cat":"循環器","title":"不整脈の自覚","en":"Irregular Heartbeat","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did you notice the irregular beat?","qjp":"脈の乱れに気づいたのはいつですか？","purpose":"Onset｜発症を確認します。","a":"A few hours ago.","ajp":"数時間前です。","next":"q"},"q":{"step":"Q","q":"Is it constant or does it come and go?","qjp":"ずっとですか、波がありますか？","purpose":"Quality｜発作性か持続性かを区別します。","branch":{"question":"持続パターンで評価が分かれます","options":[{"label":"It comes and goes.","jp":"出たり治まったりします。","route":"→ 発作性。誘因を確認","next":"parox","setReply":{"a":"It comes and goes.","ajp":"出たり治まったりします。"}},{"label":"It's been constant.","jp":"ずっと続いています。","route":"→ 持続性。既往を確認","next":"persist","setReply":{"a":"It's been constant.","ajp":"ずっと続いています。"}}]}},"parox":{"step":"P","q":"Did caffeine or stress trigger it?","qjp":"カフェインやストレスがきっかけでしたか？","purpose":"誘因｜発作の引き金を探ります。","a":"I had a lot of coffee.","ajp":"コーヒーをたくさん飲みました。","next":"s"},"persist":{"step":"P","q":"Have you been told you have an arrhythmia?","qjp":"不整脈と言われたことはありますか？","purpose":"既往｜既知の不整脈を確認します。","a":"Yes, atrial fibrillation.","ajp":"はい、心房細動です。","next":"s"},"s":{"step":"S","q":"Do you feel chest pain or faint?","qjp":"胸痛や気の遠くなる感じは？","purpose":"重症度｜循環不全を評価します。","a":"No, just the fluttering.","ajp":"いいえ、ドキドキするだけです。","end":{"impr":"Thank you. We'll record your heart rhythm now.","imprJp":"ありがとうございます。今、心臓のリズムを記録しますね。"}}},"lv":7},{"id":"postsyncope","icon":"😌","cat":"循環器","title":"失神からの回復後","en":"Post-Syncope","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"How do you feel now that you're awake?","qjp":"目が覚めた今、気分はどうですか？","purpose":"Signs｜回復後の状態を確認します。","a":"A bit shaky, but okay.","ajp":"少しふらつきますが、大丈夫です。","next":"e1"},"e1":{"step":"E","q":"How long were you unconscious?","qjp":"どのくらい意識を失っていましたか？","purpose":"Events｜意識消失時間を確認します。","branch":{"question":"消失時間で評価が分かれます","options":[{"label":"Just a few seconds.","jp":"数秒だけです。","route":"→ 単純失神を評価","next":"brief","setReply":{"a":"Just a few seconds.","ajp":"数秒だけです。"}},{"label":"Maybe a minute.","jp":"1分くらいかもしれません。","route":"→ 慎重に評価","next":"longer","setReply":{"a":"Maybe about a minute.","ajp":"1分くらいかもしれません。"}}]}},"brief":{"step":"S","q":"Did you injure yourself when you fell?","qjp":"倒れたとき怪我はしましたか？","purpose":"外傷｜転倒による損傷を確認します。","a":"I bumped my head a little.","ajp":"少し頭を打ちました。","next":"p"},"longer":{"step":"S","q":"Do you feel any chest pain or palpitations?","qjp":"胸痛や動悸はありますか？","purpose":"原因｜心原性を評価します。","a":"My heart felt fast before.","ajp":"前に心臓が速く感じました。","next":"p"},"p":{"step":"P","q":"Has this happened to you before?","qjp":"以前にもありましたか？","purpose":"既往｜反復性を確認します。","a":"Once last year.","ajp":"去年1回。","end":{"impr":"Thank you. Please rest lying down while we check you.","imprJp":"ありがとうございます。検査の間、横になって休んでください。"}}},"lv":5},{"id":"tooth","icon":"🦷","cat":"外傷","title":"歯の外傷","en":"Dental Trauma","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"How did you injure your mouth?","qjp":"どうやって口を負傷しましたか？","purpose":"受傷機転｜損傷範囲を推定します。","a":"I got elbowed playing sport.","ajp":"スポーツで肘が当たりました。","next":"d"},"d":{"step":"D","q":"Did a tooth get knocked out?","qjp":"歯は抜けましたか？","purpose":"観察｜再植の可能性を評価します。","branch":{"question":"歯の状態で対応が分かれます","options":[{"label":"Yes, one came right out.","jp":"はい、1本抜けました。","route":"→ 歯の保存を指導","next":"out","setReply":{"a":"Yes, one tooth came out.","ajp":"はい、1本抜けました。"}},{"label":"No, just loose and bleeding.","jp":"いいえ、ぐらついて出血だけ。","route":"→ 出血と気道を確認","next":"loose","setReply":{"a":"No, just loose and bleeding.","ajp":"いいえ、ぐらついて出血しています。"}}]}},"out":{"step":"T","q":"Do you have the tooth? Keep it in milk.","qjp":"歯はありますか？牛乳に入れてください。","purpose":"処置｜抜けた歯は乾燥させず保存します。","a":"Yes, I have it here.","ajp":"はい、ここにあります。","next":"l"},"loose":{"step":"T","q":"Can you breathe and swallow okay?","qjp":"呼吸や飲み込みは大丈夫ですか？","purpose":"気道｜出血の気道への影響を評価します。","a":"Yes, but it bleeds a lot.","ajp":"はい、でも出血が多いです。","next":"l"},"l":{"step":"L","q":"Is any tooth fragment missing or swallowed?","qjp":"歯のかけらが行方不明、または飲み込みは？","purpose":"異物｜誤嚥・誤飲を評価します。","a":"No, I don't think so.","ajp":"いいえ、ないと思います。","end":{"impr":"Thank you. We'll control the bleeding and protect the tooth.","imprJp":"ありがとうございます。出血を抑え、歯を守りますね。"}}},"lv":6},{"id":"preeclampsia","icon":"🤰","cat":"産科","title":"妊娠高血圧・子癇前症","en":"Pre-eclampsia","framework":"GTPAL","start":"g","nodes":{"g":{"step":"G","q":"How many weeks pregnant are you?","qjp":"妊娠何週ですか？","purpose":"妊娠週数｜子癇前症は後期に多い疾患です。","a":"About thirty-four weeks.","ajp":"34週くらいです。","next":"t"},"t":{"step":"T","q":"Do you have a headache or vision changes?","qjp":"頭痛や見え方の変化はありますか？","purpose":"症状｜重症徴候を評価します。","branch":{"question":"症状で重症度が分かれます","options":[{"label":"Yes, a bad headache and blurry vision.","jp":"はい、ひどい頭痛と視界のぼやけです。","route":"→ 重症。緊急対応へ","next":"severe","setReply":{"a":"Yes, a bad headache and blurry vision.","ajp":"はい、ひどい頭痛と視界のぼやけです。"}},{"label":"Just some swelling in my hands.","jp":"手のむくみだけです。","route":"→ 経過と既往を確認","next":"mild","setReply":{"a":"Just swelling in my hands.","ajp":"手のむくみだけです。"}}]}},"severe":{"step":"P","q":"Do you have pain under your ribs?","qjp":"みぞおちの下に痛みは？","purpose":"重症｜肝被膜進展の徴候を評価します。","a":"Yes, on the right side.","ajp":"はい、右側にあります。","next":"a"},"mild":{"step":"P","q":"Has your blood pressure been high lately?","qjp":"最近、血圧は高めでしたか？","purpose":"評価｜高血圧の経過を確認します。","a":"Yes, at my last check.","ajp":"はい、前回の健診で。","next":"a"},"a":{"step":"A","q":"Is this your first pregnancy?","qjp":"初めての妊娠ですか？","purpose":"既往｜初産は子癇前症の危険因子です。","a":"Yes, it is.","ajp":"はい、そうです。","end":{"impr":"Thank you. Please stay calm and still. We're moving quickly.","imprJp":"ありがとうございます。落ち着いて、動かずに。急ぎます。"}}},"lv":4},{"id":"abnormbleed","icon":"🩸","cat":"産科","title":"不正性器出血","en":"Abnormal Bleeding","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"When did the bleeding start?","qjp":"出血はいつ始まりましたか？","purpose":"Signs｜発症の経過を確認します。","a":"This morning, heavier than a period.","ajp":"今朝、生理より多い量です。","next":"e1"},"e1":{"step":"E","q":"Is there any chance you are pregnant?","qjp":"妊娠の可能性はありますか？","purpose":"Events｜妊娠関連を鑑別します。","branch":{"question":"妊娠の可能性で評価が分かれます","options":[{"label":"Yes, it's possible.","jp":"はい、可能性はあります。","route":"→ 妊娠関連を疑い緊急評価","next":"preg","setReply":{"a":"Yes, it's possible.","ajp":"はい、可能性はあります。"}},{"label":"No, I'm past menopause.","jp":"いいえ、閉経後です。","route":"→ 閉経後出血を評価","next":"postmeno","setReply":{"a":"No, I'm past menopause.","ajp":"いいえ、閉経後です。"}}]}},"preg":{"step":"S","q":"Do you have belly pain or dizziness?","qjp":"腹痛やめまいはありますか？","purpose":"重症度｜流産・異所性を評価します。","a":"Yes, cramps and a bit dizzy.","ajp":"はい、差し込みと、少しめまいが。","next":"p"},"postmeno":{"step":"S","q":"How much are you bleeding now?","qjp":"今、出血量はどのくらいですか？","purpose":"重症度｜出血量を評価します。","a":"Soaking through pads.","ajp":"ナプキンを通すほどです。","next":"p"},"p":{"step":"P","q":"Are you taking any blood thinners?","qjp":"血液をサラサラにする薬は？","purpose":"既往｜出血傾向を評価します。","a":"No, I'm not.","ajp":"いいえ、飲んでいません。","end":{"impr":"Thank you. We'll monitor you and take you in for assessment.","imprJp":"ありがとうございます。経過を見ながら、検査のためお連れします。"}}},"lv":2},{"id":"preterm","icon":"👶","cat":"産科","title":"切迫早産","en":"Preterm Labor","framework":"GTPAL","start":"g","nodes":{"g":{"step":"G","q":"How many weeks pregnant are you?","qjp":"妊娠何週ですか？","purpose":"妊娠週数｜早産の判断に必須です。","a":"Only thirty-one weeks.","ajp":"まだ31週です。","next":"t"},"t":{"step":"T","q":"Are you having regular contractions?","qjp":"規則的な陣痛がありますか？","purpose":"陣痛｜早産の進行を評価します。","branch":{"question":"陣痛の状況で緊急度が分かれます","options":[{"label":"Yes, every five minutes.","jp":"はい、5分ごとです。","route":"→ 進行。破水を確認","next":"active","setReply":{"a":"Yes, about every five minutes.","ajp":"はい、5分ごとくらいです。"}},{"label":"Just tightening sometimes.","jp":"時々張る程度です。","route":"→ 経過観察の評価へ","next":"mild","setReply":{"a":"Just some tightening now and then.","ajp":"時々張る程度です。"}}]}},"active":{"step":"P","q":"Has your water broken?","qjp":"破水はしましたか？","purpose":"破水｜早産進行と感染を評価します。","a":"Yes, a little while ago.","ajp":"はい、少し前に。","next":"a"},"mild":{"step":"P","q":"Do you have any bleeding or fluid leaking?","qjp":"出血や水が漏れる感じは？","purpose":"評価｜破水・出血を確認します。","a":"No, none.","ajp":"いいえ、ありません。","next":"a"},"a":{"step":"A","q":"Have you had a preterm birth before?","qjp":"以前に早産はありましたか？","purpose":"既往｜早産の危険因子を確認します。","a":"No, this is my first.","ajp":"いいえ、初めてです。","end":{"impr":"Thank you. We'll take you to a hospital ready for the baby.","imprJp":"ありがとうございます。赤ちゃんに備えた病院へお連れします。"}}},"lv":2},{"id":"tbi","icon":"🧠","cat":"外傷","title":"重症頭部外傷","en":"Severe Head Trauma","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"How was the head injured?","qjp":"どのように頭を負傷しましたか？","purpose":"受傷機転｜高エネルギー外傷を評価します。","a":"A heavy beam fell on him.","ajp":"重い梁が頭に落ちました。","next":"d"},"d":{"step":"D","q":"Is the person awake and responding?","qjp":"その人は起きて反応しますか？","purpose":"意識｜意識レベルを評価します。","branch":{"question":"反応の有無で対応が分かれます","options":[{"label":"No, not responding at all.","jp":"いいえ、全く反応しません。","route":"→ 重症。気道を確保","next":"unconscious","setReply":{"a":"No, he is not responding.","ajp":"いいえ、全く反応しません。"}},{"label":"Drowsy, mumbling.","jp":"もうろうとして、つぶやくだけ。","route":"→ 神経症状を確認","next":"drowsy","setReply":{"a":"He's drowsy and mumbling.","ajp":"もうろうとして、つぶやくだけです。"}}]}},"unconscious":{"step":"T","q":"Is he breathing on his own?","qjp":"自分で呼吸していますか？","purpose":"気道｜呼吸の有無を最優先で確認します。","a":"Yes, but it's noisy.","ajp":"はい、でも雑音がします。","next":"l"},"drowsy":{"step":"T","q":"Are the pupils the same size?","qjp":"瞳孔の大きさは左右同じですか？","purpose":"神経｜頭蓋内圧亢進を評価します。","a":"One looks bigger.","ajp":"片方が大きく見えます。","next":"l"},"l":{"step":"L","q":"Is there bleeding or fluid from the ears or nose?","qjp":"耳や鼻から血や液体は？","purpose":"観察｜頭蓋底骨折を評価します。","a":"Some clear fluid from the nose.","ajp":"鼻から透明な液体が。","next":"end"},"end":{"step":"S","q":"Is he on any blood thinners?","qjp":"血液をサラサラにする薬は？","purpose":"既往｜頭蓋内出血のリスクを評価します。","a":"I'm not sure.","ajp":"分かりません。","end":{"impr":"Stay still. We're protecting his airway and moving fast.","imprJp":"動かさないで。気道を守り、急いで運びます。"}}},"lv":9},{"id":"abdtrauma","icon":"🤕","cat":"外傷","title":"腹部外傷","en":"Abdominal Trauma","framework":"DCAP","start":"o","nodes":{"o":{"step":"O","q":"How did you hurt your belly?","qjp":"どうやってお腹を負傷しましたか？","purpose":"受傷機転｜臓器損傷を推定します。","a":"The steering wheel hit me.","ajp":"ハンドルがぶつかりました。","next":"d"},"d":{"step":"D","q":"Is your belly tender or hard?","qjp":"お腹は押すと痛い、硬いですか？","purpose":"観察｜腹腔内出血・腹膜炎を評価します。","branch":{"question":"腹部所見で重症度が分かれます","options":[{"label":"It's hard and very painful.","jp":"硬くて、とても痛いです。","route":"→ 内臓損傷を疑い緊急評価","next":"rigid","setReply":{"a":"It's hard and very painful.","ajp":"硬くて、とても痛いです。"}},{"label":"Sore, but soft.","jp":"痛いですが、柔らかいです。","route":"→ 経過と随伴症状を確認","next":"soft","setReply":{"a":"Sore, but still soft.","ajp":"痛いですが、まだ柔らかいです。"}}]}},"rigid":{"step":"T","q":"Do you feel faint or very thirsty?","qjp":"気が遠くなる、強い渇きは？","purpose":"ショック｜出血性ショックを評価します。","a":"Yes, very thirsty.","ajp":"はい、とても渇きます。","next":"l"},"soft":{"step":"T","q":"Is there bruising across your belly?","qjp":"お腹にあざはありますか？","purpose":"観察｜シートベルト痕等を確認します。","a":"Yes, a seatbelt mark.","ajp":"はい、シートベルトの痕が。","next":"l"},"l":{"step":"L","q":"Do you have pain in your shoulder?","qjp":"肩に痛みはありますか？","purpose":"放散｜横隔膜刺激（脾損傷）を評価します。","a":"My left shoulder aches.","ajp":"左肩が痛みます。","end":{"impr":"Stay still and lie flat. We're taking you in urgently.","imprJp":"動かず、平らに寝て。緊急でお連れします。"}}},"lv":3},{"id":"interpreter","icon":"🌐","cat":"基本","title":"通訳が必要な患者","en":"Patient Needing Interpreter","framework":"SAMPLE","start":"s","nodes":{"s":{"step":"S","q":"Hello. What language do you speak?","qjp":"こんにちは。何語を話しますか？","purpose":"言語｜通訳手段を確保します。","a":"Spanish. Little English.","ajp":"スペイン語です。英語は少し。","next":"e1"},"e1":{"step":"E","q":"I will use a translator app. Where is the pain?","qjp":"翻訳アプリを使います。どこが痛いですか？","purpose":"代替手段｜ツールで意思疎通します。","branch":{"question":"理解度で進め方が分かれます","options":[{"label":"(points to belly) Here.","jp":"（お腹を指す）ここ。","route":"→ 身振りで主訴を把握","next":"point","setReply":{"a":"Here. (points to belly)","ajp":"ここ。（お腹を指す）"}},{"label":"(speaks, app translates)","jp":"（話す、アプリが訳す）","route":"→ アプリで聴取を続行","next":"app","setReply":{"a":"My stomach has hurt since morning.","ajp":"朝からお腹が痛いです。"}}]}},"point":{"step":"S","q":"Pain strong? Show me, one to ten.","qjp":"痛みは強い？1から10で示して。","purpose":"重症度｜数字で程度を把握します。","a":"(shows seven fingers)","ajp":"（指を7本立てる）","next":"a"},"app":{"step":"S","q":"Is the pain getting worse?","qjp":"痛みは悪化していますか？","purpose":"経過｜アプリ経由で経過を確認します。","a":"Yes, a little worse.","ajp":"はい、少し悪化しています。","next":"a"},"a":{"step":"A","q":"Medicine allergy? Yes or no?","qjp":"薬のアレルギーは？あり、なし？","purpose":"Allergies｜短い言葉で安全確認します。","a":"No allergy.","ajp":"アレルギーなし。","next":"family"},"family":{"step":"E","q":"Family here? Can we call?","qjp":"ご家族は?電話できますか？","purpose":"支援｜通訳できる家族を探します。","a":"My daughter speaks English.","ajp":"娘が英語を話します。","end":{"impr":"Good. We'll call her and get a full interpreter too.","imprJp":"よかった。娘さんに電話し、正式な通訳も手配します。"}}},"lv":9},{"id":"chesttight","icon":"🫁","cat":"呼吸器","title":"胸の圧迫感と息切れ","en":"Chest Tightness","framework":"OPQRST","start":"o","nodes":{"o":{"step":"O","q":"When did the tightness start?","qjp":"締めつけ感はいつ始まりましたか？","purpose":"Onset｜発症のタイミングを確認します。","a":"About an hour ago.","ajp":"1時間ほど前です。","next":"p"},"p":{"step":"P","q":"Does it come on with exertion?","qjp":"動いたときに出ますか？","purpose":"Provocation｜労作性か否かで原因を絞ります。","branch":{"question":"労作との関係で評価が分かれます","options":[{"label":"Yes, when I walk or climb.","jp":"はい、歩いたり階段で。","route":"→ 心原性を疑い放散へ","next":"exertion","setReply":{"a":"Yes, when I walk or climb stairs.","ajp":"はい、歩いたり階段を上ると出ます。"}},{"label":"No, even at rest.","jp":"いいえ、安静時でもです。","route":"→ 不安定型を疑い随伴症状へ","next":"rest","setReply":{"a":"No, it happens even at rest.","ajp":"いいえ、安静時でも出ます。"}}]}},"exertion":{"step":"R","q":"Does it spread to your arm or jaw?","qjp":"腕やあごに広がりますか？","purpose":"Radiation｜心原性の放散を確認します。","a":"A little into my left arm.","ajp":"少し左腕に広がります。","next":"s"},"rest":{"step":"R","q":"Are you sweating or feeling sick?","qjp":"汗や吐き気はありますか？","purpose":"随伴症状｜心筋虚血の徴候を評価します。","a":"Yes, cold sweat.","ajp":"はい、冷や汗が出ます。","next":"s"},"s":{"step":"S","q":"How tight does it feel, one to ten?","qjp":"締めつけは10段階でどのくらいですか？","purpose":"Severity｜程度を数値化します。","a":"About a seven.","ajp":"7くらいです。","next":"t"},"t":{"step":"T","q":"Is it constant or easing off?","qjp":"ずっと続いていますか、和らいでいますか？","purpose":"Time｜経過で緊急度を評価します。","a":"It's still there.","ajp":"まだ続いています。","end":{"impr":"Thank you. We'll check your heart and give you oxygen.","imprJp":"ありがとうございます。心臓を確認し、酸素を投与しますね。"}}},"lv":9}];
